-- V7: Seed ayahs juz16_20

INSERT INTO mst_ayah (surah_id, ayah_number, text_arabic, text_simple,
                      juz_number, hizb_number, manzil_number, page_number,
                      sajda, created_at, updated_at)
VALUES
((SELECT id FROM mst_surah WHERE surah_number = 18), 75, '۞ قَالَ أَلَمْ أَقُل لَّكَ إِنَّكَ لَن تَسْتَطِيعَ مَعِىَ صَبْرًۭا', NULL, 16, 121, 4, 302, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 76, 'قَالَ إِن سَأَلْتُكَ عَن شَىْءٍۭ بَعْدَهَا فَلَا تُصَٰحِبْنِى ۖ قَدْ بَلَغْتَ مِن لَّدُنِّى عُذْرًۭا', NULL, 16, 121, 4, 302, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 77, 'فَٱنطَلَقَا حَتَّىٰٓ إِذَآ أَتَيَآ أَهْلَ قَرْيَةٍ ٱسْتَطْعَمَآ أَهْلَهَا فَأَبَوْا۟ أَن يُضَيِّفُوهُمَا فَوَجَدَا فِيهَا جِدَارًۭا يُرِيدُ أَن يَنقَضَّ فَأَقَامَهُۥ ۖ قَالَ لَوْ شِئْتَ لَتَّخَذْتَ عَلَيْهِ أَجْرًۭا', NULL, 16, 121, 4, 302, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 78, 'قَالَ هَٰذَا فِرَاقُ بَيْنِى وَبَيْنِكَ ۚ سَأُنَبِّئُكَ بِتَأْوِيلِ مَا لَمْ تَسْتَطِع عَّلَيْهِ صَبْرًا', NULL, 16, 121, 4, 302, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 79, 'أَمَّا ٱلسَّفِينَةُ فَكَانَتْ لِمَسَٰكِينَ يَعْمَلُونَ فِى ٱلْبَحْرِ فَأَرَدتُّ أَنْ أَعِيبَهَا وَكَانَ وَرَآءَهُم مَّلِكٌۭ يَأْخُذُ كُلَّ سَفِينَةٍ غَصْبًۭا', NULL, 16, 121, 4, 302, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 80, 'وَأَمَّا ٱلْغُلَٰمُ فَكَانَ أَبَوَاهُ مُؤْمِنَيْنِ فَخَشِينَآ أَن يُرْهِقَهُمَا طُغْيَٰنًۭا وَكُفْرًۭا', NULL, 16, 121, 4, 302, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 81, 'فَأَرَدْنَآ أَن يُبْدِلَهُمَا رَبُّهُمَا خَيْرًۭا مِّنْهُ زَكَوٰةًۭ وَأَقْرَبَ رُحْمًۭا', NULL, 16, 121, 4, 302, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 82, 'وَأَمَّا ٱلْجِدَارُ فَكَانَ لِغُلَٰمَيْنِ يَتِيمَيْنِ فِى ٱلْمَدِينَةِ وَكَانَ تَحْتَهُۥ كَنزٌۭ لَّهُمَا وَكَانَ أَبُوهُمَا صَٰلِحًۭا فَأَرَادَ رَبُّكَ أَن يَبْلُغَآ أَشُدَّهُمَا وَيَسْتَخْرِجَا كَنزَهُمَا رَحْمَةًۭ مِّن رَّبِّكَ ۚ وَمَا فَعَلْتُهُۥ عَنْ أَمْرِى ۚ ذَٰلِكَ تَأْوِيلُ مَا لَمْ تَسْطِع عَّلَيْهِ صَبْرًۭا', NULL, 16, 121, 4, 302, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 83, 'وَيَسْـَٔلُونَكَ عَن ذِى ٱلْقَرْنَيْنِ ۖ قُلْ سَأَتْلُوا۟ عَلَيْكُم مِّنْهُ ذِكْرًا', NULL, 16, 121, 4, 302, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 84, 'إِنَّا مَكَّنَّا لَهُۥ فِى ٱلْأَرْضِ وَءَاتَيْنَٰهُ مِن كُلِّ شَىْءٍۢ سَبَبًۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 85, 'فَأَتْبَعَ سَبَبًا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 86, 'حَتَّىٰٓ إِذَا بَلَغَ مَغْرِبَ ٱلشَّمْسِ وَجَدَهَا تَغْرُبُ فِى عَيْنٍ حَمِئَةٍۢ وَوَجَدَ عِندَهَا قَوْمًۭا ۗ قُلْنَا يَٰذَا ٱلْقَرْنَيْنِ إِمَّآ أَن تُعَذِّبَ وَإِمَّآ أَن تَتَّخِذَ فِيهِمْ حُسْنًۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 87, 'قَالَ أَمَّا مَن ظَلَمَ فَسَوْفَ نُعَذِّبُهُۥ ثُمَّ يُرَدُّ إِلَىٰ رَبِّهِۦ فَيُعَذِّبُهُۥ عَذَابًۭا نُّكْرًۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 88, 'وَأَمَّا مَنْ ءَامَنَ وَعَمِلَ صَٰلِحًۭا فَلَهُۥ جَزَآءً ٱلْحُسْنَىٰ ۖ وَسَنَقُولُ لَهُۥ مِنْ أَمْرِنَا يُسْرًۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 89, 'ثُمَّ أَتْبَعَ سَبَبًا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 90, 'حَتَّىٰٓ إِذَا بَلَغَ مَطْلِعَ ٱلشَّمْسِ وَجَدَهَا تَطْلُعُ عَلَىٰ قَوْمٍۢ لَّمْ نَجْعَل لَّهُم مِّن دُونِهَا سِتْرًۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 91, 'كَذَٰلِكَ وَقَدْ أَحَطْنَا بِمَا لَدَيْهِ خُبْرًۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 92, 'ثُمَّ أَتْبَعَ سَبَبًا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 93, 'حَتَّىٰٓ إِذَا بَلَغَ بَيْنَ ٱلسَّدَّيْنِ وَجَدَ مِن دُونِهِمَا قَوْمًۭا لَّا يَكَادُونَ يَفْقَهُونَ قَوْلًۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 94, 'قَالُوا۟ يَٰذَا ٱلْقَرْنَيْنِ إِنَّ يَأْجُوجَ وَمَأْجُوجَ مُفْسِدُونَ فِى ٱلْأَرْضِ فَهَلْ نَجْعَلُ لَكَ خَرْجًا عَلَىٰٓ أَن تَجْعَلَ بَيْنَنَا وَبَيْنَهُمْ سَدًّۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 95, 'قَالَ مَا مَكَّنِّى فِيهِ رَبِّى خَيْرٌۭ فَأَعِينُونِى بِقُوَّةٍ أَجْعَلْ بَيْنَكُمْ وَبَيْنَهُمْ رَدْمًا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 96, 'ءَاتُونِى زُبَرَ ٱلْحَدِيدِ ۖ حَتَّىٰٓ إِذَا سَاوَىٰ بَيْنَ ٱلصَّدَفَيْنِ قَالَ ٱنفُخُوا۟ ۖ حَتَّىٰٓ إِذَا جَعَلَهُۥ نَارًۭا قَالَ ءَاتُونِىٓ أُفْرِغْ عَلَيْهِ قِطْرًۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 97, 'فَمَا ٱسْطَٰعُوٓا۟ أَن يَظْهَرُوهُ وَمَا ٱسْتَطَٰعُوا۟ لَهُۥ نَقْبًۭا', NULL, 16, 121, 4, 303, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 98, 'قَالَ هَٰذَا رَحْمَةٌۭ مِّن رَّبِّى ۖ فَإِذَا جَآءَ وَعْدُ رَبِّى جَعَلَهُۥ دَكَّآءَ ۖ وَكَانَ وَعْدُ رَبِّى حَقًّۭا', NULL, 16, 121, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 99, '۞ وَتَرَكْنَا بَعْضَهُمْ يَوْمَئِذٍۢ يَمُوجُ فِى بَعْضٍۢ ۖ وَنُفِخَ فِى ٱلصُّورِ فَجَمَعْنَٰهُمْ جَمْعًۭا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 100, 'وَعَرَضْنَا جَهَنَّمَ يَوْمَئِذٍۢ لِّلْكَٰفِرِينَ عَرْضًا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 101, 'ٱلَّذِينَ كَانَتْ أَعْيُنُهُمْ فِى غِطَآءٍ عَن ذِكْرِى وَكَانُوا۟ لَا يَسْتَطِيعُونَ سَمْعًا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 102, 'أَفَحَسِبَ ٱلَّذِينَ كَفَرُوٓا۟ أَن يَتَّخِذُوا۟ عِبَادِى مِن دُونِىٓ أَوْلِيَآءَ ۚ إِنَّآ أَعْتَدْنَا جَهَنَّمَ لِلْكَٰفِرِينَ نُزُلًۭا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 103, 'قُلْ هَلْ نُنَبِّئُكُم بِٱلْأَخْسَرِينَ أَعْمَٰلًا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 104, 'ٱلَّذِينَ ضَلَّ سَعْيُهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَهُمْ يَحْسَبُونَ أَنَّهُمْ يُحْسِنُونَ صُنْعًا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 105, 'أُو۟لَٰٓئِكَ ٱلَّذِينَ كَفَرُوا۟ بِـَٔايَٰتِ رَبِّهِمْ وَلِقَآئِهِۦ فَحَبِطَتْ أَعْمَٰلُهُمْ فَلَا نُقِيمُ لَهُمْ يَوْمَ ٱلْقِيَٰمَةِ وَزْنًۭا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 106, 'ذَٰلِكَ جَزَآؤُهُمْ جَهَنَّمُ بِمَا كَفَرُوا۟ وَٱتَّخَذُوٓا۟ ءَايَٰتِى وَرُسُلِى هُزُوًا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 107, 'إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ كَانَتْ لَهُمْ جَنَّٰتُ ٱلْفِرْدَوْسِ نُزُلًا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 108, 'خَٰلِدِينَ فِيهَا لَا يَبْغُونَ عَنْهَا حِوَلًۭا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 109, 'قُل لَّوْ كَانَ ٱلْبَحْرُ مِدَادًۭا لِّكَلِمَٰتِ رَبِّى لَنَفِدَ ٱلْبَحْرُ قَبْلَ أَن تَنفَدَ كَلِمَٰتُ رَبِّى وَلَوْ جِئْنَا بِمِثْلِهِۦ مَدَدًۭا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 18), 110, 'قُلْ إِنَّمَآ أَنَا۠ بَشَرٌۭ مِّثْلُكُمْ يُوحَىٰٓ إِلَىَّ أَنَّمَآ إِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ ۖ فَمَن كَانَ يَرْجُوا۟ لِقَآءَ رَبِّهِۦ فَلْيَعْمَلْ عَمَلًۭا صَٰلِحًۭا وَلَا يُشْرِكْ بِعِبَادَةِ رَبِّهِۦٓ أَحَدًۢا', NULL, 16, 122, 4, 304, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ كٓهيعٓصٓ', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 2, 'ذِكْرُ رَحْمَتِ رَبِّكَ عَبْدَهُۥ زَكَرِيَّآ', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 3, 'إِذْ نَادَىٰ رَبَّهُۥ نِدَآءً خَفِيًّۭا', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 4, 'قَالَ رَبِّ إِنِّى وَهَنَ ٱلْعَظْمُ مِنِّى وَٱشْتَعَلَ ٱلرَّأْسُ شَيْبًۭا وَلَمْ أَكُنۢ بِدُعَآئِكَ رَبِّ شَقِيًّۭا', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 5, 'وَإِنِّى خِفْتُ ٱلْمَوَٰلِىَ مِن وَرَآءِى وَكَانَتِ ٱمْرَأَتِى عَاقِرًۭا فَهَبْ لِى مِن لَّدُنكَ وَلِيًّۭا', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 6, 'يَرِثُنِى وَيَرِثُ مِنْ ءَالِ يَعْقُوبَ ۖ وَٱجْعَلْهُ رَبِّ رَضِيًّۭا', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 7, 'يَٰزَكَرِيَّآ إِنَّا نُبَشِّرُكَ بِغُلَٰمٍ ٱسْمُهُۥ يَحْيَىٰ لَمْ نَجْعَل لَّهُۥ مِن قَبْلُ سَمِيًّۭا', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 8, 'قَالَ رَبِّ أَنَّىٰ يَكُونُ لِى غُلَٰمٌۭ وَكَانَتِ ٱمْرَأَتِى عَاقِرًۭا وَقَدْ بَلَغْتُ مِنَ ٱلْكِبَرِ عِتِيًّۭا', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 9, 'قَالَ كَذَٰلِكَ قَالَ رَبُّكَ هُوَ عَلَىَّ هَيِّنٌۭ وَقَدْ خَلَقْتُكَ مِن قَبْلُ وَلَمْ تَكُ شَيْـًۭٔا', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 10, 'قَالَ رَبِّ ٱجْعَل لِّىٓ ءَايَةًۭ ۚ قَالَ ءَايَتُكَ أَلَّا تُكَلِّمَ ٱلنَّاسَ ثَلَٰثَ لَيَالٍۢ سَوِيًّۭا', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 11, 'فَخَرَجَ عَلَىٰ قَوْمِهِۦ مِنَ ٱلْمِحْرَابِ فَأَوْحَىٰٓ إِلَيْهِمْ أَن سَبِّحُوا۟ بُكْرَةًۭ وَعَشِيًّۭا', NULL, 16, 122, 4, 305, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 12, 'يَٰيَحْيَىٰ خُذِ ٱلْكِتَٰبَ بِقُوَّةٍۢ ۖ وَءَاتَيْنَٰهُ ٱلْحُكْمَ صَبِيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 13, 'وَحَنَانًۭا مِّن لَّدُنَّا وَزَكَوٰةًۭ ۖ وَكَانَ تَقِيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 14, 'وَبَرًّۢا بِوَٰلِدَيْهِ وَلَمْ يَكُن جَبَّارًا عَصِيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 15, 'وَسَلَٰمٌ عَلَيْهِ يَوْمَ وُلِدَ وَيَوْمَ يَمُوتُ وَيَوْمَ يُبْعَثُ حَيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 16, 'وَٱذْكُرْ فِى ٱلْكِتَٰبِ مَرْيَمَ إِذِ ٱنتَبَذَتْ مِنْ أَهْلِهَا مَكَانًۭا شَرْقِيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 17, 'فَٱتَّخَذَتْ مِن دُونِهِمْ حِجَابًۭا فَأَرْسَلْنَآ إِلَيْهَا رُوحَنَا فَتَمَثَّلَ لَهَا بَشَرًۭا سَوِيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 18, 'قَالَتْ إِنِّىٓ أَعُوذُ بِٱلرَّحْمَٰنِ مِنكَ إِن كُنتَ تَقِيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 19, 'قَالَ إِنَّمَآ أَنَا۠ رَسُولُ رَبِّكِ لِأَهَبَ لَكِ غُلَٰمًۭا زَكِيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 20, 'قَالَتْ أَنَّىٰ يَكُونُ لِى غُلَٰمٌۭ وَلَمْ يَمْسَسْنِى بَشَرٌۭ وَلَمْ أَكُ بَغِيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 21, 'قَالَ كَذَٰلِكِ قَالَ رَبُّكِ هُوَ عَلَىَّ هَيِّنٌۭ ۖ وَلِنَجْعَلَهُۥٓ ءَايَةًۭ لِّلنَّاسِ وَرَحْمَةًۭ مِّنَّا ۚ وَكَانَ أَمْرًۭا مَّقْضِيًّۭا', NULL, 16, 122, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 22, '۞ فَحَمَلَتْهُ فَٱنتَبَذَتْ بِهِۦ مَكَانًۭا قَصِيًّۭا', NULL, 16, 123, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 23, 'فَأَجَآءَهَا ٱلْمَخَاضُ إِلَىٰ جِذْعِ ٱلنَّخْلَةِ قَالَتْ يَٰلَيْتَنِى مِتُّ قَبْلَ هَٰذَا وَكُنتُ نَسْيًۭا مَّنسِيًّۭا', NULL, 16, 123, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 24, 'فَنَادَىٰهَا مِن تَحْتِهَآ أَلَّا تَحْزَنِى قَدْ جَعَلَ رَبُّكِ تَحْتَكِ سَرِيًّۭا', NULL, 16, 123, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 25, 'وَهُزِّىٓ إِلَيْكِ بِجِذْعِ ٱلنَّخْلَةِ تُسَٰقِطْ عَلَيْكِ رُطَبًۭا جَنِيًّۭا', NULL, 16, 123, 4, 306, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 26, 'فَكُلِى وَٱشْرَبِى وَقَرِّى عَيْنًۭا ۖ فَإِمَّا تَرَيِنَّ مِنَ ٱلْبَشَرِ أَحَدًۭا فَقُولِىٓ إِنِّى نَذَرْتُ لِلرَّحْمَٰنِ صَوْمًۭا فَلَنْ أُكَلِّمَ ٱلْيَوْمَ إِنسِيًّۭا', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 27, 'فَأَتَتْ بِهِۦ قَوْمَهَا تَحْمِلُهُۥ ۖ قَالُوا۟ يَٰمَرْيَمُ لَقَدْ جِئْتِ شَيْـًۭٔا فَرِيًّۭا', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 28, 'يَٰٓأُخْتَ هَٰرُونَ مَا كَانَ أَبُوكِ ٱمْرَأَ سَوْءٍۢ وَمَا كَانَتْ أُمُّكِ بَغِيًّۭا', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 29, 'فَأَشَارَتْ إِلَيْهِ ۖ قَالُوا۟ كَيْفَ نُكَلِّمُ مَن كَانَ فِى ٱلْمَهْدِ صَبِيًّۭا', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 30, 'قَالَ إِنِّى عَبْدُ ٱللَّهِ ءَاتَىٰنِىَ ٱلْكِتَٰبَ وَجَعَلَنِى نَبِيًّۭا', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 31, 'وَجَعَلَنِى مُبَارَكًا أَيْنَ مَا كُنتُ وَأَوْصَٰنِى بِٱلصَّلَوٰةِ وَٱلزَّكَوٰةِ مَا دُمْتُ حَيًّۭا', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 32, 'وَبَرًّۢا بِوَٰلِدَتِى وَلَمْ يَجْعَلْنِى جَبَّارًۭا شَقِيًّۭا', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 33, 'وَٱلسَّلَٰمُ عَلَىَّ يَوْمَ وُلِدتُّ وَيَوْمَ أَمُوتُ وَيَوْمَ أُبْعَثُ حَيًّۭا', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 34, 'ذَٰلِكَ عِيسَى ٱبْنُ مَرْيَمَ ۚ قَوْلَ ٱلْحَقِّ ٱلَّذِى فِيهِ يَمْتَرُونَ', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 35, 'مَا كَانَ لِلَّهِ أَن يَتَّخِذَ مِن وَلَدٍۢ ۖ سُبْحَٰنَهُۥٓ ۚ إِذَا قَضَىٰٓ أَمْرًۭا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 36, 'وَإِنَّ ٱللَّهَ رَبِّى وَرَبُّكُمْ فَٱعْبُدُوهُ ۚ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 37, 'فَٱخْتَلَفَ ٱلْأَحْزَابُ مِنۢ بَيْنِهِمْ ۖ فَوَيْلٌۭ لِّلَّذِينَ كَفَرُوا۟ مِن مَّشْهَدِ يَوْمٍ عَظِيمٍ', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 38, 'أَسْمِعْ بِهِمْ وَأَبْصِرْ يَوْمَ يَأْتُونَنَا ۖ لَٰكِنِ ٱلظَّٰلِمُونَ ٱلْيَوْمَ فِى ضَلَٰلٍۢ مُّبِينٍۢ', NULL, 16, 123, 4, 307, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 39, 'وَأَنذِرْهُمْ يَوْمَ ٱلْحَسْرَةِ إِذْ قُضِىَ ٱلْأَمْرُ وَهُمْ فِى غَفْلَةٍۢ وَهُمْ لَا يُؤْمِنُونَ', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 40, 'إِنَّا نَحْنُ نَرِثُ ٱلْأَرْضَ وَمَنْ عَلَيْهَا وَإِلَيْنَا يُرْجَعُونَ', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 41, 'وَٱذْكُرْ فِى ٱلْكِتَٰبِ إِبْرَٰهِيمَ ۚ إِنَّهُۥ كَانَ صِدِّيقًۭا نَّبِيًّا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 42, 'إِذْ قَالَ لِأَبِيهِ يَٰٓأَبَتِ لِمَ تَعْبُدُ مَا لَا يَسْمَعُ وَلَا يُبْصِرُ وَلَا يُغْنِى عَنكَ شَيْـًۭٔا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 43, 'يَٰٓأَبَتِ إِنِّى قَدْ جَآءَنِى مِنَ ٱلْعِلْمِ مَا لَمْ يَأْتِكَ فَٱتَّبِعْنِىٓ أَهْدِكَ صِرَٰطًۭا سَوِيًّۭا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 44, 'يَٰٓأَبَتِ لَا تَعْبُدِ ٱلشَّيْطَٰنَ ۖ إِنَّ ٱلشَّيْطَٰنَ كَانَ لِلرَّحْمَٰنِ عَصِيًّۭا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 45, 'يَٰٓأَبَتِ إِنِّىٓ أَخَافُ أَن يَمَسَّكَ عَذَابٌۭ مِّنَ ٱلرَّحْمَٰنِ فَتَكُونَ لِلشَّيْطَٰنِ وَلِيًّۭا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 46, 'قَالَ أَرَاغِبٌ أَنتَ عَنْ ءَالِهَتِى يَٰٓإِبْرَٰهِيمُ ۖ لَئِن لَّمْ تَنتَهِ لَأَرْجُمَنَّكَ ۖ وَٱهْجُرْنِى مَلِيًّۭا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 47, 'قَالَ سَلَٰمٌ عَلَيْكَ ۖ سَأَسْتَغْفِرُ لَكَ رَبِّىٓ ۖ إِنَّهُۥ كَانَ بِى حَفِيًّۭا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 48, 'وَأَعْتَزِلُكُمْ وَمَا تَدْعُونَ مِن دُونِ ٱللَّهِ وَأَدْعُوا۟ رَبِّى عَسَىٰٓ أَلَّآ أَكُونَ بِدُعَآءِ رَبِّى شَقِيًّۭا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 49, 'فَلَمَّا ٱعْتَزَلَهُمْ وَمَا يَعْبُدُونَ مِن دُونِ ٱللَّهِ وَهَبْنَا لَهُۥٓ إِسْحَٰقَ وَيَعْقُوبَ ۖ وَكُلًّۭا جَعَلْنَا نَبِيًّۭا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 50, 'وَوَهَبْنَا لَهُم مِّن رَّحْمَتِنَا وَجَعَلْنَا لَهُمْ لِسَانَ صِدْقٍ عَلِيًّۭا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 51, 'وَٱذْكُرْ فِى ٱلْكِتَٰبِ مُوسَىٰٓ ۚ إِنَّهُۥ كَانَ مُخْلَصًۭا وَكَانَ رَسُولًۭا نَّبِيًّۭا', NULL, 16, 123, 4, 308, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 52, 'وَنَٰدَيْنَٰهُ مِن جَانِبِ ٱلطُّورِ ٱلْأَيْمَنِ وَقَرَّبْنَٰهُ نَجِيًّۭا', NULL, 16, 123, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 53, 'وَوَهَبْنَا لَهُۥ مِن رَّحْمَتِنَآ أَخَاهُ هَٰرُونَ نَبِيًّۭا', NULL, 16, 123, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 54, 'وَٱذْكُرْ فِى ٱلْكِتَٰبِ إِسْمَٰعِيلَ ۚ إِنَّهُۥ كَانَ صَادِقَ ٱلْوَعْدِ وَكَانَ رَسُولًۭا نَّبِيًّۭا', NULL, 16, 123, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 55, 'وَكَانَ يَأْمُرُ أَهْلَهُۥ بِٱلصَّلَوٰةِ وَٱلزَّكَوٰةِ وَكَانَ عِندَ رَبِّهِۦ مَرْضِيًّۭا', NULL, 16, 123, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 56, 'وَٱذْكُرْ فِى ٱلْكِتَٰبِ إِدْرِيسَ ۚ إِنَّهُۥ كَانَ صِدِّيقًۭا نَّبِيًّۭا', NULL, 16, 123, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 57, 'وَرَفَعْنَٰهُ مَكَانًا عَلِيًّا', NULL, 16, 123, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 58, 'أُو۟لَٰٓئِكَ ٱلَّذِينَ أَنْعَمَ ٱللَّهُ عَلَيْهِم مِّنَ ٱلنَّبِيِّۦنَ مِن ذُرِّيَّةِ ءَادَمَ وَمِمَّنْ حَمَلْنَا مَعَ نُوحٍۢ وَمِن ذُرِّيَّةِ إِبْرَٰهِيمَ وَإِسْرَٰٓءِيلَ وَمِمَّنْ هَدَيْنَا وَٱجْتَبَيْنَآ ۚ إِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُ ٱلرَّحْمَٰنِ خَرُّوا۟ سُجَّدًۭا وَبُكِيًّۭا ۩', NULL, 16, 123, 4, 309, true, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 59, '۞ فَخَلَفَ مِنۢ بَعْدِهِمْ خَلْفٌ أَضَاعُوا۟ ٱلصَّلَوٰةَ وَٱتَّبَعُوا۟ ٱلشَّهَوَٰتِ ۖ فَسَوْفَ يَلْقَوْنَ غَيًّا', NULL, 16, 124, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 60, 'إِلَّا مَن تَابَ وَءَامَنَ وَعَمِلَ صَٰلِحًۭا فَأُو۟لَٰٓئِكَ يَدْخُلُونَ ٱلْجَنَّةَ وَلَا يُظْلَمُونَ شَيْـًۭٔا', NULL, 16, 124, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 61, 'جَنَّٰتِ عَدْنٍ ٱلَّتِى وَعَدَ ٱلرَّحْمَٰنُ عِبَادَهُۥ بِٱلْغَيْبِ ۚ إِنَّهُۥ كَانَ وَعْدُهُۥ مَأْتِيًّۭا', NULL, 16, 124, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 62, 'لَّا يَسْمَعُونَ فِيهَا لَغْوًا إِلَّا سَلَٰمًۭا ۖ وَلَهُمْ رِزْقُهُمْ فِيهَا بُكْرَةًۭ وَعَشِيًّۭا', NULL, 16, 124, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 63, 'تِلْكَ ٱلْجَنَّةُ ٱلَّتِى نُورِثُ مِنْ عِبَادِنَا مَن كَانَ تَقِيًّۭا', NULL, 16, 124, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 64, 'وَمَا نَتَنَزَّلُ إِلَّا بِأَمْرِ رَبِّكَ ۖ لَهُۥ مَا بَيْنَ أَيْدِينَا وَمَا خَلْفَنَا وَمَا بَيْنَ ذَٰلِكَ ۚ وَمَا كَانَ رَبُّكَ نَسِيًّۭا', NULL, 16, 124, 4, 309, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 65, 'رَّبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا فَٱعْبُدْهُ وَٱصْطَبِرْ لِعِبَٰدَتِهِۦ ۚ هَلْ تَعْلَمُ لَهُۥ سَمِيًّۭا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 66, 'وَيَقُولُ ٱلْإِنسَٰنُ أَءِذَا مَا مِتُّ لَسَوْفَ أُخْرَجُ حَيًّا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 67, 'أَوَلَا يَذْكُرُ ٱلْإِنسَٰنُ أَنَّا خَلَقْنَٰهُ مِن قَبْلُ وَلَمْ يَكُ شَيْـًۭٔا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 68, 'فَوَرَبِّكَ لَنَحْشُرَنَّهُمْ وَٱلشَّيَٰطِينَ ثُمَّ لَنُحْضِرَنَّهُمْ حَوْلَ جَهَنَّمَ جِثِيًّۭا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 69, 'ثُمَّ لَنَنزِعَنَّ مِن كُلِّ شِيعَةٍ أَيُّهُمْ أَشَدُّ عَلَى ٱلرَّحْمَٰنِ عِتِيًّۭا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 70, 'ثُمَّ لَنَحْنُ أَعْلَمُ بِٱلَّذِينَ هُمْ أَوْلَىٰ بِهَا صِلِيًّۭا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 71, 'وَإِن مِّنكُمْ إِلَّا وَارِدُهَا ۚ كَانَ عَلَىٰ رَبِّكَ حَتْمًۭا مَّقْضِيًّۭا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 72, 'ثُمَّ نُنَجِّى ٱلَّذِينَ ٱتَّقَوا۟ وَّنَذَرُ ٱلظَّٰلِمِينَ فِيهَا جِثِيًّۭا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 73, 'وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُنَا بَيِّنَٰتٍۢ قَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوٓا۟ أَىُّ ٱلْفَرِيقَيْنِ خَيْرٌۭ مَّقَامًۭا وَأَحْسَنُ نَدِيًّۭا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 74, 'وَكَمْ أَهْلَكْنَا قَبْلَهُم مِّن قَرْنٍ هُمْ أَحْسَنُ أَثَٰثًۭا وَرِءْيًۭا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 75, 'قُلْ مَن كَانَ فِى ٱلضَّلَٰلَةِ فَلْيَمْدُدْ لَهُ ٱلرَّحْمَٰنُ مَدًّا ۚ حَتَّىٰٓ إِذَا رَأَوْا۟ مَا يُوعَدُونَ إِمَّا ٱلْعَذَابَ وَإِمَّا ٱلسَّاعَةَ فَسَيَعْلَمُونَ مَنْ هُوَ شَرٌّۭ مَّكَانًۭا وَأَضْعَفُ جُندًۭا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 76, 'وَيَزِيدُ ٱللَّهُ ٱلَّذِينَ ٱهْتَدَوْا۟ هُدًۭى ۗ وَٱلْبَٰقِيَٰتُ ٱلصَّٰلِحَٰتُ خَيْرٌ عِندَ رَبِّكَ ثَوَابًۭا وَخَيْرٌۭ مَّرَدًّا', NULL, 16, 124, 4, 310, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 77, 'أَفَرَءَيْتَ ٱلَّذِى كَفَرَ بِـَٔايَٰتِنَا وَقَالَ لَأُوتَيَنَّ مَالًۭا وَوَلَدًا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 78, 'أَطَّلَعَ ٱلْغَيْبَ أَمِ ٱتَّخَذَ عِندَ ٱلرَّحْمَٰنِ عَهْدًۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 79, 'كَلَّا ۚ سَنَكْتُبُ مَا يَقُولُ وَنَمُدُّ لَهُۥ مِنَ ٱلْعَذَابِ مَدًّۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 80, 'وَنَرِثُهُۥ مَا يَقُولُ وَيَأْتِينَا فَرْدًۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 81, 'وَٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ ءَالِهَةًۭ لِّيَكُونُوا۟ لَهُمْ عِزًّۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 82, 'كَلَّا ۚ سَيَكْفُرُونَ بِعِبَادَتِهِمْ وَيَكُونُونَ عَلَيْهِمْ ضِدًّا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 83, 'أَلَمْ تَرَ أَنَّآ أَرْسَلْنَا ٱلشَّيَٰطِينَ عَلَى ٱلْكَٰفِرِينَ تَؤُزُّهُمْ أَزًّۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 84, 'فَلَا تَعْجَلْ عَلَيْهِمْ ۖ إِنَّمَا نَعُدُّ لَهُمْ عَدًّۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 85, 'يَوْمَ نَحْشُرُ ٱلْمُتَّقِينَ إِلَى ٱلرَّحْمَٰنِ وَفْدًۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 86, 'وَنَسُوقُ ٱلْمُجْرِمِينَ إِلَىٰ جَهَنَّمَ وِرْدًۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 87, 'لَّا يَمْلِكُونَ ٱلشَّفَٰعَةَ إِلَّا مَنِ ٱتَّخَذَ عِندَ ٱلرَّحْمَٰنِ عَهْدًۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 88, 'وَقَالُوا۟ ٱتَّخَذَ ٱلرَّحْمَٰنُ وَلَدًۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 89, 'لَّقَدْ جِئْتُمْ شَيْـًٔا إِدًّۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 90, 'تَكَادُ ٱلسَّمَٰوَٰتُ يَتَفَطَّرْنَ مِنْهُ وَتَنشَقُّ ٱلْأَرْضُ وَتَخِرُّ ٱلْجِبَالُ هَدًّا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 91, 'أَن دَعَوْا۟ لِلرَّحْمَٰنِ وَلَدًۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 92, 'وَمَا يَنۢبَغِى لِلرَّحْمَٰنِ أَن يَتَّخِذَ وَلَدًا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 93, 'إِن كُلُّ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ إِلَّآ ءَاتِى ٱلرَّحْمَٰنِ عَبْدًۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 94, 'لَّقَدْ أَحْصَىٰهُمْ وَعَدَّهُمْ عَدًّۭا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 95, 'وَكُلُّهُمْ ءَاتِيهِ يَوْمَ ٱلْقِيَٰمَةِ فَرْدًا', NULL, 16, 124, 4, 311, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 96, 'إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ سَيَجْعَلُ لَهُمُ ٱلرَّحْمَٰنُ وُدًّۭا', NULL, 16, 124, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 97, 'فَإِنَّمَا يَسَّرْنَٰهُ بِلِسَانِكَ لِتُبَشِّرَ بِهِ ٱلْمُتَّقِينَ وَتُنذِرَ بِهِۦ قَوْمًۭا لُّدًّۭا', NULL, 16, 124, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 19), 98, 'وَكَمْ أَهْلَكْنَا قَبْلَهُم مِّن قَرْنٍ هَلْ تُحِسُّ مِنْهُم مِّنْ أَحَدٍ أَوْ تَسْمَعُ لَهُمْ رِكْزًۢا', NULL, 16, 124, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ طه', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 2, 'مَآ أَنزَلْنَا عَلَيْكَ ٱلْقُرْءَانَ لِتَشْقَىٰٓ', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 3, 'إِلَّا تَذْكِرَةًۭ لِّمَن يَخْشَىٰ', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 4, 'تَنزِيلًۭا مِّمَّنْ خَلَقَ ٱلْأَرْضَ وَٱلسَّمَٰوَٰتِ ٱلْعُلَى', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 5, 'ٱلرَّحْمَٰنُ عَلَى ٱلْعَرْشِ ٱسْتَوَىٰ', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 6, 'لَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ وَمَا بَيْنَهُمَا وَمَا تَحْتَ ٱلثَّرَىٰ', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 7, 'وَإِن تَجْهَرْ بِٱلْقَوْلِ فَإِنَّهُۥ يَعْلَمُ ٱلسِّرَّ وَأَخْفَى', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 8, 'ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ۖ لَهُ ٱلْأَسْمَآءُ ٱلْحُسْنَىٰ', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 9, 'وَهَلْ أَتَىٰكَ حَدِيثُ مُوسَىٰٓ', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 10, 'إِذْ رَءَا نَارًۭا فَقَالَ لِأَهْلِهِ ٱمْكُثُوٓا۟ إِنِّىٓ ءَانَسْتُ نَارًۭا لَّعَلِّىٓ ءَاتِيكُم مِّنْهَا بِقَبَسٍ أَوْ أَجِدُ عَلَى ٱلنَّارِ هُدًۭى', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 11, 'فَلَمَّآ أَتَىٰهَا نُودِىَ يَٰمُوسَىٰٓ', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 12, 'إِنِّىٓ أَنَا۠ رَبُّكَ فَٱخْلَعْ نَعْلَيْكَ ۖ إِنَّكَ بِٱلْوَادِ ٱلْمُقَدَّسِ طُوًۭى', NULL, 16, 125, 4, 312, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 13, 'وَأَنَا ٱخْتَرْتُكَ فَٱسْتَمِعْ لِمَا يُوحَىٰٓ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 14, 'إِنَّنِىٓ أَنَا ٱللَّهُ لَآ إِلَٰهَ إِلَّآ أَنَا۠ فَٱعْبُدْنِى وَأَقِمِ ٱلصَّلَوٰةَ لِذِكْرِىٓ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 15, 'إِنَّ ٱلسَّاعَةَ ءَاتِيَةٌ أَكَادُ أُخْفِيهَا لِتُجْزَىٰ كُلُّ نَفْسٍۭ بِمَا تَسْعَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 16, 'فَلَا يَصُدَّنَّكَ عَنْهَا مَن لَّا يُؤْمِنُ بِهَا وَٱتَّبَعَ هَوَىٰهُ فَتَرْدَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 17, 'وَمَا تِلْكَ بِيَمِينِكَ يَٰمُوسَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 18, 'قَالَ هِىَ عَصَاىَ أَتَوَكَّؤُا۟ عَلَيْهَا وَأَهُشُّ بِهَا عَلَىٰ غَنَمِى وَلِىَ فِيهَا مَـَٔارِبُ أُخْرَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 19, 'قَالَ أَلْقِهَا يَٰمُوسَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 20, 'فَأَلْقَىٰهَا فَإِذَا هِىَ حَيَّةٌۭ تَسْعَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 21, 'قَالَ خُذْهَا وَلَا تَخَفْ ۖ سَنُعِيدُهَا سِيرَتَهَا ٱلْأُولَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 22, 'وَٱضْمُمْ يَدَكَ إِلَىٰ جَنَاحِكَ تَخْرُجْ بَيْضَآءَ مِنْ غَيْرِ سُوٓءٍ ءَايَةً أُخْرَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 23, 'لِنُرِيَكَ مِنْ ءَايَٰتِنَا ٱلْكُبْرَى', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 24, 'ٱذْهَبْ إِلَىٰ فِرْعَوْنَ إِنَّهُۥ طَغَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 25, 'قَالَ رَبِّ ٱشْرَحْ لِى صَدْرِى', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 26, 'وَيَسِّرْ لِىٓ أَمْرِى', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 27, 'وَٱحْلُلْ عُقْدَةًۭ مِّن لِّسَانِى', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 28, 'يَفْقَهُوا۟ قَوْلِى', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 29, 'وَٱجْعَل لِّى وَزِيرًۭا مِّنْ أَهْلِى', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 30, 'هَٰرُونَ أَخِى', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 31, 'ٱشْدُدْ بِهِۦٓ أَزْرِى', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 32, 'وَأَشْرِكْهُ فِىٓ أَمْرِى', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 33, 'كَىْ نُسَبِّحَكَ كَثِيرًۭا', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 34, 'وَنَذْكُرَكَ كَثِيرًا', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 35, 'إِنَّكَ كُنتَ بِنَا بَصِيرًۭا', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 36, 'قَالَ قَدْ أُوتِيتَ سُؤْلَكَ يَٰمُوسَىٰ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 37, 'وَلَقَدْ مَنَنَّا عَلَيْكَ مَرَّةً أُخْرَىٰٓ', NULL, 16, 125, 4, 313, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 38, 'إِذْ أَوْحَيْنَآ إِلَىٰٓ أُمِّكَ مَا يُوحَىٰٓ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 39, 'أَنِ ٱقْذِفِيهِ فِى ٱلتَّابُوتِ فَٱقْذِفِيهِ فِى ٱلْيَمِّ فَلْيُلْقِهِ ٱلْيَمُّ بِٱلسَّاحِلِ يَأْخُذْهُ عَدُوٌّۭ لِّى وَعَدُوٌّۭ لَّهُۥ ۚ وَأَلْقَيْتُ عَلَيْكَ مَحَبَّةًۭ مِّنِّى وَلِتُصْنَعَ عَلَىٰ عَيْنِىٓ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 40, 'إِذْ تَمْشِىٓ أُخْتُكَ فَتَقُولُ هَلْ أَدُلُّكُمْ عَلَىٰ مَن يَكْفُلُهُۥ ۖ فَرَجَعْنَٰكَ إِلَىٰٓ أُمِّكَ كَىْ تَقَرَّ عَيْنُهَا وَلَا تَحْزَنَ ۚ وَقَتَلْتَ نَفْسًۭا فَنَجَّيْنَٰكَ مِنَ ٱلْغَمِّ وَفَتَنَّٰكَ فُتُونًۭا ۚ فَلَبِثْتَ سِنِينَ فِىٓ أَهْلِ مَدْيَنَ ثُمَّ جِئْتَ عَلَىٰ قَدَرٍۢ يَٰمُوسَىٰ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 41, 'وَٱصْطَنَعْتُكَ لِنَفْسِى', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 42, 'ٱذْهَبْ أَنتَ وَأَخُوكَ بِـَٔايَٰتِى وَلَا تَنِيَا فِى ذِكْرِى', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 43, 'ٱذْهَبَآ إِلَىٰ فِرْعَوْنَ إِنَّهُۥ طَغَىٰ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 44, 'فَقُولَا لَهُۥ قَوْلًۭا لَّيِّنًۭا لَّعَلَّهُۥ يَتَذَكَّرُ أَوْ يَخْشَىٰ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 45, 'قَالَا رَبَّنَآ إِنَّنَا نَخَافُ أَن يَفْرُطَ عَلَيْنَآ أَوْ أَن يَطْغَىٰ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 46, 'قَالَ لَا تَخَافَآ ۖ إِنَّنِى مَعَكُمَآ أَسْمَعُ وَأَرَىٰ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 47, 'فَأْتِيَاهُ فَقُولَآ إِنَّا رَسُولَا رَبِّكَ فَأَرْسِلْ مَعَنَا بَنِىٓ إِسْرَٰٓءِيلَ وَلَا تُعَذِّبْهُمْ ۖ قَدْ جِئْنَٰكَ بِـَٔايَةٍۢ مِّن رَّبِّكَ ۖ وَٱلسَّلَٰمُ عَلَىٰ مَنِ ٱتَّبَعَ ٱلْهُدَىٰٓ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 48, 'إِنَّا قَدْ أُوحِىَ إِلَيْنَآ أَنَّ ٱلْعَذَابَ عَلَىٰ مَن كَذَّبَ وَتَوَلَّىٰ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 49, 'قَالَ فَمَن رَّبُّكُمَا يَٰمُوسَىٰ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 50, 'قَالَ رَبُّنَا ٱلَّذِىٓ أَعْطَىٰ كُلَّ شَىْءٍ خَلْقَهُۥ ثُمَّ هَدَىٰ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 51, 'قَالَ فَمَا بَالُ ٱلْقُرُونِ ٱلْأُولَىٰ', NULL, 16, 125, 4, 314, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 52, 'قَالَ عِلْمُهَا عِندَ رَبِّى فِى كِتَٰبٍۢ ۖ لَّا يَضِلُّ رَبِّى وَلَا يَنسَى', NULL, 16, 125, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 53, 'ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ مَهْدًۭا وَسَلَكَ لَكُمْ فِيهَا سُبُلًۭا وَأَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَخْرَجْنَا بِهِۦٓ أَزْوَٰجًۭا مِّن نَّبَاتٍۢ شَتَّىٰ', NULL, 16, 125, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 54, 'كُلُوا۟ وَٱرْعَوْا۟ أَنْعَٰمَكُمْ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّأُو۟لِى ٱلنُّهَىٰ', NULL, 16, 125, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 55, '۞ مِنْهَا خَلَقْنَٰكُمْ وَفِيهَا نُعِيدُكُمْ وَمِنْهَا نُخْرِجُكُمْ تَارَةً أُخْرَىٰ', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 56, 'وَلَقَدْ أَرَيْنَٰهُ ءَايَٰتِنَا كُلَّهَا فَكَذَّبَ وَأَبَىٰ', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 57, 'قَالَ أَجِئْتَنَا لِتُخْرِجَنَا مِنْ أَرْضِنَا بِسِحْرِكَ يَٰمُوسَىٰ', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 58, 'فَلَنَأْتِيَنَّكَ بِسِحْرٍۢ مِّثْلِهِۦ فَٱجْعَلْ بَيْنَنَا وَبَيْنَكَ مَوْعِدًۭا لَّا نُخْلِفُهُۥ نَحْنُ وَلَآ أَنتَ مَكَانًۭا سُوًۭى', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 59, 'قَالَ مَوْعِدُكُمْ يَوْمُ ٱلزِّينَةِ وَأَن يُحْشَرَ ٱلنَّاسُ ضُحًۭى', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 60, 'فَتَوَلَّىٰ فِرْعَوْنُ فَجَمَعَ كَيْدَهُۥ ثُمَّ أَتَىٰ', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 61, 'قَالَ لَهُم مُّوسَىٰ وَيْلَكُمْ لَا تَفْتَرُوا۟ عَلَى ٱللَّهِ كَذِبًۭا فَيُسْحِتَكُم بِعَذَابٍۢ ۖ وَقَدْ خَابَ مَنِ ٱفْتَرَىٰ', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 62, 'فَتَنَٰزَعُوٓا۟ أَمْرَهُم بَيْنَهُمْ وَأَسَرُّوا۟ ٱلنَّجْوَىٰ', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 63, 'قَالُوٓا۟ إِنْ هَٰذَٰنِ لَسَٰحِرَٰنِ يُرِيدَانِ أَن يُخْرِجَاكُم مِّنْ أَرْضِكُم بِسِحْرِهِمَا وَيَذْهَبَا بِطَرِيقَتِكُمُ ٱلْمُثْلَىٰ', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 64, 'فَأَجْمِعُوا۟ كَيْدَكُمْ ثُمَّ ٱئْتُوا۟ صَفًّۭا ۚ وَقَدْ أَفْلَحَ ٱلْيَوْمَ مَنِ ٱسْتَعْلَىٰ', NULL, 16, 126, 4, 315, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 65, 'قَالُوا۟ يَٰمُوسَىٰٓ إِمَّآ أَن تُلْقِىَ وَإِمَّآ أَن نَّكُونَ أَوَّلَ مَنْ أَلْقَىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 66, 'قَالَ بَلْ أَلْقُوا۟ ۖ فَإِذَا حِبَالُهُمْ وَعِصِيُّهُمْ يُخَيَّلُ إِلَيْهِ مِن سِحْرِهِمْ أَنَّهَا تَسْعَىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 67, 'فَأَوْجَسَ فِى نَفْسِهِۦ خِيفَةًۭ مُّوسَىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 68, 'قُلْنَا لَا تَخَفْ إِنَّكَ أَنتَ ٱلْأَعْلَىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 69, 'وَأَلْقِ مَا فِى يَمِينِكَ تَلْقَفْ مَا صَنَعُوٓا۟ ۖ إِنَّمَا صَنَعُوا۟ كَيْدُ سَٰحِرٍۢ ۖ وَلَا يُفْلِحُ ٱلسَّاحِرُ حَيْثُ أَتَىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 70, 'فَأُلْقِىَ ٱلسَّحَرَةُ سُجَّدًۭا قَالُوٓا۟ ءَامَنَّا بِرَبِّ هَٰرُونَ وَمُوسَىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 71, 'قَالَ ءَامَنتُمْ لَهُۥ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّهُۥ لَكَبِيرُكُمُ ٱلَّذِى عَلَّمَكُمُ ٱلسِّحْرَ ۖ فَلَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَٰفٍۢ وَلَأُصَلِّبَنَّكُمْ فِى جُذُوعِ ٱلنَّخْلِ وَلَتَعْلَمُنَّ أَيُّنَآ أَشَدُّ عَذَابًۭا وَأَبْقَىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 72, 'قَالُوا۟ لَن نُّؤْثِرَكَ عَلَىٰ مَا جَآءَنَا مِنَ ٱلْبَيِّنَٰتِ وَٱلَّذِى فَطَرَنَا ۖ فَٱقْضِ مَآ أَنتَ قَاضٍ ۖ إِنَّمَا تَقْضِى هَٰذِهِ ٱلْحَيَوٰةَ ٱلدُّنْيَآ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 73, 'إِنَّآ ءَامَنَّا بِرَبِّنَا لِيَغْفِرَ لَنَا خَطَٰيَٰنَا وَمَآ أَكْرَهْتَنَا عَلَيْهِ مِنَ ٱلسِّحْرِ ۗ وَٱللَّهُ خَيْرٌۭ وَأَبْقَىٰٓ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 74, 'إِنَّهُۥ مَن يَأْتِ رَبَّهُۥ مُجْرِمًۭا فَإِنَّ لَهُۥ جَهَنَّمَ لَا يَمُوتُ فِيهَا وَلَا يَحْيَىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 75, 'وَمَن يَأْتِهِۦ مُؤْمِنًۭا قَدْ عَمِلَ ٱلصَّٰلِحَٰتِ فَأُو۟لَٰٓئِكَ لَهُمُ ٱلدَّرَجَٰتُ ٱلْعُلَىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 76, 'جَنَّٰتُ عَدْنٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ وَذَٰلِكَ جَزَآءُ مَن تَزَكَّىٰ', NULL, 16, 126, 4, 316, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 77, 'وَلَقَدْ أَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَسْرِ بِعِبَادِى فَٱضْرِبْ لَهُمْ طَرِيقًۭا فِى ٱلْبَحْرِ يَبَسًۭا لَّا تَخَٰفُ دَرَكًۭا وَلَا تَخْشَىٰ', NULL, 16, 126, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 78, 'فَأَتْبَعَهُمْ فِرْعَوْنُ بِجُنُودِهِۦ فَغَشِيَهُم مِّنَ ٱلْيَمِّ مَا غَشِيَهُمْ', NULL, 16, 126, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 79, 'وَأَضَلَّ فِرْعَوْنُ قَوْمَهُۥ وَمَا هَدَىٰ', NULL, 16, 126, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 80, 'يَٰبَنِىٓ إِسْرَٰٓءِيلَ قَدْ أَنجَيْنَٰكُم مِّنْ عَدُوِّكُمْ وَوَٰعَدْنَٰكُمْ جَانِبَ ٱلطُّورِ ٱلْأَيْمَنَ وَنَزَّلْنَا عَلَيْكُمُ ٱلْمَنَّ وَٱلسَّلْوَىٰ', NULL, 16, 126, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 81, 'كُلُوا۟ مِن طَيِّبَٰتِ مَا رَزَقْنَٰكُمْ وَلَا تَطْغَوْا۟ فِيهِ فَيَحِلَّ عَلَيْكُمْ غَضَبِى ۖ وَمَن يَحْلِلْ عَلَيْهِ غَضَبِى فَقَدْ هَوَىٰ', NULL, 16, 126, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 82, 'وَإِنِّى لَغَفَّارٌۭ لِّمَن تَابَ وَءَامَنَ وَعَمِلَ صَٰلِحًۭا ثُمَّ ٱهْتَدَىٰ', NULL, 16, 126, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 83, '۞ وَمَآ أَعْجَلَكَ عَن قَوْمِكَ يَٰمُوسَىٰ', NULL, 16, 127, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 84, 'قَالَ هُمْ أُو۟لَآءِ عَلَىٰٓ أَثَرِى وَعَجِلْتُ إِلَيْكَ رَبِّ لِتَرْضَىٰ', NULL, 16, 127, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 85, 'قَالَ فَإِنَّا قَدْ فَتَنَّا قَوْمَكَ مِنۢ بَعْدِكَ وَأَضَلَّهُمُ ٱلسَّامِرِىُّ', NULL, 16, 127, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 86, 'فَرَجَعَ مُوسَىٰٓ إِلَىٰ قَوْمِهِۦ غَضْبَٰنَ أَسِفًۭا ۚ قَالَ يَٰقَوْمِ أَلَمْ يَعِدْكُمْ رَبُّكُمْ وَعْدًا حَسَنًا ۚ أَفَطَالَ عَلَيْكُمُ ٱلْعَهْدُ أَمْ أَرَدتُّمْ أَن يَحِلَّ عَلَيْكُمْ غَضَبٌۭ مِّن رَّبِّكُمْ فَأَخْلَفْتُم مَّوْعِدِى', NULL, 16, 127, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 87, 'قَالُوا۟ مَآ أَخْلَفْنَا مَوْعِدَكَ بِمَلْكِنَا وَلَٰكِنَّا حُمِّلْنَآ أَوْزَارًۭا مِّن زِينَةِ ٱلْقَوْمِ فَقَذَفْنَٰهَا فَكَذَٰلِكَ أَلْقَى ٱلسَّامِرِىُّ', NULL, 16, 127, 4, 317, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 88, 'فَأَخْرَجَ لَهُمْ عِجْلًۭا جَسَدًۭا لَّهُۥ خُوَارٌۭ فَقَالُوا۟ هَٰذَآ إِلَٰهُكُمْ وَإِلَٰهُ مُوسَىٰ فَنَسِىَ', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 89, 'أَفَلَا يَرَوْنَ أَلَّا يَرْجِعُ إِلَيْهِمْ قَوْلًۭا وَلَا يَمْلِكُ لَهُمْ ضَرًّۭا وَلَا نَفْعًۭا', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 90, 'وَلَقَدْ قَالَ لَهُمْ هَٰرُونُ مِن قَبْلُ يَٰقَوْمِ إِنَّمَا فُتِنتُم بِهِۦ ۖ وَإِنَّ رَبَّكُمُ ٱلرَّحْمَٰنُ فَٱتَّبِعُونِى وَأَطِيعُوٓا۟ أَمْرِى', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 91, 'قَالُوا۟ لَن نَّبْرَحَ عَلَيْهِ عَٰكِفِينَ حَتَّىٰ يَرْجِعَ إِلَيْنَا مُوسَىٰ', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 92, 'قَالَ يَٰهَٰرُونُ مَا مَنَعَكَ إِذْ رَأَيْتَهُمْ ضَلُّوٓا۟', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 93, 'أَلَّا تَتَّبِعَنِ ۖ أَفَعَصَيْتَ أَمْرِى', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 94, 'قَالَ يَبْنَؤُمَّ لَا تَأْخُذْ بِلِحْيَتِى وَلَا بِرَأْسِىٓ ۖ إِنِّى خَشِيتُ أَن تَقُولَ فَرَّقْتَ بَيْنَ بَنِىٓ إِسْرَٰٓءِيلَ وَلَمْ تَرْقُبْ قَوْلِى', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 95, 'قَالَ فَمَا خَطْبُكَ يَٰسَٰمِرِىُّ', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 96, 'قَالَ بَصُرْتُ بِمَا لَمْ يَبْصُرُوا۟ بِهِۦ فَقَبَضْتُ قَبْضَةًۭ مِّنْ أَثَرِ ٱلرَّسُولِ فَنَبَذْتُهَا وَكَذَٰلِكَ سَوَّلَتْ لِى نَفْسِى', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 97, 'قَالَ فَٱذْهَبْ فَإِنَّ لَكَ فِى ٱلْحَيَوٰةِ أَن تَقُولَ لَا مِسَاسَ ۖ وَإِنَّ لَكَ مَوْعِدًۭا لَّن تُخْلَفَهُۥ ۖ وَٱنظُرْ إِلَىٰٓ إِلَٰهِكَ ٱلَّذِى ظَلْتَ عَلَيْهِ عَاكِفًۭا ۖ لَّنُحَرِّقَنَّهُۥ ثُمَّ لَنَنسِفَنَّهُۥ فِى ٱلْيَمِّ نَسْفًا', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 98, 'إِنَّمَآ إِلَٰهُكُمُ ٱللَّهُ ٱلَّذِى لَآ إِلَٰهَ إِلَّا هُوَ ۚ وَسِعَ كُلَّ شَىْءٍ عِلْمًۭا', NULL, 16, 127, 4, 318, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 99, 'كَذَٰلِكَ نَقُصُّ عَلَيْكَ مِنْ أَنۢبَآءِ مَا قَدْ سَبَقَ ۚ وَقَدْ ءَاتَيْنَٰكَ مِن لَّدُنَّا ذِكْرًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 100, 'مَّنْ أَعْرَضَ عَنْهُ فَإِنَّهُۥ يَحْمِلُ يَوْمَ ٱلْقِيَٰمَةِ وِزْرًا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 101, 'خَٰلِدِينَ فِيهِ ۖ وَسَآءَ لَهُمْ يَوْمَ ٱلْقِيَٰمَةِ حِمْلًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 102, 'يَوْمَ يُنفَخُ فِى ٱلصُّورِ ۚ وَنَحْشُرُ ٱلْمُجْرِمِينَ يَوْمَئِذٍۢ زُرْقًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 103, 'يَتَخَٰفَتُونَ بَيْنَهُمْ إِن لَّبِثْتُمْ إِلَّا عَشْرًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 104, 'نَّحْنُ أَعْلَمُ بِمَا يَقُولُونَ إِذْ يَقُولُ أَمْثَلُهُمْ طَرِيقَةً إِن لَّبِثْتُمْ إِلَّا يَوْمًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 105, 'وَيَسْـَٔلُونَكَ عَنِ ٱلْجِبَالِ فَقُلْ يَنسِفُهَا رَبِّى نَسْفًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 106, 'فَيَذَرُهَا قَاعًۭا صَفْصَفًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 107, 'لَّا تَرَىٰ فِيهَا عِوَجًۭا وَلَآ أَمْتًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 108, 'يَوْمَئِذٍۢ يَتَّبِعُونَ ٱلدَّاعِىَ لَا عِوَجَ لَهُۥ ۖ وَخَشَعَتِ ٱلْأَصْوَاتُ لِلرَّحْمَٰنِ فَلَا تَسْمَعُ إِلَّا هَمْسًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 109, 'يَوْمَئِذٍۢ لَّا تَنفَعُ ٱلشَّفَٰعَةُ إِلَّا مَنْ أَذِنَ لَهُ ٱلرَّحْمَٰنُ وَرَضِىَ لَهُۥ قَوْلًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 110, 'يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَلَا يُحِيطُونَ بِهِۦ عِلْمًۭا', NULL, 16, 127, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 111, '۞ وَعَنَتِ ٱلْوُجُوهُ لِلْحَىِّ ٱلْقَيُّومِ ۖ وَقَدْ خَابَ مَنْ حَمَلَ ظُلْمًۭا', NULL, 16, 128, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 112, 'وَمَن يَعْمَلْ مِنَ ٱلصَّٰلِحَٰتِ وَهُوَ مُؤْمِنٌۭ فَلَا يَخَافُ ظُلْمًۭا وَلَا هَضْمًۭا', NULL, 16, 128, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 113, 'وَكَذَٰلِكَ أَنزَلْنَٰهُ قُرْءَانًا عَرَبِيًّۭا وَصَرَّفْنَا فِيهِ مِنَ ٱلْوَعِيدِ لَعَلَّهُمْ يَتَّقُونَ أَوْ يُحْدِثُ لَهُمْ ذِكْرًۭا', NULL, 16, 128, 4, 319, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 114, 'فَتَعَٰلَى ٱللَّهُ ٱلْمَلِكُ ٱلْحَقُّ ۗ وَلَا تَعْجَلْ بِٱلْقُرْءَانِ مِن قَبْلِ أَن يُقْضَىٰٓ إِلَيْكَ وَحْيُهُۥ ۖ وَقُل رَّبِّ زِدْنِى عِلْمًۭا', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 115, 'وَلَقَدْ عَهِدْنَآ إِلَىٰٓ ءَادَمَ مِن قَبْلُ فَنَسِىَ وَلَمْ نَجِدْ لَهُۥ عَزْمًۭا', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 116, 'وَإِذْ قُلْنَا لِلْمَلَٰٓئِكَةِ ٱسْجُدُوا۟ لِءَادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ أَبَىٰ', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 117, 'فَقُلْنَا يَٰٓـَٔادَمُ إِنَّ هَٰذَا عَدُوٌّۭ لَّكَ وَلِزَوْجِكَ فَلَا يُخْرِجَنَّكُمَا مِنَ ٱلْجَنَّةِ فَتَشْقَىٰٓ', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 118, 'إِنَّ لَكَ أَلَّا تَجُوعَ فِيهَا وَلَا تَعْرَىٰ', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 119, 'وَأَنَّكَ لَا تَظْمَؤُا۟ فِيهَا وَلَا تَضْحَىٰ', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 120, 'فَوَسْوَسَ إِلَيْهِ ٱلشَّيْطَٰنُ قَالَ يَٰٓـَٔادَمُ هَلْ أَدُلُّكَ عَلَىٰ شَجَرَةِ ٱلْخُلْدِ وَمُلْكٍۢ لَّا يَبْلَىٰ', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 121, 'فَأَكَلَا مِنْهَا فَبَدَتْ لَهُمَا سَوْءَٰتُهُمَا وَطَفِقَا يَخْصِفَانِ عَلَيْهِمَا مِن وَرَقِ ٱلْجَنَّةِ ۚ وَعَصَىٰٓ ءَادَمُ رَبَّهُۥ فَغَوَىٰ', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 122, 'ثُمَّ ٱجْتَبَٰهُ رَبُّهُۥ فَتَابَ عَلَيْهِ وَهَدَىٰ', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 123, 'قَالَ ٱهْبِطَا مِنْهَا جَمِيعًۢا ۖ بَعْضُكُمْ لِبَعْضٍ عَدُوٌّۭ ۖ فَإِمَّا يَأْتِيَنَّكُم مِّنِّى هُدًۭى فَمَنِ ٱتَّبَعَ هُدَاىَ فَلَا يَضِلُّ وَلَا يَشْقَىٰ', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 124, 'وَمَنْ أَعْرَضَ عَن ذِكْرِى فَإِنَّ لَهُۥ مَعِيشَةًۭ ضَنكًۭا وَنَحْشُرُهُۥ يَوْمَ ٱلْقِيَٰمَةِ أَعْمَىٰ', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 125, 'قَالَ رَبِّ لِمَ حَشَرْتَنِىٓ أَعْمَىٰ وَقَدْ كُنتُ بَصِيرًۭا', NULL, 16, 128, 4, 320, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 126, 'قَالَ كَذَٰلِكَ أَتَتْكَ ءَايَٰتُنَا فَنَسِيتَهَا ۖ وَكَذَٰلِكَ ٱلْيَوْمَ تُنسَىٰ', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 127, 'وَكَذَٰلِكَ نَجْزِى مَنْ أَسْرَفَ وَلَمْ يُؤْمِنۢ بِـَٔايَٰتِ رَبِّهِۦ ۚ وَلَعَذَابُ ٱلْءَاخِرَةِ أَشَدُّ وَأَبْقَىٰٓ', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 128, 'أَفَلَمْ يَهْدِ لَهُمْ كَمْ أَهْلَكْنَا قَبْلَهُم مِّنَ ٱلْقُرُونِ يَمْشُونَ فِى مَسَٰكِنِهِمْ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّأُو۟لِى ٱلنُّهَىٰ', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 129, 'وَلَوْلَا كَلِمَةٌۭ سَبَقَتْ مِن رَّبِّكَ لَكَانَ لِزَامًۭا وَأَجَلٌۭ مُّسَمًّۭى', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 130, 'فَٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ ٱلشَّمْسِ وَقَبْلَ غُرُوبِهَا ۖ وَمِنْ ءَانَآئِ ٱلَّيْلِ فَسَبِّحْ وَأَطْرَافَ ٱلنَّهَارِ لَعَلَّكَ تَرْضَىٰ', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 131, 'وَلَا تَمُدَّنَّ عَيْنَيْكَ إِلَىٰ مَا مَتَّعْنَا بِهِۦٓ أَزْوَٰجًۭا مِّنْهُمْ زَهْرَةَ ٱلْحَيَوٰةِ ٱلدُّنْيَا لِنَفْتِنَهُمْ فِيهِ ۚ وَرِزْقُ رَبِّكَ خَيْرٌۭ وَأَبْقَىٰ', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 132, 'وَأْمُرْ أَهْلَكَ بِٱلصَّلَوٰةِ وَٱصْطَبِرْ عَلَيْهَا ۖ لَا نَسْـَٔلُكَ رِزْقًۭا ۖ نَّحْنُ نَرْزُقُكَ ۗ وَٱلْعَٰقِبَةُ لِلتَّقْوَىٰ', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 133, 'وَقَالُوا۟ لَوْلَا يَأْتِينَا بِـَٔايَةٍۢ مِّن رَّبِّهِۦٓ ۚ أَوَلَمْ تَأْتِهِم بَيِّنَةُ مَا فِى ٱلصُّحُفِ ٱلْأُولَىٰ', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 134, 'وَلَوْ أَنَّآ أَهْلَكْنَٰهُم بِعَذَابٍۢ مِّن قَبْلِهِۦ لَقَالُوا۟ رَبَّنَا لَوْلَآ أَرْسَلْتَ إِلَيْنَا رَسُولًۭا فَنَتَّبِعَ ءَايَٰتِكَ مِن قَبْلِ أَن نَّذِلَّ وَنَخْزَىٰ', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 20), 135, 'قُلْ كُلٌّۭ مُّتَرَبِّصٌۭ فَتَرَبَّصُوا۟ ۖ فَسَتَعْلَمُونَ مَنْ أَصْحَٰبُ ٱلصِّرَٰطِ ٱلسَّوِىِّ وَمَنِ ٱهْتَدَىٰ', NULL, 16, 128, 4, 321, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ ٱقْتَرَبَ لِلنَّاسِ حِسَابُهُمْ وَهُمْ فِى غَفْلَةٍۢ مُّعْرِضُونَ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 2, 'مَا يَأْتِيهِم مِّن ذِكْرٍۢ مِّن رَّبِّهِم مُّحْدَثٍ إِلَّا ٱسْتَمَعُوهُ وَهُمْ يَلْعَبُونَ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 3, 'لَاهِيَةًۭ قُلُوبُهُمْ ۗ وَأَسَرُّوا۟ ٱلنَّجْوَى ٱلَّذِينَ ظَلَمُوا۟ هَلْ هَٰذَآ إِلَّا بَشَرٌۭ مِّثْلُكُمْ ۖ أَفَتَأْتُونَ ٱلسِّحْرَ وَأَنتُمْ تُبْصِرُونَ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 4, 'قَالَ رَبِّى يَعْلَمُ ٱلْقَوْلَ فِى ٱلسَّمَآءِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 5, 'بَلْ قَالُوٓا۟ أَضْغَٰثُ أَحْلَٰمٍۭ بَلِ ٱفْتَرَىٰهُ بَلْ هُوَ شَاعِرٌۭ فَلْيَأْتِنَا بِـَٔايَةٍۢ كَمَآ أُرْسِلَ ٱلْأَوَّلُونَ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 6, 'مَآ ءَامَنَتْ قَبْلَهُم مِّن قَرْيَةٍ أَهْلَكْنَٰهَآ ۖ أَفَهُمْ يُؤْمِنُونَ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 7, 'وَمَآ أَرْسَلْنَا قَبْلَكَ إِلَّا رِجَالًۭا نُّوحِىٓ إِلَيْهِمْ ۖ فَسْـَٔلُوٓا۟ أَهْلَ ٱلذِّكْرِ إِن كُنتُمْ لَا تَعْلَمُونَ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 8, 'وَمَا جَعَلْنَٰهُمْ جَسَدًۭا لَّا يَأْكُلُونَ ٱلطَّعَامَ وَمَا كَانُوا۟ خَٰلِدِينَ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 9, 'ثُمَّ صَدَقْنَٰهُمُ ٱلْوَعْدَ فَأَنجَيْنَٰهُمْ وَمَن نَّشَآءُ وَأَهْلَكْنَا ٱلْمُسْرِفِينَ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 10, 'لَقَدْ أَنزَلْنَآ إِلَيْكُمْ كِتَٰبًۭا فِيهِ ذِكْرُكُمْ ۖ أَفَلَا تَعْقِلُونَ', NULL, 17, 129, 4, 322, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 11, 'وَكَمْ قَصَمْنَا مِن قَرْيَةٍۢ كَانَتْ ظَالِمَةًۭ وَأَنشَأْنَا بَعْدَهَا قَوْمًا ءَاخَرِينَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 12, 'فَلَمَّآ أَحَسُّوا۟ بَأْسَنَآ إِذَا هُم مِّنْهَا يَرْكُضُونَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 13, 'لَا تَرْكُضُوا۟ وَٱرْجِعُوٓا۟ إِلَىٰ مَآ أُتْرِفْتُمْ فِيهِ وَمَسَٰكِنِكُمْ لَعَلَّكُمْ تُسْـَٔلُونَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 14, 'قَالُوا۟ يَٰوَيْلَنَآ إِنَّا كُنَّا ظَٰلِمِينَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 15, 'فَمَا زَالَت تِّلْكَ دَعْوَىٰهُمْ حَتَّىٰ جَعَلْنَٰهُمْ حَصِيدًا خَٰمِدِينَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 16, 'وَمَا خَلَقْنَا ٱلسَّمَآءَ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا لَٰعِبِينَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 17, 'لَوْ أَرَدْنَآ أَن نَّتَّخِذَ لَهْوًۭا لَّٱتَّخَذْنَٰهُ مِن لَّدُنَّآ إِن كُنَّا فَٰعِلِينَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 18, 'بَلْ نَقْذِفُ بِٱلْحَقِّ عَلَى ٱلْبَٰطِلِ فَيَدْمَغُهُۥ فَإِذَا هُوَ زَاهِقٌۭ ۚ وَلَكُمُ ٱلْوَيْلُ مِمَّا تَصِفُونَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 19, 'وَلَهُۥ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَمَنْ عِندَهُۥ لَا يَسْتَكْبِرُونَ عَنْ عِبَادَتِهِۦ وَلَا يَسْتَحْسِرُونَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 20, 'يُسَبِّحُونَ ٱلَّيْلَ وَٱلنَّهَارَ لَا يَفْتُرُونَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 21, 'أَمِ ٱتَّخَذُوٓا۟ ءَالِهَةًۭ مِّنَ ٱلْأَرْضِ هُمْ يُنشِرُونَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 22, 'لَوْ كَانَ فِيهِمَآ ءَالِهَةٌ إِلَّا ٱللَّهُ لَفَسَدَتَا ۚ فَسُبْحَٰنَ ٱللَّهِ رَبِّ ٱلْعَرْشِ عَمَّا يَصِفُونَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 23, 'لَا يُسْـَٔلُ عَمَّا يَفْعَلُ وَهُمْ يُسْـَٔلُونَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 24, 'أَمِ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ ءَالِهَةًۭ ۖ قُلْ هَاتُوا۟ بُرْهَٰنَكُمْ ۖ هَٰذَا ذِكْرُ مَن مَّعِىَ وَذِكْرُ مَن قَبْلِى ۗ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ ٱلْحَقَّ ۖ فَهُم مُّعْرِضُونَ', NULL, 17, 129, 4, 323, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 25, 'وَمَآ أَرْسَلْنَا مِن قَبْلِكَ مِن رَّسُولٍ إِلَّا نُوحِىٓ إِلَيْهِ أَنَّهُۥ لَآ إِلَٰهَ إِلَّآ أَنَا۠ فَٱعْبُدُونِ', NULL, 17, 129, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 26, 'وَقَالُوا۟ ٱتَّخَذَ ٱلرَّحْمَٰنُ وَلَدًۭا ۗ سُبْحَٰنَهُۥ ۚ بَلْ عِبَادٌۭ مُّكْرَمُونَ', NULL, 17, 129, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 27, 'لَا يَسْبِقُونَهُۥ بِٱلْقَوْلِ وَهُم بِأَمْرِهِۦ يَعْمَلُونَ', NULL, 17, 129, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 28, 'يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَلَا يَشْفَعُونَ إِلَّا لِمَنِ ٱرْتَضَىٰ وَهُم مِّنْ خَشْيَتِهِۦ مُشْفِقُونَ', NULL, 17, 129, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 29, '۞ وَمَن يَقُلْ مِنْهُمْ إِنِّىٓ إِلَٰهٌۭ مِّن دُونِهِۦ فَذَٰلِكَ نَجْزِيهِ جَهَنَّمَ ۚ كَذَٰلِكَ نَجْزِى ٱلظَّٰلِمِينَ', NULL, 17, 130, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 30, 'أَوَلَمْ يَرَ ٱلَّذِينَ كَفَرُوٓا۟ أَنَّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ كَانَتَا رَتْقًۭا فَفَتَقْنَٰهُمَا ۖ وَجَعَلْنَا مِنَ ٱلْمَآءِ كُلَّ شَىْءٍ حَىٍّ ۖ أَفَلَا يُؤْمِنُونَ', NULL, 17, 130, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 31, 'وَجَعَلْنَا فِى ٱلْأَرْضِ رَوَٰسِىَ أَن تَمِيدَ بِهِمْ وَجَعَلْنَا فِيهَا فِجَاجًۭا سُبُلًۭا لَّعَلَّهُمْ يَهْتَدُونَ', NULL, 17, 130, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 32, 'وَجَعَلْنَا ٱلسَّمَآءَ سَقْفًۭا مَّحْفُوظًۭا ۖ وَهُمْ عَنْ ءَايَٰتِهَا مُعْرِضُونَ', NULL, 17, 130, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 33, 'وَهُوَ ٱلَّذِى خَلَقَ ٱلَّيْلَ وَٱلنَّهَارَ وَٱلشَّمْسَ وَٱلْقَمَرَ ۖ كُلٌّۭ فِى فَلَكٍۢ يَسْبَحُونَ', NULL, 17, 130, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 34, 'وَمَا جَعَلْنَا لِبَشَرٍۢ مِّن قَبْلِكَ ٱلْخُلْدَ ۖ أَفَإِي۟ن مِّتَّ فَهُمُ ٱلْخَٰلِدُونَ', NULL, 17, 130, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 35, 'كُلُّ نَفْسٍۢ ذَآئِقَةُ ٱلْمَوْتِ ۗ وَنَبْلُوكُم بِٱلشَّرِّ وَٱلْخَيْرِ فِتْنَةًۭ ۖ وَإِلَيْنَا تُرْجَعُونَ', NULL, 17, 130, 4, 324, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 36, 'وَإِذَا رَءَاكَ ٱلَّذِينَ كَفَرُوٓا۟ إِن يَتَّخِذُونَكَ إِلَّا هُزُوًا أَهَٰذَا ٱلَّذِى يَذْكُرُ ءَالِهَتَكُمْ وَهُم بِذِكْرِ ٱلرَّحْمَٰنِ هُمْ كَٰفِرُونَ', NULL, 17, 130, 4, 325, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 37, 'خُلِقَ ٱلْإِنسَٰنُ مِنْ عَجَلٍۢ ۚ سَأُو۟رِيكُمْ ءَايَٰتِى فَلَا تَسْتَعْجِلُونِ', NULL, 17, 130, 4, 325, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 38, 'وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ', NULL, 17, 130, 4, 325, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 39, 'لَوْ يَعْلَمُ ٱلَّذِينَ كَفَرُوا۟ حِينَ لَا يَكُفُّونَ عَن وُجُوهِهِمُ ٱلنَّارَ وَلَا عَن ظُهُورِهِمْ وَلَا هُمْ يُنصَرُونَ', NULL, 17, 130, 4, 325, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 40, 'بَلْ تَأْتِيهِم بَغْتَةًۭ فَتَبْهَتُهُمْ فَلَا يَسْتَطِيعُونَ رَدَّهَا وَلَا هُمْ يُنظَرُونَ', NULL, 17, 130, 4, 325, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 41, 'وَلَقَدِ ٱسْتُهْزِئَ بِرُسُلٍۢ مِّن قَبْلِكَ فَحَاقَ بِٱلَّذِينَ سَخِرُوا۟ مِنْهُم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ', NULL, 17, 130, 4, 325, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 42, 'قُلْ مَن يَكْلَؤُكُم بِٱلَّيْلِ وَٱلنَّهَارِ مِنَ ٱلرَّحْمَٰنِ ۗ بَلْ هُمْ عَن ذِكْرِ رَبِّهِم مُّعْرِضُونَ', NULL, 17, 130, 4, 325, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 43, 'أَمْ لَهُمْ ءَالِهَةٌۭ تَمْنَعُهُم مِّن دُونِنَا ۚ لَا يَسْتَطِيعُونَ نَصْرَ أَنفُسِهِمْ وَلَا هُم مِّنَّا يُصْحَبُونَ', NULL, 17, 130, 4, 325, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 44, 'بَلْ مَتَّعْنَا هَٰٓؤُلَآءِ وَءَابَآءَهُمْ حَتَّىٰ طَالَ عَلَيْهِمُ ٱلْعُمُرُ ۗ أَفَلَا يَرَوْنَ أَنَّا نَأْتِى ٱلْأَرْضَ نَنقُصُهَا مِنْ أَطْرَافِهَآ ۚ أَفَهُمُ ٱلْغَٰلِبُونَ', NULL, 17, 130, 4, 325, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 45, 'قُلْ إِنَّمَآ أُنذِرُكُم بِٱلْوَحْىِ ۚ وَلَا يَسْمَعُ ٱلصُّمُّ ٱلدُّعَآءَ إِذَا مَا يُنذَرُونَ', NULL, 17, 130, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 46, 'وَلَئِن مَّسَّتْهُمْ نَفْحَةٌۭ مِّنْ عَذَابِ رَبِّكَ لَيَقُولُنَّ يَٰوَيْلَنَآ إِنَّا كُنَّا ظَٰلِمِينَ', NULL, 17, 130, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 47, 'وَنَضَعُ ٱلْمَوَٰزِينَ ٱلْقِسْطَ لِيَوْمِ ٱلْقِيَٰمَةِ فَلَا تُظْلَمُ نَفْسٌۭ شَيْـًۭٔا ۖ وَإِن كَانَ مِثْقَالَ حَبَّةٍۢ مِّنْ خَرْدَلٍ أَتَيْنَا بِهَا ۗ وَكَفَىٰ بِنَا حَٰسِبِينَ', NULL, 17, 130, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 48, 'وَلَقَدْ ءَاتَيْنَا مُوسَىٰ وَهَٰرُونَ ٱلْفُرْقَانَ وَضِيَآءًۭ وَذِكْرًۭا لِّلْمُتَّقِينَ', NULL, 17, 130, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 49, 'ٱلَّذِينَ يَخْشَوْنَ رَبَّهُم بِٱلْغَيْبِ وَهُم مِّنَ ٱلسَّاعَةِ مُشْفِقُونَ', NULL, 17, 130, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 50, 'وَهَٰذَا ذِكْرٌۭ مُّبَارَكٌ أَنزَلْنَٰهُ ۚ أَفَأَنتُمْ لَهُۥ مُنكِرُونَ', NULL, 17, 130, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 51, '۞ وَلَقَدْ ءَاتَيْنَآ إِبْرَٰهِيمَ رُشْدَهُۥ مِن قَبْلُ وَكُنَّا بِهِۦ عَٰلِمِينَ', NULL, 17, 131, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 52, 'إِذْ قَالَ لِأَبِيهِ وَقَوْمِهِۦ مَا هَٰذِهِ ٱلتَّمَاثِيلُ ٱلَّتِىٓ أَنتُمْ لَهَا عَٰكِفُونَ', NULL, 17, 131, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 53, 'قَالُوا۟ وَجَدْنَآ ءَابَآءَنَا لَهَا عَٰبِدِينَ', NULL, 17, 131, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 54, 'قَالَ لَقَدْ كُنتُمْ أَنتُمْ وَءَابَآؤُكُمْ فِى ضَلَٰلٍۢ مُّبِينٍۢ', NULL, 17, 131, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 55, 'قَالُوٓا۟ أَجِئْتَنَا بِٱلْحَقِّ أَمْ أَنتَ مِنَ ٱللَّٰعِبِينَ', NULL, 17, 131, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 56, 'قَالَ بَل رَّبُّكُمْ رَبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ٱلَّذِى فَطَرَهُنَّ وَأَنَا۠ عَلَىٰ ذَٰلِكُم مِّنَ ٱلشَّٰهِدِينَ', NULL, 17, 131, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 57, 'وَتَٱللَّهِ لَأَكِيدَنَّ أَصْنَٰمَكُم بَعْدَ أَن تُوَلُّوا۟ مُدْبِرِينَ', NULL, 17, 131, 4, 326, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 58, 'فَجَعَلَهُمْ جُذَٰذًا إِلَّا كَبِيرًۭا لَّهُمْ لَعَلَّهُمْ إِلَيْهِ يَرْجِعُونَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 59, 'قَالُوا۟ مَن فَعَلَ هَٰذَا بِـَٔالِهَتِنَآ إِنَّهُۥ لَمِنَ ٱلظَّٰلِمِينَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 60, 'قَالُوا۟ سَمِعْنَا فَتًۭى يَذْكُرُهُمْ يُقَالُ لَهُۥٓ إِبْرَٰهِيمُ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 61, 'قَالُوا۟ فَأْتُوا۟ بِهِۦ عَلَىٰٓ أَعْيُنِ ٱلنَّاسِ لَعَلَّهُمْ يَشْهَدُونَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 62, 'قَالُوٓا۟ ءَأَنتَ فَعَلْتَ هَٰذَا بِـَٔالِهَتِنَا يَٰٓإِبْرَٰهِيمُ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 63, 'قَالَ بَلْ فَعَلَهُۥ كَبِيرُهُمْ هَٰذَا فَسْـَٔلُوهُمْ إِن كَانُوا۟ يَنطِقُونَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 64, 'فَرَجَعُوٓا۟ إِلَىٰٓ أَنفُسِهِمْ فَقَالُوٓا۟ إِنَّكُمْ أَنتُمُ ٱلظَّٰلِمُونَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 65, 'ثُمَّ نُكِسُوا۟ عَلَىٰ رُءُوسِهِمْ لَقَدْ عَلِمْتَ مَا هَٰٓؤُلَآءِ يَنطِقُونَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 66, 'قَالَ أَفَتَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُكُمْ شَيْـًۭٔا وَلَا يَضُرُّكُمْ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 67, 'أُفٍّۢ لَّكُمْ وَلِمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ ۖ أَفَلَا تَعْقِلُونَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 68, 'قَالُوا۟ حَرِّقُوهُ وَٱنصُرُوٓا۟ ءَالِهَتَكُمْ إِن كُنتُمْ فَٰعِلِينَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 69, 'قُلْنَا يَٰنَارُ كُونِى بَرْدًۭا وَسَلَٰمًا عَلَىٰٓ إِبْرَٰهِيمَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 70, 'وَأَرَادُوا۟ بِهِۦ كَيْدًۭا فَجَعَلْنَٰهُمُ ٱلْأَخْسَرِينَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 71, 'وَنَجَّيْنَٰهُ وَلُوطًا إِلَى ٱلْأَرْضِ ٱلَّتِى بَٰرَكْنَا فِيهَا لِلْعَٰلَمِينَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 72, 'وَوَهَبْنَا لَهُۥٓ إِسْحَٰقَ وَيَعْقُوبَ نَافِلَةًۭ ۖ وَكُلًّۭا جَعَلْنَا صَٰلِحِينَ', NULL, 17, 131, 4, 327, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 73, 'وَجَعَلْنَٰهُمْ أَئِمَّةًۭ يَهْدُونَ بِأَمْرِنَا وَأَوْحَيْنَآ إِلَيْهِمْ فِعْلَ ٱلْخَيْرَٰتِ وَإِقَامَ ٱلصَّلَوٰةِ وَإِيتَآءَ ٱلزَّكَوٰةِ ۖ وَكَانُوا۟ لَنَا عَٰبِدِينَ', NULL, 17, 131, 4, 328, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 74, 'وَلُوطًا ءَاتَيْنَٰهُ حُكْمًۭا وَعِلْمًۭا وَنَجَّيْنَٰهُ مِنَ ٱلْقَرْيَةِ ٱلَّتِى كَانَت تَّعْمَلُ ٱلْخَبَٰٓئِثَ ۗ إِنَّهُمْ كَانُوا۟ قَوْمَ سَوْءٍۢ فَٰسِقِينَ', NULL, 17, 131, 4, 328, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 75, 'وَأَدْخَلْنَٰهُ فِى رَحْمَتِنَآ ۖ إِنَّهُۥ مِنَ ٱلصَّٰلِحِينَ', NULL, 17, 131, 4, 328, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 76, 'وَنُوحًا إِذْ نَادَىٰ مِن قَبْلُ فَٱسْتَجَبْنَا لَهُۥ فَنَجَّيْنَٰهُ وَأَهْلَهُۥ مِنَ ٱلْكَرْبِ ٱلْعَظِيمِ', NULL, 17, 131, 4, 328, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 77, 'وَنَصَرْنَٰهُ مِنَ ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَآ ۚ إِنَّهُمْ كَانُوا۟ قَوْمَ سَوْءٍۢ فَأَغْرَقْنَٰهُمْ أَجْمَعِينَ', NULL, 17, 131, 4, 328, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 78, 'وَدَاوُۥدَ وَسُلَيْمَٰنَ إِذْ يَحْكُمَانِ فِى ٱلْحَرْثِ إِذْ نَفَشَتْ فِيهِ غَنَمُ ٱلْقَوْمِ وَكُنَّا لِحُكْمِهِمْ شَٰهِدِينَ', NULL, 17, 131, 4, 328, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 79, 'فَفَهَّمْنَٰهَا سُلَيْمَٰنَ ۚ وَكُلًّا ءَاتَيْنَا حُكْمًۭا وَعِلْمًۭا ۚ وَسَخَّرْنَا مَعَ دَاوُۥدَ ٱلْجِبَالَ يُسَبِّحْنَ وَٱلطَّيْرَ ۚ وَكُنَّا فَٰعِلِينَ', NULL, 17, 131, 4, 328, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 80, 'وَعَلَّمْنَٰهُ صَنْعَةَ لَبُوسٍۢ لَّكُمْ لِتُحْصِنَكُم مِّنۢ بَأْسِكُمْ ۖ فَهَلْ أَنتُمْ شَٰكِرُونَ', NULL, 17, 131, 4, 328, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 81, 'وَلِسُلَيْمَٰنَ ٱلرِّيحَ عَاصِفَةًۭ تَجْرِى بِأَمْرِهِۦٓ إِلَى ٱلْأَرْضِ ٱلَّتِى بَٰرَكْنَا فِيهَا ۚ وَكُنَّا بِكُلِّ شَىْءٍ عَٰلِمِينَ', NULL, 17, 131, 4, 328, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 82, 'وَمِنَ ٱلشَّيَٰطِينِ مَن يَغُوصُونَ لَهُۥ وَيَعْمَلُونَ عَمَلًۭا دُونَ ذَٰلِكَ ۖ وَكُنَّا لَهُمْ حَٰفِظِينَ', NULL, 17, 131, 4, 329, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 83, '۞ وَأَيُّوبَ إِذْ نَادَىٰ رَبَّهُۥٓ أَنِّى مَسَّنِىَ ٱلضُّرُّ وَأَنتَ أَرْحَمُ ٱلرَّٰحِمِينَ', NULL, 17, 132, 4, 329, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 84, 'فَٱسْتَجَبْنَا لَهُۥ فَكَشَفْنَا مَا بِهِۦ مِن ضُرٍّۢ ۖ وَءَاتَيْنَٰهُ أَهْلَهُۥ وَمِثْلَهُم مَّعَهُمْ رَحْمَةًۭ مِّنْ عِندِنَا وَذِكْرَىٰ لِلْعَٰبِدِينَ', NULL, 17, 132, 4, 329, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 85, 'وَإِسْمَٰعِيلَ وَإِدْرِيسَ وَذَا ٱلْكِفْلِ ۖ كُلٌّۭ مِّنَ ٱلصَّٰبِرِينَ', NULL, 17, 132, 4, 329, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 86, 'وَأَدْخَلْنَٰهُمْ فِى رَحْمَتِنَآ ۖ إِنَّهُم مِّنَ ٱلصَّٰلِحِينَ', NULL, 17, 132, 4, 329, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 87, 'وَذَا ٱلنُّونِ إِذ ذَّهَبَ مُغَٰضِبًۭا فَظَنَّ أَن لَّن نَّقْدِرَ عَلَيْهِ فَنَادَىٰ فِى ٱلظُّلُمَٰتِ أَن لَّآ إِلَٰهَ إِلَّآ أَنتَ سُبْحَٰنَكَ إِنِّى كُنتُ مِنَ ٱلظَّٰلِمِينَ', NULL, 17, 132, 4, 329, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 88, 'فَٱسْتَجَبْنَا لَهُۥ وَنَجَّيْنَٰهُ مِنَ ٱلْغَمِّ ۚ وَكَذَٰلِكَ نُۨجِى ٱلْمُؤْمِنِينَ', NULL, 17, 132, 4, 329, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 89, 'وَزَكَرِيَّآ إِذْ نَادَىٰ رَبَّهُۥ رَبِّ لَا تَذَرْنِى فَرْدًۭا وَأَنتَ خَيْرُ ٱلْوَٰرِثِينَ', NULL, 17, 132, 4, 329, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 90, 'فَٱسْتَجَبْنَا لَهُۥ وَوَهَبْنَا لَهُۥ يَحْيَىٰ وَأَصْلَحْنَا لَهُۥ زَوْجَهُۥٓ ۚ إِنَّهُمْ كَانُوا۟ يُسَٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَيَدْعُونَنَا رَغَبًۭا وَرَهَبًۭا ۖ وَكَانُوا۟ لَنَا خَٰشِعِينَ', NULL, 17, 132, 4, 329, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 91, 'وَٱلَّتِىٓ أَحْصَنَتْ فَرْجَهَا فَنَفَخْنَا فِيهَا مِن رُّوحِنَا وَجَعَلْنَٰهَا وَٱبْنَهَآ ءَايَةًۭ لِّلْعَٰلَمِينَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 92, 'إِنَّ هَٰذِهِۦٓ أُمَّتُكُمْ أُمَّةًۭ وَٰحِدَةًۭ وَأَنَا۠ رَبُّكُمْ فَٱعْبُدُونِ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 93, 'وَتَقَطَّعُوٓا۟ أَمْرَهُم بَيْنَهُمْ ۖ كُلٌّ إِلَيْنَا رَٰجِعُونَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 94, 'فَمَن يَعْمَلْ مِنَ ٱلصَّٰلِحَٰتِ وَهُوَ مُؤْمِنٌۭ فَلَا كُفْرَانَ لِسَعْيِهِۦ وَإِنَّا لَهُۥ كَٰتِبُونَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 95, 'وَحَرَٰمٌ عَلَىٰ قَرْيَةٍ أَهْلَكْنَٰهَآ أَنَّهُمْ لَا يَرْجِعُونَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 96, 'حَتَّىٰٓ إِذَا فُتِحَتْ يَأْجُوجُ وَمَأْجُوجُ وَهُم مِّن كُلِّ حَدَبٍۢ يَنسِلُونَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 97, 'وَٱقْتَرَبَ ٱلْوَعْدُ ٱلْحَقُّ فَإِذَا هِىَ شَٰخِصَةٌ أَبْصَٰرُ ٱلَّذِينَ كَفَرُوا۟ يَٰوَيْلَنَا قَدْ كُنَّا فِى غَفْلَةٍۢ مِّنْ هَٰذَا بَلْ كُنَّا ظَٰلِمِينَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 98, 'إِنَّكُمْ وَمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ حَصَبُ جَهَنَّمَ أَنتُمْ لَهَا وَٰرِدُونَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 99, 'لَوْ كَانَ هَٰٓؤُلَآءِ ءَالِهَةًۭ مَّا وَرَدُوهَا ۖ وَكُلٌّۭ فِيهَا خَٰلِدُونَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 100, 'لَهُمْ فِيهَا زَفِيرٌۭ وَهُمْ فِيهَا لَا يَسْمَعُونَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 101, 'إِنَّ ٱلَّذِينَ سَبَقَتْ لَهُم مِّنَّا ٱلْحُسْنَىٰٓ أُو۟لَٰٓئِكَ عَنْهَا مُبْعَدُونَ', NULL, 17, 132, 4, 330, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 102, 'لَا يَسْمَعُونَ حَسِيسَهَا ۖ وَهُمْ فِى مَا ٱشْتَهَتْ أَنفُسُهُمْ خَٰلِدُونَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 103, 'لَا يَحْزُنُهُمُ ٱلْفَزَعُ ٱلْأَكْبَرُ وَتَتَلَقَّىٰهُمُ ٱلْمَلَٰٓئِكَةُ هَٰذَا يَوْمُكُمُ ٱلَّذِى كُنتُمْ تُوعَدُونَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 104, 'يَوْمَ نَطْوِى ٱلسَّمَآءَ كَطَىِّ ٱلسِّجِلِّ لِلْكُتُبِ ۚ كَمَا بَدَأْنَآ أَوَّلَ خَلْقٍۢ نُّعِيدُهُۥ ۚ وَعْدًا عَلَيْنَآ ۚ إِنَّا كُنَّا فَٰعِلِينَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 105, 'وَلَقَدْ كَتَبْنَا فِى ٱلزَّبُورِ مِنۢ بَعْدِ ٱلذِّكْرِ أَنَّ ٱلْأَرْضَ يَرِثُهَا عِبَادِىَ ٱلصَّٰلِحُونَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 106, 'إِنَّ فِى هَٰذَا لَبَلَٰغًۭا لِّقَوْمٍ عَٰبِدِينَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 107, 'وَمَآ أَرْسَلْنَٰكَ إِلَّا رَحْمَةًۭ لِّلْعَٰلَمِينَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 108, 'قُلْ إِنَّمَا يُوحَىٰٓ إِلَىَّ أَنَّمَآ إِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ ۖ فَهَلْ أَنتُم مُّسْلِمُونَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 109, 'فَإِن تَوَلَّوْا۟ فَقُلْ ءَاذَنتُكُمْ عَلَىٰ سَوَآءٍۢ ۖ وَإِنْ أَدْرِىٓ أَقَرِيبٌ أَم بَعِيدٌۭ مَّا تُوعَدُونَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 110, 'إِنَّهُۥ يَعْلَمُ ٱلْجَهْرَ مِنَ ٱلْقَوْلِ وَيَعْلَمُ مَا تَكْتُمُونَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 111, 'وَإِنْ أَدْرِى لَعَلَّهُۥ فِتْنَةٌۭ لَّكُمْ وَمَتَٰعٌ إِلَىٰ حِينٍۢ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 21), 112, 'قَٰلَ رَبِّ ٱحْكُم بِٱلْحَقِّ ۗ وَرَبُّنَا ٱلرَّحْمَٰنُ ٱلْمُسْتَعَانُ عَلَىٰ مَا تَصِفُونَ', NULL, 17, 132, 4, 331, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ يَٰٓأَيُّهَا ٱلنَّاسُ ٱتَّقُوا۟ رَبَّكُمْ ۚ إِنَّ زَلْزَلَةَ ٱلسَّاعَةِ شَىْءٌ عَظِيمٌۭ', NULL, 17, 133, 4, 332, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 2, 'يَوْمَ تَرَوْنَهَا تَذْهَلُ كُلُّ مُرْضِعَةٍ عَمَّآ أَرْضَعَتْ وَتَضَعُ كُلُّ ذَاتِ حَمْلٍ حَمْلَهَا وَتَرَى ٱلنَّاسَ سُكَٰرَىٰ وَمَا هُم بِسُكَٰرَىٰ وَلَٰكِنَّ عَذَابَ ٱللَّهِ شَدِيدٌۭ', NULL, 17, 133, 4, 332, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 3, 'وَمِنَ ٱلنَّاسِ مَن يُجَٰدِلُ فِى ٱللَّهِ بِغَيْرِ عِلْمٍۢ وَيَتَّبِعُ كُلَّ شَيْطَٰنٍۢ مَّرِيدٍۢ', NULL, 17, 133, 4, 332, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 4, 'كُتِبَ عَلَيْهِ أَنَّهُۥ مَن تَوَلَّاهُ فَأَنَّهُۥ يُضِلُّهُۥ وَيَهْدِيهِ إِلَىٰ عَذَابِ ٱلسَّعِيرِ', NULL, 17, 133, 4, 332, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 5, 'يَٰٓأَيُّهَا ٱلنَّاسُ إِن كُنتُمْ فِى رَيْبٍۢ مِّنَ ٱلْبَعْثِ فَإِنَّا خَلَقْنَٰكُم مِّن تُرَابٍۢ ثُمَّ مِن نُّطْفَةٍۢ ثُمَّ مِنْ عَلَقَةٍۢ ثُمَّ مِن مُّضْغَةٍۢ مُّخَلَّقَةٍۢ وَغَيْرِ مُخَلَّقَةٍۢ لِّنُبَيِّنَ لَكُمْ ۚ وَنُقِرُّ فِى ٱلْأَرْحَامِ مَا نَشَآءُ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى ثُمَّ نُخْرِجُكُمْ طِفْلًۭا ثُمَّ لِتَبْلُغُوٓا۟ أَشُدَّكُمْ ۖ وَمِنكُم مَّن يُتَوَفَّىٰ وَمِنكُم مَّن يُرَدُّ إِلَىٰٓ أَرْذَلِ ٱلْعُمُرِ لِكَيْلَا يَعْلَمَ مِنۢ بَعْدِ عِلْمٍۢ شَيْـًۭٔا ۚ وَتَرَى ٱلْأَرْضَ هَامِدَةًۭ فَإِذَآ أَنزَلْنَا عَلَيْهَا ٱلْمَآءَ ٱهْتَزَّتْ وَرَبَتْ وَأَنۢبَتَتْ مِن كُلِّ زَوْجٍۭ بَهِيجٍۢ', NULL, 17, 133, 4, 332, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 6, 'ذَٰلِكَ بِأَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ وَأَنَّهُۥ يُحْىِ ٱلْمَوْتَىٰ وَأَنَّهُۥ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 7, 'وَأَنَّ ٱلسَّاعَةَ ءَاتِيَةٌۭ لَّا رَيْبَ فِيهَا وَأَنَّ ٱللَّهَ يَبْعَثُ مَن فِى ٱلْقُبُورِ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 8, 'وَمِنَ ٱلنَّاسِ مَن يُجَٰدِلُ فِى ٱللَّهِ بِغَيْرِ عِلْمٍۢ وَلَا هُدًۭى وَلَا كِتَٰبٍۢ مُّنِيرٍۢ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 9, 'ثَانِىَ عِطْفِهِۦ لِيُضِلَّ عَن سَبِيلِ ٱللَّهِ ۖ لَهُۥ فِى ٱلدُّنْيَا خِزْىٌۭ ۖ وَنُذِيقُهُۥ يَوْمَ ٱلْقِيَٰمَةِ عَذَابَ ٱلْحَرِيقِ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 10, 'ذَٰلِكَ بِمَا قَدَّمَتْ يَدَاكَ وَأَنَّ ٱللَّهَ لَيْسَ بِظَلَّٰمٍۢ لِّلْعَبِيدِ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 11, 'وَمِنَ ٱلنَّاسِ مَن يَعْبُدُ ٱللَّهَ عَلَىٰ حَرْفٍۢ ۖ فَإِنْ أَصَابَهُۥ خَيْرٌ ٱطْمَأَنَّ بِهِۦ ۖ وَإِنْ أَصَابَتْهُ فِتْنَةٌ ٱنقَلَبَ عَلَىٰ وَجْهِهِۦ خَسِرَ ٱلدُّنْيَا وَٱلْءَاخِرَةَ ۚ ذَٰلِكَ هُوَ ٱلْخُسْرَانُ ٱلْمُبِينُ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 12, 'يَدْعُوا۟ مِن دُونِ ٱللَّهِ مَا لَا يَضُرُّهُۥ وَمَا لَا يَنفَعُهُۥ ۚ ذَٰلِكَ هُوَ ٱلضَّلَٰلُ ٱلْبَعِيدُ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 13, 'يَدْعُوا۟ لَمَن ضَرُّهُۥٓ أَقْرَبُ مِن نَّفْعِهِۦ ۚ لَبِئْسَ ٱلْمَوْلَىٰ وَلَبِئْسَ ٱلْعَشِيرُ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 14, 'إِنَّ ٱللَّهَ يُدْخِلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ۚ إِنَّ ٱللَّهَ يَفْعَلُ مَا يُرِيدُ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 15, 'مَن كَانَ يَظُنُّ أَن لَّن يَنصُرَهُ ٱللَّهُ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ فَلْيَمْدُدْ بِسَبَبٍ إِلَى ٱلسَّمَآءِ ثُمَّ لْيَقْطَعْ فَلْيَنظُرْ هَلْ يُذْهِبَنَّ كَيْدُهُۥ مَا يَغِيظُ', NULL, 17, 133, 4, 333, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 16, 'وَكَذَٰلِكَ أَنزَلْنَٰهُ ءَايَٰتٍۭ بَيِّنَٰتٍۢ وَأَنَّ ٱللَّهَ يَهْدِى مَن يُرِيدُ', NULL, 17, 133, 4, 334, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 17, 'إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَادُوا۟ وَٱلصَّٰبِـِٔينَ وَٱلنَّصَٰرَىٰ وَٱلْمَجُوسَ وَٱلَّذِينَ أَشْرَكُوٓا۟ إِنَّ ٱللَّهَ يَفْصِلُ بَيْنَهُمْ يَوْمَ ٱلْقِيَٰمَةِ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ شَهِيدٌ', NULL, 17, 133, 4, 334, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 18, 'أَلَمْ تَرَ أَنَّ ٱللَّهَ يَسْجُدُ لَهُۥ مَن فِى ٱلسَّمَٰوَٰتِ وَمَن فِى ٱلْأَرْضِ وَٱلشَّمْسُ وَٱلْقَمَرُ وَٱلنُّجُومُ وَٱلْجِبَالُ وَٱلشَّجَرُ وَٱلدَّوَآبُّ وَكَثِيرٌۭ مِّنَ ٱلنَّاسِ ۖ وَكَثِيرٌ حَقَّ عَلَيْهِ ٱلْعَذَابُ ۗ وَمَن يُهِنِ ٱللَّهُ فَمَا لَهُۥ مِن مُّكْرِمٍ ۚ إِنَّ ٱللَّهَ يَفْعَلُ مَا يَشَآءُ ۩', NULL, 17, 133, 4, 334, true, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 19, '۞ هَٰذَانِ خَصْمَانِ ٱخْتَصَمُوا۟ فِى رَبِّهِمْ ۖ فَٱلَّذِينَ كَفَرُوا۟ قُطِّعَتْ لَهُمْ ثِيَابٌۭ مِّن نَّارٍۢ يُصَبُّ مِن فَوْقِ رُءُوسِهِمُ ٱلْحَمِيمُ', NULL, 17, 134, 4, 334, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 20, 'يُصْهَرُ بِهِۦ مَا فِى بُطُونِهِمْ وَٱلْجُلُودُ', NULL, 17, 134, 4, 334, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 21, 'وَلَهُم مَّقَٰمِعُ مِنْ حَدِيدٍۢ', NULL, 17, 134, 4, 334, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 22, 'كُلَّمَآ أَرَادُوٓا۟ أَن يَخْرُجُوا۟ مِنْهَا مِنْ غَمٍّ أُعِيدُوا۟ فِيهَا وَذُوقُوا۟ عَذَابَ ٱلْحَرِيقِ', NULL, 17, 134, 4, 334, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 23, 'إِنَّ ٱللَّهَ يُدْخِلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ يُحَلَّوْنَ فِيهَا مِنْ أَسَاوِرَ مِن ذَهَبٍۢ وَلُؤْلُؤًۭا ۖ وَلِبَاسُهُمْ فِيهَا حَرِيرٌۭ', NULL, 17, 134, 4, 334, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 24, 'وَهُدُوٓا۟ إِلَى ٱلطَّيِّبِ مِنَ ٱلْقَوْلِ وَهُدُوٓا۟ إِلَىٰ صِرَٰطِ ٱلْحَمِيدِ', NULL, 17, 134, 4, 335, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 25, 'إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَيَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَٱلْمَسْجِدِ ٱلْحَرَامِ ٱلَّذِى جَعَلْنَٰهُ لِلنَّاسِ سَوَآءً ٱلْعَٰكِفُ فِيهِ وَٱلْبَادِ ۚ وَمَن يُرِدْ فِيهِ بِإِلْحَادٍۭ بِظُلْمٍۢ نُّذِقْهُ مِنْ عَذَابٍ أَلِيمٍۢ', NULL, 17, 134, 4, 335, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 26, 'وَإِذْ بَوَّأْنَا لِإِبْرَٰهِيمَ مَكَانَ ٱلْبَيْتِ أَن لَّا تُشْرِكْ بِى شَيْـًۭٔا وَطَهِّرْ بَيْتِىَ لِلطَّآئِفِينَ وَٱلْقَآئِمِينَ وَٱلرُّكَّعِ ٱلسُّجُودِ', NULL, 17, 134, 4, 335, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 27, 'وَأَذِّن فِى ٱلنَّاسِ بِٱلْحَجِّ يَأْتُوكَ رِجَالًۭا وَعَلَىٰ كُلِّ ضَامِرٍۢ يَأْتِينَ مِن كُلِّ فَجٍّ عَمِيقٍۢ', NULL, 17, 134, 4, 335, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 28, 'لِّيَشْهَدُوا۟ مَنَٰفِعَ لَهُمْ وَيَذْكُرُوا۟ ٱسْمَ ٱللَّهِ فِىٓ أَيَّامٍۢ مَّعْلُومَٰتٍ عَلَىٰ مَا رَزَقَهُم مِّنۢ بَهِيمَةِ ٱلْأَنْعَٰمِ ۖ فَكُلُوا۟ مِنْهَا وَأَطْعِمُوا۟ ٱلْبَآئِسَ ٱلْفَقِيرَ', NULL, 17, 134, 4, 335, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 29, 'ثُمَّ لْيَقْضُوا۟ تَفَثَهُمْ وَلْيُوفُوا۟ نُذُورَهُمْ وَلْيَطَّوَّفُوا۟ بِٱلْبَيْتِ ٱلْعَتِيقِ', NULL, 17, 134, 4, 335, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 30, 'ذَٰلِكَ وَمَن يُعَظِّمْ حُرُمَٰتِ ٱللَّهِ فَهُوَ خَيْرٌۭ لَّهُۥ عِندَ رَبِّهِۦ ۗ وَأُحِلَّتْ لَكُمُ ٱلْأَنْعَٰمُ إِلَّا مَا يُتْلَىٰ عَلَيْكُمْ ۖ فَٱجْتَنِبُوا۟ ٱلرِّجْسَ مِنَ ٱلْأَوْثَٰنِ وَٱجْتَنِبُوا۟ قَوْلَ ٱلزُّورِ', NULL, 17, 134, 4, 335, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 31, 'حُنَفَآءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِۦ ۚ وَمَن يُشْرِكْ بِٱللَّهِ فَكَأَنَّمَا خَرَّ مِنَ ٱلسَّمَآءِ فَتَخْطَفُهُ ٱلطَّيْرُ أَوْ تَهْوِى بِهِ ٱلرِّيحُ فِى مَكَانٍۢ سَحِيقٍۢ', NULL, 17, 134, 4, 336, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 32, 'ذَٰلِكَ وَمَن يُعَظِّمْ شَعَٰٓئِرَ ٱللَّهِ فَإِنَّهَا مِن تَقْوَى ٱلْقُلُوبِ', NULL, 17, 134, 4, 336, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 33, 'لَكُمْ فِيهَا مَنَٰفِعُ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى ثُمَّ مَحِلُّهَآ إِلَى ٱلْبَيْتِ ٱلْعَتِيقِ', NULL, 17, 134, 4, 336, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 34, 'وَلِكُلِّ أُمَّةٍۢ جَعَلْنَا مَنسَكًۭا لِّيَذْكُرُوا۟ ٱسْمَ ٱللَّهِ عَلَىٰ مَا رَزَقَهُم مِّنۢ بَهِيمَةِ ٱلْأَنْعَٰمِ ۗ فَإِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ فَلَهُۥٓ أَسْلِمُوا۟ ۗ وَبَشِّرِ ٱلْمُخْبِتِينَ', NULL, 17, 134, 4, 336, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 35, 'ٱلَّذِينَ إِذَا ذُكِرَ ٱللَّهُ وَجِلَتْ قُلُوبُهُمْ وَٱلصَّٰبِرِينَ عَلَىٰ مَآ أَصَابَهُمْ وَٱلْمُقِيمِى ٱلصَّلَوٰةِ وَمِمَّا رَزَقْنَٰهُمْ يُنفِقُونَ', NULL, 17, 134, 4, 336, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 36, 'وَٱلْبُدْنَ جَعَلْنَٰهَا لَكُم مِّن شَعَٰٓئِرِ ٱللَّهِ لَكُمْ فِيهَا خَيْرٌۭ ۖ فَٱذْكُرُوا۟ ٱسْمَ ٱللَّهِ عَلَيْهَا صَوَآفَّ ۖ فَإِذَا وَجَبَتْ جُنُوبُهَا فَكُلُوا۟ مِنْهَا وَأَطْعِمُوا۟ ٱلْقَانِعَ وَٱلْمُعْتَرَّ ۚ كَذَٰلِكَ سَخَّرْنَٰهَا لَكُمْ لَعَلَّكُمْ تَشْكُرُونَ', NULL, 17, 134, 4, 336, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 37, 'لَن يَنَالَ ٱللَّهَ لُحُومُهَا وَلَا دِمَآؤُهَا وَلَٰكِن يَنَالُهُ ٱلتَّقْوَىٰ مِنكُمْ ۚ كَذَٰلِكَ سَخَّرَهَا لَكُمْ لِتُكَبِّرُوا۟ ٱللَّهَ عَلَىٰ مَا هَدَىٰكُمْ ۗ وَبَشِّرِ ٱلْمُحْسِنِينَ', NULL, 17, 134, 4, 336, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 38, '۞ إِنَّ ٱللَّهَ يُدَٰفِعُ عَنِ ٱلَّذِينَ ءَامَنُوٓا۟ ۗ إِنَّ ٱللَّهَ لَا يُحِبُّ كُلَّ خَوَّانٍۢ كَفُورٍ', NULL, 17, 135, 4, 336, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 39, 'أُذِنَ لِلَّذِينَ يُقَٰتَلُونَ بِأَنَّهُمْ ظُلِمُوا۟ ۚ وَإِنَّ ٱللَّهَ عَلَىٰ نَصْرِهِمْ لَقَدِيرٌ', NULL, 17, 135, 4, 337, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 40, 'ٱلَّذِينَ أُخْرِجُوا۟ مِن دِيَٰرِهِم بِغَيْرِ حَقٍّ إِلَّآ أَن يَقُولُوا۟ رَبُّنَا ٱللَّهُ ۗ وَلَوْلَا دَفْعُ ٱللَّهِ ٱلنَّاسَ بَعْضَهُم بِبَعْضٍۢ لَّهُدِّمَتْ صَوَٰمِعُ وَبِيَعٌۭ وَصَلَوَٰتٌۭ وَمَسَٰجِدُ يُذْكَرُ فِيهَا ٱسْمُ ٱللَّهِ كَثِيرًۭا ۗ وَلَيَنصُرَنَّ ٱللَّهُ مَن يَنصُرُهُۥٓ ۗ إِنَّ ٱللَّهَ لَقَوِىٌّ عَزِيزٌ', NULL, 17, 135, 4, 337, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 41, 'ٱلَّذِينَ إِن مَّكَّنَّٰهُمْ فِى ٱلْأَرْضِ أَقَامُوا۟ ٱلصَّلَوٰةَ وَءَاتَوُا۟ ٱلزَّكَوٰةَ وَأَمَرُوا۟ بِٱلْمَعْرُوفِ وَنَهَوْا۟ عَنِ ٱلْمُنكَرِ ۗ وَلِلَّهِ عَٰقِبَةُ ٱلْأُمُورِ', NULL, 17, 135, 4, 337, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 42, 'وَإِن يُكَذِّبُوكَ فَقَدْ كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍۢ وَعَادٌۭ وَثَمُودُ', NULL, 17, 135, 4, 337, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 43, 'وَقَوْمُ إِبْرَٰهِيمَ وَقَوْمُ لُوطٍۢ', NULL, 17, 135, 4, 337, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 44, 'وَأَصْحَٰبُ مَدْيَنَ ۖ وَكُذِّبَ مُوسَىٰ فَأَمْلَيْتُ لِلْكَٰفِرِينَ ثُمَّ أَخَذْتُهُمْ ۖ فَكَيْفَ كَانَ نَكِيرِ', NULL, 17, 135, 4, 337, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 45, 'فَكَأَيِّن مِّن قَرْيَةٍ أَهْلَكْنَٰهَا وَهِىَ ظَالِمَةٌۭ فَهِىَ خَاوِيَةٌ عَلَىٰ عُرُوشِهَا وَبِئْرٍۢ مُّعَطَّلَةٍۢ وَقَصْرٍۢ مَّشِيدٍ', NULL, 17, 135, 4, 337, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 46, 'أَفَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَتَكُونَ لَهُمْ قُلُوبٌۭ يَعْقِلُونَ بِهَآ أَوْ ءَاذَانٌۭ يَسْمَعُونَ بِهَا ۖ فَإِنَّهَا لَا تَعْمَى ٱلْأَبْصَٰرُ وَلَٰكِن تَعْمَى ٱلْقُلُوبُ ٱلَّتِى فِى ٱلصُّدُورِ', NULL, 17, 135, 4, 337, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 47, 'وَيَسْتَعْجِلُونَكَ بِٱلْعَذَابِ وَلَن يُخْلِفَ ٱللَّهُ وَعْدَهُۥ ۚ وَإِنَّ يَوْمًا عِندَ رَبِّكَ كَأَلْفِ سَنَةٍۢ مِّمَّا تَعُدُّونَ', NULL, 17, 135, 4, 338, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 48, 'وَكَأَيِّن مِّن قَرْيَةٍ أَمْلَيْتُ لَهَا وَهِىَ ظَالِمَةٌۭ ثُمَّ أَخَذْتُهَا وَإِلَىَّ ٱلْمَصِيرُ', NULL, 17, 135, 4, 338, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 49, 'قُلْ يَٰٓأَيُّهَا ٱلنَّاسُ إِنَّمَآ أَنَا۠ لَكُمْ نَذِيرٌۭ مُّبِينٌۭ', NULL, 17, 135, 4, 338, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 50, 'فَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَهُم مَّغْفِرَةٌۭ وَرِزْقٌۭ كَرِيمٌۭ', NULL, 17, 135, 4, 338, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 51, 'وَٱلَّذِينَ سَعَوْا۟ فِىٓ ءَايَٰتِنَا مُعَٰجِزِينَ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَحِيمِ', NULL, 17, 135, 4, 338, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 52, 'وَمَآ أَرْسَلْنَا مِن قَبْلِكَ مِن رَّسُولٍۢ وَلَا نَبِىٍّ إِلَّآ إِذَا تَمَنَّىٰٓ أَلْقَى ٱلشَّيْطَٰنُ فِىٓ أُمْنِيَّتِهِۦ فَيَنسَخُ ٱللَّهُ مَا يُلْقِى ٱلشَّيْطَٰنُ ثُمَّ يُحْكِمُ ٱللَّهُ ءَايَٰتِهِۦ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌۭ', NULL, 17, 135, 4, 338, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 53, 'لِّيَجْعَلَ مَا يُلْقِى ٱلشَّيْطَٰنُ فِتْنَةًۭ لِّلَّذِينَ فِى قُلُوبِهِم مَّرَضٌۭ وَٱلْقَاسِيَةِ قُلُوبُهُمْ ۗ وَإِنَّ ٱلظَّٰلِمِينَ لَفِى شِقَاقٍۭ بَعِيدٍۢ', NULL, 17, 135, 4, 338, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 54, 'وَلِيَعْلَمَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ أَنَّهُ ٱلْحَقُّ مِن رَّبِّكَ فَيُؤْمِنُوا۟ بِهِۦ فَتُخْبِتَ لَهُۥ قُلُوبُهُمْ ۗ وَإِنَّ ٱللَّهَ لَهَادِ ٱلَّذِينَ ءَامَنُوٓا۟ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ', NULL, 17, 135, 4, 338, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 55, 'وَلَا يَزَالُ ٱلَّذِينَ كَفَرُوا۟ فِى مِرْيَةٍۢ مِّنْهُ حَتَّىٰ تَأْتِيَهُمُ ٱلسَّاعَةُ بَغْتَةً أَوْ يَأْتِيَهُمْ عَذَابُ يَوْمٍ عَقِيمٍ', NULL, 17, 135, 4, 338, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 56, 'ٱلْمُلْكُ يَوْمَئِذٍۢ لِّلَّهِ يَحْكُمُ بَيْنَهُمْ ۚ فَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فِى جَنَّٰتِ ٱلنَّعِيمِ', NULL, 17, 135, 4, 339, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 57, 'وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَا فَأُو۟لَٰٓئِكَ لَهُمْ عَذَابٌۭ مُّهِينٌۭ', NULL, 17, 135, 4, 339, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 58, 'وَٱلَّذِينَ هَاجَرُوا۟ فِى سَبِيلِ ٱللَّهِ ثُمَّ قُتِلُوٓا۟ أَوْ مَاتُوا۟ لَيَرْزُقَنَّهُمُ ٱللَّهُ رِزْقًا حَسَنًۭا ۚ وَإِنَّ ٱللَّهَ لَهُوَ خَيْرُ ٱلرَّٰزِقِينَ', NULL, 17, 135, 4, 339, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 59, 'لَيُدْخِلَنَّهُم مُّدْخَلًۭا يَرْضَوْنَهُۥ ۗ وَإِنَّ ٱللَّهَ لَعَلِيمٌ حَلِيمٌۭ', NULL, 17, 135, 4, 339, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 60, '۞ ذَٰلِكَ وَمَنْ عَاقَبَ بِمِثْلِ مَا عُوقِبَ بِهِۦ ثُمَّ بُغِىَ عَلَيْهِ لَيَنصُرَنَّهُ ٱللَّهُ ۗ إِنَّ ٱللَّهَ لَعَفُوٌّ غَفُورٌۭ', NULL, 17, 136, 4, 339, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 61, 'ذَٰلِكَ بِأَنَّ ٱللَّهَ يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ وَأَنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌۭ', NULL, 17, 136, 4, 339, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 62, 'ذَٰلِكَ بِأَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ وَأَنَّ مَا يَدْعُونَ مِن دُونِهِۦ هُوَ ٱلْبَٰطِلُ وَأَنَّ ٱللَّهَ هُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ', NULL, 17, 136, 4, 339, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 63, 'أَلَمْ تَرَ أَنَّ ٱللَّهَ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَتُصْبِحُ ٱلْأَرْضُ مُخْضَرَّةً ۗ إِنَّ ٱللَّهَ لَطِيفٌ خَبِيرٌۭ', NULL, 17, 136, 4, 339, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 64, 'لَّهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَإِنَّ ٱللَّهَ لَهُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ', NULL, 17, 136, 4, 339, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 65, 'أَلَمْ تَرَ أَنَّ ٱللَّهَ سَخَّرَ لَكُم مَّا فِى ٱلْأَرْضِ وَٱلْفُلْكَ تَجْرِى فِى ٱلْبَحْرِ بِأَمْرِهِۦ وَيُمْسِكُ ٱلسَّمَآءَ أَن تَقَعَ عَلَى ٱلْأَرْضِ إِلَّا بِإِذْنِهِۦٓ ۗ إِنَّ ٱللَّهَ بِٱلنَّاسِ لَرَءُوفٌۭ رَّحِيمٌۭ', NULL, 17, 136, 4, 340, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 66, 'وَهُوَ ٱلَّذِىٓ أَحْيَاكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْ ۗ إِنَّ ٱلْإِنسَٰنَ لَكَفُورٌۭ', NULL, 17, 136, 4, 340, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 67, 'لِّكُلِّ أُمَّةٍۢ جَعَلْنَا مَنسَكًا هُمْ نَاسِكُوهُ ۖ فَلَا يُنَٰزِعُنَّكَ فِى ٱلْأَمْرِ ۚ وَٱدْعُ إِلَىٰ رَبِّكَ ۖ إِنَّكَ لَعَلَىٰ هُدًۭى مُّسْتَقِيمٍۢ', NULL, 17, 136, 4, 340, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 68, 'وَإِن جَٰدَلُوكَ فَقُلِ ٱللَّهُ أَعْلَمُ بِمَا تَعْمَلُونَ', NULL, 17, 136, 4, 340, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 69, 'ٱللَّهُ يَحْكُمُ بَيْنَكُمْ يَوْمَ ٱلْقِيَٰمَةِ فِيمَا كُنتُمْ فِيهِ تَخْتَلِفُونَ', NULL, 17, 136, 4, 340, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 70, 'أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ يَعْلَمُ مَا فِى ٱلسَّمَآءِ وَٱلْأَرْضِ ۗ إِنَّ ذَٰلِكَ فِى كِتَٰبٍ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ', NULL, 17, 136, 4, 340, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 71, 'وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ سُلْطَٰنًۭا وَمَا لَيْسَ لَهُم بِهِۦ عِلْمٌۭ ۗ وَمَا لِلظَّٰلِمِينَ مِن نَّصِيرٍۢ', NULL, 17, 136, 4, 340, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 72, 'وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُنَا بَيِّنَٰتٍۢ تَعْرِفُ فِى وُجُوهِ ٱلَّذِينَ كَفَرُوا۟ ٱلْمُنكَرَ ۖ يَكَادُونَ يَسْطُونَ بِٱلَّذِينَ يَتْلُونَ عَلَيْهِمْ ءَايَٰتِنَا ۗ قُلْ أَفَأُنَبِّئُكُم بِشَرٍّۢ مِّن ذَٰلِكُمُ ۗ ٱلنَّارُ وَعَدَهَا ٱللَّهُ ٱلَّذِينَ كَفَرُوا۟ ۖ وَبِئْسَ ٱلْمَصِيرُ', NULL, 17, 136, 4, 340, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 73, 'يَٰٓأَيُّهَا ٱلنَّاسُ ضُرِبَ مَثَلٌۭ فَٱسْتَمِعُوا۟ لَهُۥٓ ۚ إِنَّ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ لَن يَخْلُقُوا۟ ذُبَابًۭا وَلَوِ ٱجْتَمَعُوا۟ لَهُۥ ۖ وَإِن يَسْلُبْهُمُ ٱلذُّبَابُ شَيْـًۭٔا لَّا يَسْتَنقِذُوهُ مِنْهُ ۚ ضَعُفَ ٱلطَّالِبُ وَٱلْمَطْلُوبُ', NULL, 17, 136, 4, 341, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 74, 'مَا قَدَرُوا۟ ٱللَّهَ حَقَّ قَدْرِهِۦٓ ۗ إِنَّ ٱللَّهَ لَقَوِىٌّ عَزِيزٌ', NULL, 17, 136, 4, 341, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 75, 'ٱللَّهُ يَصْطَفِى مِنَ ٱلْمَلَٰٓئِكَةِ رُسُلًۭا وَمِنَ ٱلنَّاسِ ۚ إِنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌۭ', NULL, 17, 136, 4, 341, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 76, 'يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ ۗ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ', NULL, 17, 136, 4, 341, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 77, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱرْكَعُوا۟ وَٱسْجُدُوا۟ وَٱعْبُدُوا۟ رَبَّكُمْ وَٱفْعَلُوا۟ ٱلْخَيْرَ لَعَلَّكُمْ تُفْلِحُونَ ۩', NULL, 17, 136, 4, 341, true, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 22), 78, 'وَجَٰهِدُوا۟ فِى ٱللَّهِ حَقَّ جِهَادِهِۦ ۚ هُوَ ٱجْتَبَىٰكُمْ وَمَا جَعَلَ عَلَيْكُمْ فِى ٱلدِّينِ مِنْ حَرَجٍۢ ۚ مِّلَّةَ أَبِيكُمْ إِبْرَٰهِيمَ ۚ هُوَ سَمَّىٰكُمُ ٱلْمُسْلِمِينَ مِن قَبْلُ وَفِى هَٰذَا لِيَكُونَ ٱلرَّسُولُ شَهِيدًا عَلَيْكُمْ وَتَكُونُوا۟ شُهَدَآءَ عَلَى ٱلنَّاسِ ۚ فَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَٱعْتَصِمُوا۟ بِٱللَّهِ هُوَ مَوْلَىٰكُمْ ۖ فَنِعْمَ ٱلْمَوْلَىٰ وَنِعْمَ ٱلنَّصِيرُ', NULL, 17, 136, 4, 341, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ قَدْ أَفْلَحَ ٱلْمُؤْمِنُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 2, 'ٱلَّذِينَ هُمْ فِى صَلَاتِهِمْ خَٰشِعُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 3, 'وَٱلَّذِينَ هُمْ عَنِ ٱللَّغْوِ مُعْرِضُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 4, 'وَٱلَّذِينَ هُمْ لِلزَّكَوٰةِ فَٰعِلُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 5, 'وَٱلَّذِينَ هُمْ لِفُرُوجِهِمْ حَٰفِظُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 6, 'إِلَّا عَلَىٰٓ أَزْوَٰجِهِمْ أَوْ مَا مَلَكَتْ أَيْمَٰنُهُمْ فَإِنَّهُمْ غَيْرُ مَلُومِينَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 7, 'فَمَنِ ٱبْتَغَىٰ وَرَآءَ ذَٰلِكَ فَأُو۟لَٰٓئِكَ هُمُ ٱلْعَادُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 8, 'وَٱلَّذِينَ هُمْ لِأَمَٰنَٰتِهِمْ وَعَهْدِهِمْ رَٰعُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 9, 'وَٱلَّذِينَ هُمْ عَلَىٰ صَلَوَٰتِهِمْ يُحَافِظُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 10, 'أُو۟لَٰٓئِكَ هُمُ ٱلْوَٰرِثُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 11, 'ٱلَّذِينَ يَرِثُونَ ٱلْفِرْدَوْسَ هُمْ فِيهَا خَٰلِدُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 12, 'وَلَقَدْ خَلَقْنَا ٱلْإِنسَٰنَ مِن سُلَٰلَةٍۢ مِّن طِينٍۢ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 13, 'ثُمَّ جَعَلْنَٰهُ نُطْفَةًۭ فِى قَرَارٍۢ مَّكِينٍۢ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 14, 'ثُمَّ خَلَقْنَا ٱلنُّطْفَةَ عَلَقَةًۭ فَخَلَقْنَا ٱلْعَلَقَةَ مُضْغَةًۭ فَخَلَقْنَا ٱلْمُضْغَةَ عِظَٰمًۭا فَكَسَوْنَا ٱلْعِظَٰمَ لَحْمًۭا ثُمَّ أَنشَأْنَٰهُ خَلْقًا ءَاخَرَ ۚ فَتَبَارَكَ ٱللَّهُ أَحْسَنُ ٱلْخَٰلِقِينَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 15, 'ثُمَّ إِنَّكُم بَعْدَ ذَٰلِكَ لَمَيِّتُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 16, 'ثُمَّ إِنَّكُمْ يَوْمَ ٱلْقِيَٰمَةِ تُبْعَثُونَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 17, 'وَلَقَدْ خَلَقْنَا فَوْقَكُمْ سَبْعَ طَرَآئِقَ وَمَا كُنَّا عَنِ ٱلْخَلْقِ غَٰفِلِينَ', NULL, 18, 137, 4, 342, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 18, 'وَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءًۢ بِقَدَرٍۢ فَأَسْكَنَّٰهُ فِى ٱلْأَرْضِ ۖ وَإِنَّا عَلَىٰ ذَهَابٍۭ بِهِۦ لَقَٰدِرُونَ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 19, 'فَأَنشَأْنَا لَكُم بِهِۦ جَنَّٰتٍۢ مِّن نَّخِيلٍۢ وَأَعْنَٰبٍۢ لَّكُمْ فِيهَا فَوَٰكِهُ كَثِيرَةٌۭ وَمِنْهَا تَأْكُلُونَ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 20, 'وَشَجَرَةًۭ تَخْرُجُ مِن طُورِ سَيْنَآءَ تَنۢبُتُ بِٱلدُّهْنِ وَصِبْغٍۢ لِّلْءَاكِلِينَ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 21, 'وَإِنَّ لَكُمْ فِى ٱلْأَنْعَٰمِ لَعِبْرَةًۭ ۖ نُّسْقِيكُم مِّمَّا فِى بُطُونِهَا وَلَكُمْ فِيهَا مَنَٰفِعُ كَثِيرَةٌۭ وَمِنْهَا تَأْكُلُونَ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 22, 'وَعَلَيْهَا وَعَلَى ٱلْفُلْكِ تُحْمَلُونَ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 23, 'وَلَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَقَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥٓ ۖ أَفَلَا تَتَّقُونَ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 24, 'فَقَالَ ٱلْمَلَؤُا۟ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦ مَا هَٰذَآ إِلَّا بَشَرٌۭ مِّثْلُكُمْ يُرِيدُ أَن يَتَفَضَّلَ عَلَيْكُمْ وَلَوْ شَآءَ ٱللَّهُ لَأَنزَلَ مَلَٰٓئِكَةًۭ مَّا سَمِعْنَا بِهَٰذَا فِىٓ ءَابَآئِنَا ٱلْأَوَّلِينَ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 25, 'إِنْ هُوَ إِلَّا رَجُلٌۢ بِهِۦ جِنَّةٌۭ فَتَرَبَّصُوا۟ بِهِۦ حَتَّىٰ حِينٍۢ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 26, 'قَالَ رَبِّ ٱنصُرْنِى بِمَا كَذَّبُونِ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 27, 'فَأَوْحَيْنَآ إِلَيْهِ أَنِ ٱصْنَعِ ٱلْفُلْكَ بِأَعْيُنِنَا وَوَحْيِنَا فَإِذَا جَآءَ أَمْرُنَا وَفَارَ ٱلتَّنُّورُ ۙ فَٱسْلُكْ فِيهَا مِن كُلٍّۢ زَوْجَيْنِ ٱثْنَيْنِ وَأَهْلَكَ إِلَّا مَن سَبَقَ عَلَيْهِ ٱلْقَوْلُ مِنْهُمْ ۖ وَلَا تُخَٰطِبْنِى فِى ٱلَّذِينَ ظَلَمُوٓا۟ ۖ إِنَّهُم مُّغْرَقُونَ', NULL, 18, 137, 4, 343, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 28, 'فَإِذَا ٱسْتَوَيْتَ أَنتَ وَمَن مَّعَكَ عَلَى ٱلْفُلْكِ فَقُلِ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى نَجَّىٰنَا مِنَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ', NULL, 18, 137, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 29, 'وَقُل رَّبِّ أَنزِلْنِى مُنزَلًۭا مُّبَارَكًۭا وَأَنتَ خَيْرُ ٱلْمُنزِلِينَ', NULL, 18, 137, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 30, 'إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ وَإِن كُنَّا لَمُبْتَلِينَ', NULL, 18, 137, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 31, 'ثُمَّ أَنشَأْنَا مِنۢ بَعْدِهِمْ قَرْنًا ءَاخَرِينَ', NULL, 18, 137, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 32, 'فَأَرْسَلْنَا فِيهِمْ رَسُولًۭا مِّنْهُمْ أَنِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥٓ ۖ أَفَلَا تَتَّقُونَ', NULL, 18, 137, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 33, 'وَقَالَ ٱلْمَلَأُ مِن قَوْمِهِ ٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِلِقَآءِ ٱلْءَاخِرَةِ وَأَتْرَفْنَٰهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا مَا هَٰذَآ إِلَّا بَشَرٌۭ مِّثْلُكُمْ يَأْكُلُ مِمَّا تَأْكُلُونَ مِنْهُ وَيَشْرَبُ مِمَّا تَشْرَبُونَ', NULL, 18, 137, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 34, 'وَلَئِنْ أَطَعْتُم بَشَرًۭا مِّثْلَكُمْ إِنَّكُمْ إِذًۭا لَّخَٰسِرُونَ', NULL, 18, 137, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 35, 'أَيَعِدُكُمْ أَنَّكُمْ إِذَا مِتُّمْ وَكُنتُمْ تُرَابًۭا وَعِظَٰمًا أَنَّكُم مُّخْرَجُونَ', NULL, 18, 137, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 36, '۞ هَيْهَاتَ هَيْهَاتَ لِمَا تُوعَدُونَ', NULL, 18, 138, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 37, 'إِنْ هِىَ إِلَّا حَيَاتُنَا ٱلدُّنْيَا نَمُوتُ وَنَحْيَا وَمَا نَحْنُ بِمَبْعُوثِينَ', NULL, 18, 138, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 38, 'إِنْ هُوَ إِلَّا رَجُلٌ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًۭا وَمَا نَحْنُ لَهُۥ بِمُؤْمِنِينَ', NULL, 18, 138, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 39, 'قَالَ رَبِّ ٱنصُرْنِى بِمَا كَذَّبُونِ', NULL, 18, 138, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 40, 'قَالَ عَمَّا قَلِيلٍۢ لَّيُصْبِحُنَّ نَٰدِمِينَ', NULL, 18, 138, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 41, 'فَأَخَذَتْهُمُ ٱلصَّيْحَةُ بِٱلْحَقِّ فَجَعَلْنَٰهُمْ غُثَآءًۭ ۚ فَبُعْدًۭا لِّلْقَوْمِ ٱلظَّٰلِمِينَ', NULL, 18, 138, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 42, 'ثُمَّ أَنشَأْنَا مِنۢ بَعْدِهِمْ قُرُونًا ءَاخَرِينَ', NULL, 18, 138, 4, 344, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 43, 'مَا تَسْبِقُ مِنْ أُمَّةٍ أَجَلَهَا وَمَا يَسْتَـْٔخِرُونَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 44, 'ثُمَّ أَرْسَلْنَا رُسُلَنَا تَتْرَا ۖ كُلَّ مَا جَآءَ أُمَّةًۭ رَّسُولُهَا كَذَّبُوهُ ۚ فَأَتْبَعْنَا بَعْضَهُم بَعْضًۭا وَجَعَلْنَٰهُمْ أَحَادِيثَ ۚ فَبُعْدًۭا لِّقَوْمٍۢ لَّا يُؤْمِنُونَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 45, 'ثُمَّ أَرْسَلْنَا مُوسَىٰ وَأَخَاهُ هَٰرُونَ بِـَٔايَٰتِنَا وَسُلْطَٰنٍۢ مُّبِينٍ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 46, 'إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَٱسْتَكْبَرُوا۟ وَكَانُوا۟ قَوْمًا عَالِينَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 47, 'فَقَالُوٓا۟ أَنُؤْمِنُ لِبَشَرَيْنِ مِثْلِنَا وَقَوْمُهُمَا لَنَا عَٰبِدُونَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 48, 'فَكَذَّبُوهُمَا فَكَانُوا۟ مِنَ ٱلْمُهْلَكِينَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 49, 'وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ لَعَلَّهُمْ يَهْتَدُونَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 50, 'وَجَعَلْنَا ٱبْنَ مَرْيَمَ وَأُمَّهُۥٓ ءَايَةًۭ وَءَاوَيْنَٰهُمَآ إِلَىٰ رَبْوَةٍۢ ذَاتِ قَرَارٍۢ وَمَعِينٍۢ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 51, 'يَٰٓأَيُّهَا ٱلرُّسُلُ كُلُوا۟ مِنَ ٱلطَّيِّبَٰتِ وَٱعْمَلُوا۟ صَٰلِحًا ۖ إِنِّى بِمَا تَعْمَلُونَ عَلِيمٌۭ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 52, 'وَإِنَّ هَٰذِهِۦٓ أُمَّتُكُمْ أُمَّةًۭ وَٰحِدَةًۭ وَأَنَا۠ رَبُّكُمْ فَٱتَّقُونِ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 53, 'فَتَقَطَّعُوٓا۟ أَمْرَهُم بَيْنَهُمْ زُبُرًۭا ۖ كُلُّ حِزْبٍۭ بِمَا لَدَيْهِمْ فَرِحُونَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 54, 'فَذَرْهُمْ فِى غَمْرَتِهِمْ حَتَّىٰ حِينٍ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 55, 'أَيَحْسَبُونَ أَنَّمَا نُمِدُّهُم بِهِۦ مِن مَّالٍۢ وَبَنِينَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 56, 'نُسَارِعُ لَهُمْ فِى ٱلْخَيْرَٰتِ ۚ بَل لَّا يَشْعُرُونَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 57, 'إِنَّ ٱلَّذِينَ هُم مِّنْ خَشْيَةِ رَبِّهِم مُّشْفِقُونَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 58, 'وَٱلَّذِينَ هُم بِـَٔايَٰتِ رَبِّهِمْ يُؤْمِنُونَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 59, 'وَٱلَّذِينَ هُم بِرَبِّهِمْ لَا يُشْرِكُونَ', NULL, 18, 138, 4, 345, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 60, 'وَٱلَّذِينَ يُؤْتُونَ مَآ ءَاتَوا۟ وَّقُلُوبُهُمْ وَجِلَةٌ أَنَّهُمْ إِلَىٰ رَبِّهِمْ رَٰجِعُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 61, 'أُو۟لَٰٓئِكَ يُسَٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَهُمْ لَهَا سَٰبِقُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 62, 'وَلَا نُكَلِّفُ نَفْسًا إِلَّا وُسْعَهَا ۖ وَلَدَيْنَا كِتَٰبٌۭ يَنطِقُ بِٱلْحَقِّ ۚ وَهُمْ لَا يُظْلَمُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 63, 'بَلْ قُلُوبُهُمْ فِى غَمْرَةٍۢ مِّنْ هَٰذَا وَلَهُمْ أَعْمَٰلٌۭ مِّن دُونِ ذَٰلِكَ هُمْ لَهَا عَٰمِلُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 64, 'حَتَّىٰٓ إِذَآ أَخَذْنَا مُتْرَفِيهِم بِٱلْعَذَابِ إِذَا هُمْ يَجْـَٔرُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 65, 'لَا تَجْـَٔرُوا۟ ٱلْيَوْمَ ۖ إِنَّكُم مِّنَّا لَا تُنصَرُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 66, 'قَدْ كَانَتْ ءَايَٰتِى تُتْلَىٰ عَلَيْكُمْ فَكُنتُمْ عَلَىٰٓ أَعْقَٰبِكُمْ تَنكِصُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 67, 'مُسْتَكْبِرِينَ بِهِۦ سَٰمِرًۭا تَهْجُرُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 68, 'أَفَلَمْ يَدَّبَّرُوا۟ ٱلْقَوْلَ أَمْ جَآءَهُم مَّا لَمْ يَأْتِ ءَابَآءَهُمُ ٱلْأَوَّلِينَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 69, 'أَمْ لَمْ يَعْرِفُوا۟ رَسُولَهُمْ فَهُمْ لَهُۥ مُنكِرُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 70, 'أَمْ يَقُولُونَ بِهِۦ جِنَّةٌۢ ۚ بَلْ جَآءَهُم بِٱلْحَقِّ وَأَكْثَرُهُمْ لِلْحَقِّ كَٰرِهُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 71, 'وَلَوِ ٱتَّبَعَ ٱلْحَقُّ أَهْوَآءَهُمْ لَفَسَدَتِ ٱلسَّمَٰوَٰتُ وَٱلْأَرْضُ وَمَن فِيهِنَّ ۚ بَلْ أَتَيْنَٰهُم بِذِكْرِهِمْ فَهُمْ عَن ذِكْرِهِم مُّعْرِضُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 72, 'أَمْ تَسْـَٔلُهُمْ خَرْجًۭا فَخَرَاجُ رَبِّكَ خَيْرٌۭ ۖ وَهُوَ خَيْرُ ٱلرَّٰزِقِينَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 73, 'وَإِنَّكَ لَتَدْعُوهُمْ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 74, 'وَإِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ عَنِ ٱلصِّرَٰطِ لَنَٰكِبُونَ', NULL, 18, 138, 4, 346, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 75, '۞ وَلَوْ رَحِمْنَٰهُمْ وَكَشَفْنَا مَا بِهِم مِّن ضُرٍّۢ لَّلَجُّوا۟ فِى طُغْيَٰنِهِمْ يَعْمَهُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 76, 'وَلَقَدْ أَخَذْنَٰهُم بِٱلْعَذَابِ فَمَا ٱسْتَكَانُوا۟ لِرَبِّهِمْ وَمَا يَتَضَرَّعُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 77, 'حَتَّىٰٓ إِذَا فَتَحْنَا عَلَيْهِم بَابًۭا ذَا عَذَابٍۢ شَدِيدٍ إِذَا هُمْ فِيهِ مُبْلِسُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 78, 'وَهُوَ ٱلَّذِىٓ أَنشَأَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَٰرَ وَٱلْأَفْـِٔدَةَ ۚ قَلِيلًۭا مَّا تَشْكُرُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 79, 'وَهُوَ ٱلَّذِى ذَرَأَكُمْ فِى ٱلْأَرْضِ وَإِلَيْهِ تُحْشَرُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 80, 'وَهُوَ ٱلَّذِى يُحْىِۦ وَيُمِيتُ وَلَهُ ٱخْتِلَٰفُ ٱلَّيْلِ وَٱلنَّهَارِ ۚ أَفَلَا تَعْقِلُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 81, 'بَلْ قَالُوا۟ مِثْلَ مَا قَالَ ٱلْأَوَّلُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 82, 'قَالُوٓا۟ أَءِذَا مِتْنَا وَكُنَّا تُرَابًۭا وَعِظَٰمًا أَءِنَّا لَمَبْعُوثُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 83, 'لَقَدْ وُعِدْنَا نَحْنُ وَءَابَآؤُنَا هَٰذَا مِن قَبْلُ إِنْ هَٰذَآ إِلَّآ أَسَٰطِيرُ ٱلْأَوَّلِينَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 84, 'قُل لِّمَنِ ٱلْأَرْضُ وَمَن فِيهَآ إِن كُنتُمْ تَعْلَمُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 85, 'سَيَقُولُونَ لِلَّهِ ۚ قُلْ أَفَلَا تَذَكَّرُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 86, 'قُلْ مَن رَّبُّ ٱلسَّمَٰوَٰتِ ٱلسَّبْعِ وَرَبُّ ٱلْعَرْشِ ٱلْعَظِيمِ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 87, 'سَيَقُولُونَ لِلَّهِ ۚ قُلْ أَفَلَا تَتَّقُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 88, 'قُلْ مَنۢ بِيَدِهِۦ مَلَكُوتُ كُلِّ شَىْءٍۢ وَهُوَ يُجِيرُ وَلَا يُجَارُ عَلَيْهِ إِن كُنتُمْ تَعْلَمُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 89, 'سَيَقُولُونَ لِلَّهِ ۚ قُلْ فَأَنَّىٰ تُسْحَرُونَ', NULL, 18, 139, 4, 347, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 90, 'بَلْ أَتَيْنَٰهُم بِٱلْحَقِّ وَإِنَّهُمْ لَكَٰذِبُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 91, 'مَا ٱتَّخَذَ ٱللَّهُ مِن وَلَدٍۢ وَمَا كَانَ مَعَهُۥ مِنْ إِلَٰهٍ ۚ إِذًۭا لَّذَهَبَ كُلُّ إِلَٰهٍۭ بِمَا خَلَقَ وَلَعَلَا بَعْضُهُمْ عَلَىٰ بَعْضٍۢ ۚ سُبْحَٰنَ ٱللَّهِ عَمَّا يَصِفُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 92, 'عَٰلِمِ ٱلْغَيْبِ وَٱلشَّهَٰدَةِ فَتَعَٰلَىٰ عَمَّا يُشْرِكُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 93, 'قُل رَّبِّ إِمَّا تُرِيَنِّى مَا يُوعَدُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 94, 'رَبِّ فَلَا تَجْعَلْنِى فِى ٱلْقَوْمِ ٱلظَّٰلِمِينَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 95, 'وَإِنَّا عَلَىٰٓ أَن نُّرِيَكَ مَا نَعِدُهُمْ لَقَٰدِرُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 96, 'ٱدْفَعْ بِٱلَّتِى هِىَ أَحْسَنُ ٱلسَّيِّئَةَ ۚ نَحْنُ أَعْلَمُ بِمَا يَصِفُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 97, 'وَقُل رَّبِّ أَعُوذُ بِكَ مِنْ هَمَزَٰتِ ٱلشَّيَٰطِينِ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 98, 'وَأَعُوذُ بِكَ رَبِّ أَن يَحْضُرُونِ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 99, 'حَتَّىٰٓ إِذَا جَآءَ أَحَدَهُمُ ٱلْمَوْتُ قَالَ رَبِّ ٱرْجِعُونِ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 100, 'لَعَلِّىٓ أَعْمَلُ صَٰلِحًۭا فِيمَا تَرَكْتُ ۚ كَلَّآ ۚ إِنَّهَا كَلِمَةٌ هُوَ قَآئِلُهَا ۖ وَمِن وَرَآئِهِم بَرْزَخٌ إِلَىٰ يَوْمِ يُبْعَثُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 101, 'فَإِذَا نُفِخَ فِى ٱلصُّورِ فَلَآ أَنسَابَ بَيْنَهُمْ يَوْمَئِذٍۢ وَلَا يَتَسَآءَلُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 102, 'فَمَن ثَقُلَتْ مَوَٰزِينُهُۥ فَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 103, 'وَمَنْ خَفَّتْ مَوَٰزِينُهُۥ فَأُو۟لَٰٓئِكَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ فِى جَهَنَّمَ خَٰلِدُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 104, 'تَلْفَحُ وُجُوهَهُمُ ٱلنَّارُ وَهُمْ فِيهَا كَٰلِحُونَ', NULL, 18, 139, 4, 348, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 105, 'أَلَمْ تَكُنْ ءَايَٰتِى تُتْلَىٰ عَلَيْكُمْ فَكُنتُم بِهَا تُكَذِّبُونَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 106, 'قَالُوا۟ رَبَّنَا غَلَبَتْ عَلَيْنَا شِقْوَتُنَا وَكُنَّا قَوْمًۭا ضَآلِّينَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 107, 'رَبَّنَآ أَخْرِجْنَا مِنْهَا فَإِنْ عُدْنَا فَإِنَّا ظَٰلِمُونَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 108, 'قَالَ ٱخْسَـُٔوا۟ فِيهَا وَلَا تُكَلِّمُونِ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 109, 'إِنَّهُۥ كَانَ فَرِيقٌۭ مِّنْ عِبَادِى يَقُولُونَ رَبَّنَآ ءَامَنَّا فَٱغْفِرْ لَنَا وَٱرْحَمْنَا وَأَنتَ خَيْرُ ٱلرَّٰحِمِينَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 110, 'فَٱتَّخَذْتُمُوهُمْ سِخْرِيًّا حَتَّىٰٓ أَنسَوْكُمْ ذِكْرِى وَكُنتُم مِّنْهُمْ تَضْحَكُونَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 111, 'إِنِّى جَزَيْتُهُمُ ٱلْيَوْمَ بِمَا صَبَرُوٓا۟ أَنَّهُمْ هُمُ ٱلْفَآئِزُونَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 112, 'قَٰلَ كَمْ لَبِثْتُمْ فِى ٱلْأَرْضِ عَدَدَ سِنِينَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 113, 'قَالُوا۟ لَبِثْنَا يَوْمًا أَوْ بَعْضَ يَوْمٍۢ فَسْـَٔلِ ٱلْعَآدِّينَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 114, 'قَٰلَ إِن لَّبِثْتُمْ إِلَّا قَلِيلًۭا ۖ لَّوْ أَنَّكُمْ كُنتُمْ تَعْلَمُونَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 115, 'أَفَحَسِبْتُمْ أَنَّمَا خَلَقْنَٰكُمْ عَبَثًۭا وَأَنَّكُمْ إِلَيْنَا لَا تُرْجَعُونَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 116, 'فَتَعَٰلَى ٱللَّهُ ٱلْمَلِكُ ٱلْحَقُّ ۖ لَآ إِلَٰهَ إِلَّا هُوَ رَبُّ ٱلْعَرْشِ ٱلْكَرِيمِ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 117, 'وَمَن يَدْعُ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ لَا بُرْهَٰنَ لَهُۥ بِهِۦ فَإِنَّمَا حِسَابُهُۥ عِندَ رَبِّهِۦٓ ۚ إِنَّهُۥ لَا يُفْلِحُ ٱلْكَٰفِرُونَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 23), 118, 'وَقُل رَّبِّ ٱغْفِرْ وَٱرْحَمْ وَأَنتَ خَيْرُ ٱلرَّٰحِمِينَ', NULL, 18, 139, 4, 349, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ سُورَةٌ أَنزَلْنَٰهَا وَفَرَضْنَٰهَا وَأَنزَلْنَا فِيهَآ ءَايَٰتٍۭ بَيِّنَٰتٍۢ لَّعَلَّكُمْ تَذَكَّرُونَ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 2, 'ٱلزَّانِيَةُ وَٱلزَّانِى فَٱجْلِدُوا۟ كُلَّ وَٰحِدٍۢ مِّنْهُمَا مِا۟ئَةَ جَلْدَةٍۢ ۖ وَلَا تَأْخُذْكُم بِهِمَا رَأْفَةٌۭ فِى دِينِ ٱللَّهِ إِن كُنتُمْ تُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۖ وَلْيَشْهَدْ عَذَابَهُمَا طَآئِفَةٌۭ مِّنَ ٱلْمُؤْمِنِينَ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 3, 'ٱلزَّانِى لَا يَنكِحُ إِلَّا زَانِيَةً أَوْ مُشْرِكَةًۭ وَٱلزَّانِيَةُ لَا يَنكِحُهَآ إِلَّا زَانٍ أَوْ مُشْرِكٌۭ ۚ وَحُرِّمَ ذَٰلِكَ عَلَى ٱلْمُؤْمِنِينَ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 4, 'وَٱلَّذِينَ يَرْمُونَ ٱلْمُحْصَنَٰتِ ثُمَّ لَمْ يَأْتُوا۟ بِأَرْبَعَةِ شُهَدَآءَ فَٱجْلِدُوهُمْ ثَمَٰنِينَ جَلْدَةًۭ وَلَا تَقْبَلُوا۟ لَهُمْ شَهَٰدَةً أَبَدًۭا ۚ وَأُو۟لَٰٓئِكَ هُمُ ٱلْفَٰسِقُونَ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 5, 'إِلَّا ٱلَّذِينَ تَابُوا۟ مِنۢ بَعْدِ ذَٰلِكَ وَأَصْلَحُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 6, 'وَٱلَّذِينَ يَرْمُونَ أَزْوَٰجَهُمْ وَلَمْ يَكُن لَّهُمْ شُهَدَآءُ إِلَّآ أَنفُسُهُمْ فَشَهَٰدَةُ أَحَدِهِمْ أَرْبَعُ شَهَٰدَٰتٍۭ بِٱللَّهِ ۙ إِنَّهُۥ لَمِنَ ٱلصَّٰدِقِينَ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 7, 'وَٱلْخَٰمِسَةُ أَنَّ لَعْنَتَ ٱللَّهِ عَلَيْهِ إِن كَانَ مِنَ ٱلْكَٰذِبِينَ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 8, 'وَيَدْرَؤُا۟ عَنْهَا ٱلْعَذَابَ أَن تَشْهَدَ أَرْبَعَ شَهَٰدَٰتٍۭ بِٱللَّهِ ۙ إِنَّهُۥ لَمِنَ ٱلْكَٰذِبِينَ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 9, 'وَٱلْخَٰمِسَةَ أَنَّ غَضَبَ ٱللَّهِ عَلَيْهَآ إِن كَانَ مِنَ ٱلصَّٰدِقِينَ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 10, 'وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ وَأَنَّ ٱللَّهَ تَوَّابٌ حَكِيمٌ', NULL, 18, 140, 4, 350, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 11, 'إِنَّ ٱلَّذِينَ جَآءُو بِٱلْإِفْكِ عُصْبَةٌۭ مِّنكُمْ ۚ لَا تَحْسَبُوهُ شَرًّۭا لَّكُم ۖ بَلْ هُوَ خَيْرٌۭ لَّكُمْ ۚ لِكُلِّ ٱمْرِئٍۢ مِّنْهُم مَّا ٱكْتَسَبَ مِنَ ٱلْإِثْمِ ۚ وَٱلَّذِى تَوَلَّىٰ كِبْرَهُۥ مِنْهُمْ لَهُۥ عَذَابٌ عَظِيمٌۭ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 12, 'لَّوْلَآ إِذْ سَمِعْتُمُوهُ ظَنَّ ٱلْمُؤْمِنُونَ وَٱلْمُؤْمِنَٰتُ بِأَنفُسِهِمْ خَيْرًۭا وَقَالُوا۟ هَٰذَآ إِفْكٌۭ مُّبِينٌۭ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 13, 'لَّوْلَا جَآءُو عَلَيْهِ بِأَرْبَعَةِ شُهَدَآءَ ۚ فَإِذْ لَمْ يَأْتُوا۟ بِٱلشُّهَدَآءِ فَأُو۟لَٰٓئِكَ عِندَ ٱللَّهِ هُمُ ٱلْكَٰذِبُونَ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 14, 'وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ لَمَسَّكُمْ فِى مَآ أَفَضْتُمْ فِيهِ عَذَابٌ عَظِيمٌ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 15, 'إِذْ تَلَقَّوْنَهُۥ بِأَلْسِنَتِكُمْ وَتَقُولُونَ بِأَفْوَاهِكُم مَّا لَيْسَ لَكُم بِهِۦ عِلْمٌۭ وَتَحْسَبُونَهُۥ هَيِّنًۭا وَهُوَ عِندَ ٱللَّهِ عَظِيمٌۭ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 16, 'وَلَوْلَآ إِذْ سَمِعْتُمُوهُ قُلْتُم مَّا يَكُونُ لَنَآ أَن نَّتَكَلَّمَ بِهَٰذَا سُبْحَٰنَكَ هَٰذَا بُهْتَٰنٌ عَظِيمٌۭ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 17, 'يَعِظُكُمُ ٱللَّهُ أَن تَعُودُوا۟ لِمِثْلِهِۦٓ أَبَدًا إِن كُنتُم مُّؤْمِنِينَ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 18, 'وَيُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ ۚ وَٱللَّهُ عَلِيمٌ حَكِيمٌ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 19, 'إِنَّ ٱلَّذِينَ يُحِبُّونَ أَن تَشِيعَ ٱلْفَٰحِشَةُ فِى ٱلَّذِينَ ءَامَنُوا۟ لَهُمْ عَذَابٌ أَلِيمٌۭ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ ۚ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 20, 'وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ وَأَنَّ ٱللَّهَ رَءُوفٌۭ رَّحِيمٌۭ', NULL, 18, 140, 4, 351, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 21, '۞ يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَٰنِ ۚ وَمَن يَتَّبِعْ خُطُوَٰتِ ٱلشَّيْطَٰنِ فَإِنَّهُۥ يَأْمُرُ بِٱلْفَحْشَآءِ وَٱلْمُنكَرِ ۚ وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ مَا زَكَىٰ مِنكُم مِّنْ أَحَدٍ أَبَدًۭا وَلَٰكِنَّ ٱللَّهَ يُزَكِّى مَن يَشَآءُ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌۭ', NULL, 18, 141, 4, 352, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 22, 'وَلَا يَأْتَلِ أُو۟لُوا۟ ٱلْفَضْلِ مِنكُمْ وَٱلسَّعَةِ أَن يُؤْتُوٓا۟ أُو۟لِى ٱلْقُرْبَىٰ وَٱلْمَسَٰكِينَ وَٱلْمُهَٰجِرِينَ فِى سَبِيلِ ٱللَّهِ ۖ وَلْيَعْفُوا۟ وَلْيَصْفَحُوٓا۟ ۗ أَلَا تُحِبُّونَ أَن يَغْفِرَ ٱللَّهُ لَكُمْ ۗ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌ', NULL, 18, 141, 4, 352, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 23, 'إِنَّ ٱلَّذِينَ يَرْمُونَ ٱلْمُحْصَنَٰتِ ٱلْغَٰفِلَٰتِ ٱلْمُؤْمِنَٰتِ لُعِنُوا۟ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ وَلَهُمْ عَذَابٌ عَظِيمٌۭ', NULL, 18, 141, 4, 352, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 24, 'يَوْمَ تَشْهَدُ عَلَيْهِمْ أَلْسِنَتُهُمْ وَأَيْدِيهِمْ وَأَرْجُلُهُم بِمَا كَانُوا۟ يَعْمَلُونَ', NULL, 18, 141, 4, 352, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 25, 'يَوْمَئِذٍۢ يُوَفِّيهِمُ ٱللَّهُ دِينَهُمُ ٱلْحَقَّ وَيَعْلَمُونَ أَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ ٱلْمُبِينُ', NULL, 18, 141, 4, 352, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 26, 'ٱلْخَبِيثَٰتُ لِلْخَبِيثِينَ وَٱلْخَبِيثُونَ لِلْخَبِيثَٰتِ ۖ وَٱلطَّيِّبَٰتُ لِلطَّيِّبِينَ وَٱلطَّيِّبُونَ لِلطَّيِّبَٰتِ ۚ أُو۟لَٰٓئِكَ مُبَرَّءُونَ مِمَّا يَقُولُونَ ۖ لَهُم مَّغْفِرَةٌۭ وَرِزْقٌۭ كَرِيمٌۭ', NULL, 18, 141, 4, 352, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 27, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَدْخُلُوا۟ بُيُوتًا غَيْرَ بُيُوتِكُمْ حَتَّىٰ تَسْتَأْنِسُوا۟ وَتُسَلِّمُوا۟ عَلَىٰٓ أَهْلِهَا ۚ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ لَعَلَّكُمْ تَذَكَّرُونَ', NULL, 18, 141, 4, 352, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 28, 'فَإِن لَّمْ تَجِدُوا۟ فِيهَآ أَحَدًۭا فَلَا تَدْخُلُوهَا حَتَّىٰ يُؤْذَنَ لَكُمْ ۖ وَإِن قِيلَ لَكُمُ ٱرْجِعُوا۟ فَٱرْجِعُوا۟ ۖ هُوَ أَزْكَىٰ لَكُمْ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ عَلِيمٌۭ', NULL, 18, 141, 4, 353, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 29, 'لَّيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَدْخُلُوا۟ بُيُوتًا غَيْرَ مَسْكُونَةٍۢ فِيهَا مَتَٰعٌۭ لَّكُمْ ۚ وَٱللَّهُ يَعْلَمُ مَا تُبْدُونَ وَمَا تَكْتُمُونَ', NULL, 18, 141, 4, 353, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 30, 'قُل لِّلْمُؤْمِنِينَ يَغُضُّوا۟ مِنْ أَبْصَٰرِهِمْ وَيَحْفَظُوا۟ فُرُوجَهُمْ ۚ ذَٰلِكَ أَزْكَىٰ لَهُمْ ۗ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا يَصْنَعُونَ', NULL, 18, 141, 4, 353, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 31, 'وَقُل لِّلْمُؤْمِنَٰتِ يَغْضُضْنَ مِنْ أَبْصَٰرِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا ۖ وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَىٰ جُيُوبِهِنَّ ۖ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا لِبُعُولَتِهِنَّ أَوْ ءَابَآئِهِنَّ أَوْ ءَابَآءِ بُعُولَتِهِنَّ أَوْ أَبْنَآئِهِنَّ أَوْ أَبْنَآءِ بُعُولَتِهِنَّ أَوْ إِخْوَٰنِهِنَّ أَوْ بَنِىٓ إِخْوَٰنِهِنَّ أَوْ بَنِىٓ أَخَوَٰتِهِنَّ أَوْ نِسَآئِهِنَّ أَوْ مَا مَلَكَتْ أَيْمَٰنُهُنَّ أَوِ ٱلتَّٰبِعِينَ غَيْرِ أُو۟لِى ٱلْإِرْبَةِ مِنَ ٱلرِّجَالِ أَوِ ٱلطِّفْلِ ٱلَّذِينَ لَمْ يَظْهَرُوا۟ عَلَىٰ عَوْرَٰتِ ٱلنِّسَآءِ ۖ وَلَا يَضْرِبْنَ بِأَرْجُلِهِنَّ لِيُعْلَمَ مَا يُخْفِينَ مِن زِينَتِهِنَّ ۚ وَتُوبُوٓا۟ إِلَى ٱللَّهِ جَمِيعًا أَيُّهَ ٱلْمُؤْمِنُونَ لَعَلَّكُمْ تُفْلِحُونَ', NULL, 18, 141, 4, 353, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 32, 'وَأَنكِحُوا۟ ٱلْأَيَٰمَىٰ مِنكُمْ وَٱلصَّٰلِحِينَ مِنْ عِبَادِكُمْ وَإِمَآئِكُمْ ۚ إِن يَكُونُوا۟ فُقَرَآءَ يُغْنِهِمُ ٱللَّهُ مِن فَضْلِهِۦ ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌۭ', NULL, 18, 141, 4, 354, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 33, 'وَلْيَسْتَعْفِفِ ٱلَّذِينَ لَا يَجِدُونَ نِكَاحًا حَتَّىٰ يُغْنِيَهُمُ ٱللَّهُ مِن فَضْلِهِۦ ۗ وَٱلَّذِينَ يَبْتَغُونَ ٱلْكِتَٰبَ مِمَّا مَلَكَتْ أَيْمَٰنُكُمْ فَكَاتِبُوهُمْ إِنْ عَلِمْتُمْ فِيهِمْ خَيْرًۭا ۖ وَءَاتُوهُم مِّن مَّالِ ٱللَّهِ ٱلَّذِىٓ ءَاتَىٰكُمْ ۚ وَلَا تُكْرِهُوا۟ فَتَيَٰتِكُمْ عَلَى ٱلْبِغَآءِ إِنْ أَرَدْنَ تَحَصُّنًۭا لِّتَبْتَغُوا۟ عَرَضَ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَمَن يُكْرِههُّنَّ فَإِنَّ ٱللَّهَ مِنۢ بَعْدِ إِكْرَٰهِهِنَّ غَفُورٌۭ رَّحِيمٌۭ', NULL, 18, 141, 4, 354, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 34, 'وَلَقَدْ أَنزَلْنَآ إِلَيْكُمْ ءَايَٰتٍۢ مُّبَيِّنَٰتٍۢ وَمَثَلًۭا مِّنَ ٱلَّذِينَ خَلَوْا۟ مِن قَبْلِكُمْ وَمَوْعِظَةًۭ لِّلْمُتَّقِينَ', NULL, 18, 141, 4, 354, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 35, '۞ ٱللَّهُ نُورُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ مَثَلُ نُورِهِۦ كَمِشْكَوٰةٍۢ فِيهَا مِصْبَاحٌ ۖ ٱلْمِصْبَاحُ فِى زُجَاجَةٍ ۖ ٱلزُّجَاجَةُ كَأَنَّهَا كَوْكَبٌۭ دُرِّىٌّۭ يُوقَدُ مِن شَجَرَةٍۢ مُّبَٰرَكَةٍۢ زَيْتُونَةٍۢ لَّا شَرْقِيَّةٍۢ وَلَا غَرْبِيَّةٍۢ يَكَادُ زَيْتُهَا يُضِىٓءُ وَلَوْ لَمْ تَمْسَسْهُ نَارٌۭ ۚ نُّورٌ عَلَىٰ نُورٍۢ ۗ يَهْدِى ٱللَّهُ لِنُورِهِۦ مَن يَشَآءُ ۚ وَيَضْرِبُ ٱللَّهُ ٱلْأَمْثَٰلَ لِلنَّاسِ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۭ', NULL, 18, 142, 4, 354, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 36, 'فِى بُيُوتٍ أَذِنَ ٱللَّهُ أَن تُرْفَعَ وَيُذْكَرَ فِيهَا ٱسْمُهُۥ يُسَبِّحُ لَهُۥ فِيهَا بِٱلْغُدُوِّ وَٱلْءَاصَالِ', NULL, 18, 142, 4, 354, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 37, 'رِجَالٌۭ لَّا تُلْهِيهِمْ تِجَٰرَةٌۭ وَلَا بَيْعٌ عَن ذِكْرِ ٱللَّهِ وَإِقَامِ ٱلصَّلَوٰةِ وَإِيتَآءِ ٱلزَّكَوٰةِ ۙ يَخَافُونَ يَوْمًۭا تَتَقَلَّبُ فِيهِ ٱلْقُلُوبُ وَٱلْأَبْصَٰرُ', NULL, 18, 142, 4, 355, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 38, 'لِيَجْزِيَهُمُ ٱللَّهُ أَحْسَنَ مَا عَمِلُوا۟ وَيَزِيدَهُم مِّن فَضْلِهِۦ ۗ وَٱللَّهُ يَرْزُقُ مَن يَشَآءُ بِغَيْرِ حِسَابٍۢ', NULL, 18, 142, 4, 355, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 39, 'وَٱلَّذِينَ كَفَرُوٓا۟ أَعْمَٰلُهُمْ كَسَرَابٍۭ بِقِيعَةٍۢ يَحْسَبُهُ ٱلظَّمْـَٔانُ مَآءً حَتَّىٰٓ إِذَا جَآءَهُۥ لَمْ يَجِدْهُ شَيْـًۭٔا وَوَجَدَ ٱللَّهَ عِندَهُۥ فَوَفَّىٰهُ حِسَابَهُۥ ۗ وَٱللَّهُ سَرِيعُ ٱلْحِسَابِ', NULL, 18, 142, 4, 355, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 40, 'أَوْ كَظُلُمَٰتٍۢ فِى بَحْرٍۢ لُّجِّىٍّۢ يَغْشَىٰهُ مَوْجٌۭ مِّن فَوْقِهِۦ مَوْجٌۭ مِّن فَوْقِهِۦ سَحَابٌۭ ۚ ظُلُمَٰتٌۢ بَعْضُهَا فَوْقَ بَعْضٍ إِذَآ أَخْرَجَ يَدَهُۥ لَمْ يَكَدْ يَرَىٰهَا ۗ وَمَن لَّمْ يَجْعَلِ ٱللَّهُ لَهُۥ نُورًۭا فَمَا لَهُۥ مِن نُّورٍ', NULL, 18, 142, 4, 355, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 41, 'أَلَمْ تَرَ أَنَّ ٱللَّهَ يُسَبِّحُ لَهُۥ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَٱلطَّيْرُ صَٰٓفَّٰتٍۢ ۖ كُلٌّۭ قَدْ عَلِمَ صَلَاتَهُۥ وَتَسْبِيحَهُۥ ۗ وَٱللَّهُ عَلِيمٌۢ بِمَا يَفْعَلُونَ', NULL, 18, 142, 4, 355, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 42, 'وَلِلَّهِ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ وَإِلَى ٱللَّهِ ٱلْمَصِيرُ', NULL, 18, 142, 4, 355, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 43, 'أَلَمْ تَرَ أَنَّ ٱللَّهَ يُزْجِى سَحَابًۭا ثُمَّ يُؤَلِّفُ بَيْنَهُۥ ثُمَّ يَجْعَلُهُۥ رُكَامًۭا فَتَرَى ٱلْوَدْقَ يَخْرُجُ مِنْ خِلَٰلِهِۦ وَيُنَزِّلُ مِنَ ٱلسَّمَآءِ مِن جِبَالٍۢ فِيهَا مِنۢ بَرَدٍۢ فَيُصِيبُ بِهِۦ مَن يَشَآءُ وَيَصْرِفُهُۥ عَن مَّن يَشَآءُ ۖ يَكَادُ سَنَا بَرْقِهِۦ يَذْهَبُ بِٱلْأَبْصَٰرِ', NULL, 18, 142, 4, 355, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 44, 'يُقَلِّبُ ٱللَّهُ ٱلَّيْلَ وَٱلنَّهَارَ ۚ إِنَّ فِى ذَٰلِكَ لَعِبْرَةًۭ لِّأُو۟لِى ٱلْأَبْصَٰرِ', NULL, 18, 142, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 45, 'وَٱللَّهُ خَلَقَ كُلَّ دَآبَّةٍۢ مِّن مَّآءٍۢ ۖ فَمِنْهُم مَّن يَمْشِى عَلَىٰ بَطْنِهِۦ وَمِنْهُم مَّن يَمْشِى عَلَىٰ رِجْلَيْنِ وَمِنْهُم مَّن يَمْشِى عَلَىٰٓ أَرْبَعٍۢ ۚ يَخْلُقُ ٱللَّهُ مَا يَشَآءُ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ', NULL, 18, 142, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 46, 'لَّقَدْ أَنزَلْنَآ ءَايَٰتٍۢ مُّبَيِّنَٰتٍۢ ۚ وَٱللَّهُ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ', NULL, 18, 142, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 47, 'وَيَقُولُونَ ءَامَنَّا بِٱللَّهِ وَبِٱلرَّسُولِ وَأَطَعْنَا ثُمَّ يَتَوَلَّىٰ فَرِيقٌۭ مِّنْهُم مِّنۢ بَعْدِ ذَٰلِكَ ۚ وَمَآ أُو۟لَٰٓئِكَ بِٱلْمُؤْمِنِينَ', NULL, 18, 142, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 48, 'وَإِذَا دُعُوٓا۟ إِلَى ٱللَّهِ وَرَسُولِهِۦ لِيَحْكُمَ بَيْنَهُمْ إِذَا فَرِيقٌۭ مِّنْهُم مُّعْرِضُونَ', NULL, 18, 142, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 49, 'وَإِن يَكُن لَّهُمُ ٱلْحَقُّ يَأْتُوٓا۟ إِلَيْهِ مُذْعِنِينَ', NULL, 18, 142, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 50, 'أَفِى قُلُوبِهِم مَّرَضٌ أَمِ ٱرْتَابُوٓا۟ أَمْ يَخَافُونَ أَن يَحِيفَ ٱللَّهُ عَلَيْهِمْ وَرَسُولُهُۥ ۚ بَلْ أُو۟لَٰٓئِكَ هُمُ ٱلظَّٰلِمُونَ', NULL, 18, 142, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 51, 'إِنَّمَا كَانَ قَوْلَ ٱلْمُؤْمِنِينَ إِذَا دُعُوٓا۟ إِلَى ٱللَّهِ وَرَسُولِهِۦ لِيَحْكُمَ بَيْنَهُمْ أَن يَقُولُوا۟ سَمِعْنَا وَأَطَعْنَا ۚ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ', NULL, 18, 142, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 52, 'وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ وَيَخْشَ ٱللَّهَ وَيَتَّقْهِ فَأُو۟لَٰٓئِكَ هُمُ ٱلْفَآئِزُونَ', NULL, 18, 142, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 53, '۞ وَأَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَٰنِهِمْ لَئِنْ أَمَرْتَهُمْ لَيَخْرُجُنَّ ۖ قُل لَّا تُقْسِمُوا۟ ۖ طَاعَةٌۭ مَّعْرُوفَةٌ ۚ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا تَعْمَلُونَ', NULL, 18, 143, 4, 356, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 54, 'قُلْ أَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ ۖ فَإِن تَوَلَّوْا۟ فَإِنَّمَا عَلَيْهِ مَا حُمِّلَ وَعَلَيْكُم مَّا حُمِّلْتُمْ ۖ وَإِن تُطِيعُوهُ تَهْتَدُوا۟ ۚ وَمَا عَلَى ٱلرَّسُولِ إِلَّا ٱلْبَلَٰغُ ٱلْمُبِينُ', NULL, 18, 143, 4, 357, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 55, 'وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ مِنكُمْ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَيَسْتَخْلِفَنَّهُمْ فِى ٱلْأَرْضِ كَمَا ٱسْتَخْلَفَ ٱلَّذِينَ مِن قَبْلِهِمْ وَلَيُمَكِّنَنَّ لَهُمْ دِينَهُمُ ٱلَّذِى ٱرْتَضَىٰ لَهُمْ وَلَيُبَدِّلَنَّهُم مِّنۢ بَعْدِ خَوْفِهِمْ أَمْنًۭا ۚ يَعْبُدُونَنِى لَا يُشْرِكُونَ بِى شَيْـًۭٔا ۚ وَمَن كَفَرَ بَعْدَ ذَٰلِكَ فَأُو۟لَٰٓئِكَ هُمُ ٱلْفَٰسِقُونَ', NULL, 18, 143, 4, 357, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 56, 'وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَأَطِيعُوا۟ ٱلرَّسُولَ لَعَلَّكُمْ تُرْحَمُونَ', NULL, 18, 143, 4, 357, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 57, 'لَا تَحْسَبَنَّ ٱلَّذِينَ كَفَرُوا۟ مُعْجِزِينَ فِى ٱلْأَرْضِ ۚ وَمَأْوَىٰهُمُ ٱلنَّارُ ۖ وَلَبِئْسَ ٱلْمَصِيرُ', NULL, 18, 143, 4, 357, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 58, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لِيَسْتَـْٔذِنكُمُ ٱلَّذِينَ مَلَكَتْ أَيْمَٰنُكُمْ وَٱلَّذِينَ لَمْ يَبْلُغُوا۟ ٱلْحُلُمَ مِنكُمْ ثَلَٰثَ مَرَّٰتٍۢ ۚ مِّن قَبْلِ صَلَوٰةِ ٱلْفَجْرِ وَحِينَ تَضَعُونَ ثِيَابَكُم مِّنَ ٱلظَّهِيرَةِ وَمِنۢ بَعْدِ صَلَوٰةِ ٱلْعِشَآءِ ۚ ثَلَٰثُ عَوْرَٰتٍۢ لَّكُمْ ۚ لَيْسَ عَلَيْكُمْ وَلَا عَلَيْهِمْ جُنَاحٌۢ بَعْدَهُنَّ ۚ طَوَّٰفُونَ عَلَيْكُم بَعْضُكُمْ عَلَىٰ بَعْضٍۢ ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌۭ', NULL, 18, 143, 4, 357, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 59, 'وَإِذَا بَلَغَ ٱلْأَطْفَٰلُ مِنكُمُ ٱلْحُلُمَ فَلْيَسْتَـْٔذِنُوا۟ كَمَا ٱسْتَـْٔذَنَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَٰتِهِۦ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌۭ', NULL, 18, 143, 4, 358, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 60, 'وَٱلْقَوَٰعِدُ مِنَ ٱلنِّسَآءِ ٱلَّٰتِى لَا يَرْجُونَ نِكَاحًۭا فَلَيْسَ عَلَيْهِنَّ جُنَاحٌ أَن يَضَعْنَ ثِيَابَهُنَّ غَيْرَ مُتَبَرِّجَٰتٍۭ بِزِينَةٍۢ ۖ وَأَن يَسْتَعْفِفْنَ خَيْرٌۭ لَّهُنَّ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌۭ', NULL, 18, 143, 4, 358, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 61, 'لَّيْسَ عَلَى ٱلْأَعْمَىٰ حَرَجٌۭ وَلَا عَلَى ٱلْأَعْرَجِ حَرَجٌۭ وَلَا عَلَى ٱلْمَرِيضِ حَرَجٌۭ وَلَا عَلَىٰٓ أَنفُسِكُمْ أَن تَأْكُلُوا۟ مِنۢ بُيُوتِكُمْ أَوْ بُيُوتِ ءَابَآئِكُمْ أَوْ بُيُوتِ أُمَّهَٰتِكُمْ أَوْ بُيُوتِ إِخْوَٰنِكُمْ أَوْ بُيُوتِ أَخَوَٰتِكُمْ أَوْ بُيُوتِ أَعْمَٰمِكُمْ أَوْ بُيُوتِ عَمَّٰتِكُمْ أَوْ بُيُوتِ أَخْوَٰلِكُمْ أَوْ بُيُوتِ خَٰلَٰتِكُمْ أَوْ مَا مَلَكْتُم مَّفَاتِحَهُۥٓ أَوْ صَدِيقِكُمْ ۚ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَأْكُلُوا۟ جَمِيعًا أَوْ أَشْتَاتًۭا ۚ فَإِذَا دَخَلْتُم بُيُوتًۭا فَسَلِّمُوا۟ عَلَىٰٓ أَنفُسِكُمْ تَحِيَّةًۭ مِّنْ عِندِ ٱللَّهِ مُبَٰرَكَةًۭ طَيِّبَةًۭ ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ لَعَلَّكُمْ تَعْقِلُونَ', NULL, 18, 143, 4, 358, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 62, 'إِنَّمَا ٱلْمُؤْمِنُونَ ٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَإِذَا كَانُوا۟ مَعَهُۥ عَلَىٰٓ أَمْرٍۢ جَامِعٍۢ لَّمْ يَذْهَبُوا۟ حَتَّىٰ يَسْتَـْٔذِنُوهُ ۚ إِنَّ ٱلَّذِينَ يَسْتَـْٔذِنُونَكَ أُو۟لَٰٓئِكَ ٱلَّذِينَ يُؤْمِنُونَ بِٱللَّهِ وَرَسُولِهِۦ ۚ فَإِذَا ٱسْتَـْٔذَنُوكَ لِبَعْضِ شَأْنِهِمْ فَأْذَن لِّمَن شِئْتَ مِنْهُمْ وَٱسْتَغْفِرْ لَهُمُ ٱللَّهَ ۚ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ', NULL, 18, 143, 4, 359, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 63, 'لَّا تَجْعَلُوا۟ دُعَآءَ ٱلرَّسُولِ بَيْنَكُمْ كَدُعَآءِ بَعْضِكُم بَعْضًۭا ۚ قَدْ يَعْلَمُ ٱللَّهُ ٱلَّذِينَ يَتَسَلَّلُونَ مِنكُمْ لِوَاذًۭا ۚ فَلْيَحْذَرِ ٱلَّذِينَ يُخَالِفُونَ عَنْ أَمْرِهِۦٓ أَن تُصِيبَهُمْ فِتْنَةٌ أَوْ يُصِيبَهُمْ عَذَابٌ أَلِيمٌ', NULL, 18, 143, 4, 359, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 24), 64, 'أَلَآ إِنَّ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ قَدْ يَعْلَمُ مَآ أَنتُمْ عَلَيْهِ وَيَوْمَ يُرْجَعُونَ إِلَيْهِ فَيُنَبِّئُهُم بِمَا عَمِلُوا۟ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۢ', NULL, 18, 143, 4, 359, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ تَبَارَكَ ٱلَّذِى نَزَّلَ ٱلْفُرْقَانَ عَلَىٰ عَبْدِهِۦ لِيَكُونَ لِلْعَٰلَمِينَ نَذِيرًا', NULL, 18, 144, 4, 359, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 2, 'ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَلَمْ يَتَّخِذْ وَلَدًۭا وَلَمْ يَكُن لَّهُۥ شَرِيكٌۭ فِى ٱلْمُلْكِ وَخَلَقَ كُلَّ شَىْءٍۢ فَقَدَّرَهُۥ تَقْدِيرًۭا', NULL, 18, 144, 4, 359, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 3, 'وَٱتَّخَذُوا۟ مِن دُونِهِۦٓ ءَالِهَةًۭ لَّا يَخْلُقُونَ شَيْـًۭٔا وَهُمْ يُخْلَقُونَ وَلَا يَمْلِكُونَ لِأَنفُسِهِمْ ضَرًّۭا وَلَا نَفْعًۭا وَلَا يَمْلِكُونَ مَوْتًۭا وَلَا حَيَوٰةًۭ وَلَا نُشُورًۭا', NULL, 18, 144, 4, 360, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 4, 'وَقَالَ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ هَٰذَآ إِلَّآ إِفْكٌ ٱفْتَرَىٰهُ وَأَعَانَهُۥ عَلَيْهِ قَوْمٌ ءَاخَرُونَ ۖ فَقَدْ جَآءُو ظُلْمًۭا وَزُورًۭا', NULL, 18, 144, 4, 360, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 5, 'وَقَالُوٓا۟ أَسَٰطِيرُ ٱلْأَوَّلِينَ ٱكْتَتَبَهَا فَهِىَ تُمْلَىٰ عَلَيْهِ بُكْرَةًۭ وَأَصِيلًۭا', NULL, 18, 144, 4, 360, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 6, 'قُلْ أَنزَلَهُ ٱلَّذِى يَعْلَمُ ٱلسِّرَّ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ إِنَّهُۥ كَانَ غَفُورًۭا رَّحِيمًۭا', NULL, 18, 144, 4, 360, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 7, 'وَقَالُوا۟ مَالِ هَٰذَا ٱلرَّسُولِ يَأْكُلُ ٱلطَّعَامَ وَيَمْشِى فِى ٱلْأَسْوَاقِ ۙ لَوْلَآ أُنزِلَ إِلَيْهِ مَلَكٌۭ فَيَكُونَ مَعَهُۥ نَذِيرًا', NULL, 18, 144, 4, 360, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 8, 'أَوْ يُلْقَىٰٓ إِلَيْهِ كَنزٌ أَوْ تَكُونُ لَهُۥ جَنَّةٌۭ يَأْكُلُ مِنْهَا ۚ وَقَالَ ٱلظَّٰلِمُونَ إِن تَتَّبِعُونَ إِلَّا رَجُلًۭا مَّسْحُورًا', NULL, 18, 144, 4, 360, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 9, 'ٱنظُرْ كَيْفَ ضَرَبُوا۟ لَكَ ٱلْأَمْثَٰلَ فَضَلُّوا۟ فَلَا يَسْتَطِيعُونَ سَبِيلًۭا', NULL, 18, 144, 4, 360, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 10, 'تَبَارَكَ ٱلَّذِىٓ إِن شَآءَ جَعَلَ لَكَ خَيْرًۭا مِّن ذَٰلِكَ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ وَيَجْعَل لَّكَ قُصُورًۢا', NULL, 18, 144, 4, 360, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 11, 'بَلْ كَذَّبُوا۟ بِٱلسَّاعَةِ ۖ وَأَعْتَدْنَا لِمَن كَذَّبَ بِٱلسَّاعَةِ سَعِيرًا', NULL, 18, 144, 4, 360, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 12, 'إِذَا رَأَتْهُم مِّن مَّكَانٍۭ بَعِيدٍۢ سَمِعُوا۟ لَهَا تَغَيُّظًۭا وَزَفِيرًۭا', NULL, 18, 144, 4, 361, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 13, 'وَإِذَآ أُلْقُوا۟ مِنْهَا مَكَانًۭا ضَيِّقًۭا مُّقَرَّنِينَ دَعَوْا۟ هُنَالِكَ ثُبُورًۭا', NULL, 18, 144, 4, 361, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 14, 'لَّا تَدْعُوا۟ ٱلْيَوْمَ ثُبُورًۭا وَٰحِدًۭا وَٱدْعُوا۟ ثُبُورًۭا كَثِيرًۭا', NULL, 18, 144, 4, 361, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 15, 'قُلْ أَذَٰلِكَ خَيْرٌ أَمْ جَنَّةُ ٱلْخُلْدِ ٱلَّتِى وُعِدَ ٱلْمُتَّقُونَ ۚ كَانَتْ لَهُمْ جَزَآءًۭ وَمَصِيرًۭا', NULL, 18, 144, 4, 361, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 16, 'لَّهُمْ فِيهَا مَا يَشَآءُونَ خَٰلِدِينَ ۚ كَانَ عَلَىٰ رَبِّكَ وَعْدًۭا مَّسْـُٔولًۭا', NULL, 18, 144, 4, 361, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 17, 'وَيَوْمَ يَحْشُرُهُمْ وَمَا يَعْبُدُونَ مِن دُونِ ٱللَّهِ فَيَقُولُ ءَأَنتُمْ أَضْلَلْتُمْ عِبَادِى هَٰٓؤُلَآءِ أَمْ هُمْ ضَلُّوا۟ ٱلسَّبِيلَ', NULL, 18, 144, 4, 361, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 18, 'قَالُوا۟ سُبْحَٰنَكَ مَا كَانَ يَنۢبَغِى لَنَآ أَن نَّتَّخِذَ مِن دُونِكَ مِنْ أَوْلِيَآءَ وَلَٰكِن مَّتَّعْتَهُمْ وَءَابَآءَهُمْ حَتَّىٰ نَسُوا۟ ٱلذِّكْرَ وَكَانُوا۟ قَوْمًۢا بُورًۭا', NULL, 18, 144, 4, 361, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 19, 'فَقَدْ كَذَّبُوكُم بِمَا تَقُولُونَ فَمَا تَسْتَطِيعُونَ صَرْفًۭا وَلَا نَصْرًۭا ۚ وَمَن يَظْلِم مِّنكُمْ نُذِقْهُ عَذَابًۭا كَبِيرًۭا', NULL, 18, 144, 4, 361, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 20, 'وَمَآ أَرْسَلْنَا قَبْلَكَ مِنَ ٱلْمُرْسَلِينَ إِلَّآ إِنَّهُمْ لَيَأْكُلُونَ ٱلطَّعَامَ وَيَمْشُونَ فِى ٱلْأَسْوَاقِ ۗ وَجَعَلْنَا بَعْضَكُمْ لِبَعْضٍۢ فِتْنَةً أَتَصْبِرُونَ ۗ وَكَانَ رَبُّكَ بَصِيرًۭا', NULL, 18, 144, 4, 361, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 21, '۞ وَقَالَ ٱلَّذِينَ لَا يَرْجُونَ لِقَآءَنَا لَوْلَآ أُنزِلَ عَلَيْنَا ٱلْمَلَٰٓئِكَةُ أَوْ نَرَىٰ رَبَّنَا ۗ لَقَدِ ٱسْتَكْبَرُوا۟ فِىٓ أَنفُسِهِمْ وَعَتَوْ عُتُوًّۭا كَبِيرًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 22, 'يَوْمَ يَرَوْنَ ٱلْمَلَٰٓئِكَةَ لَا بُشْرَىٰ يَوْمَئِذٍۢ لِّلْمُجْرِمِينَ وَيَقُولُونَ حِجْرًۭا مَّحْجُورًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 23, 'وَقَدِمْنَآ إِلَىٰ مَا عَمِلُوا۟ مِنْ عَمَلٍۢ فَجَعَلْنَٰهُ هَبَآءًۭ مَّنثُورًا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 24, 'أَصْحَٰبُ ٱلْجَنَّةِ يَوْمَئِذٍ خَيْرٌۭ مُّسْتَقَرًّۭا وَأَحْسَنُ مَقِيلًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 25, 'وَيَوْمَ تَشَقَّقُ ٱلسَّمَآءُ بِٱلْغَمَٰمِ وَنُزِّلَ ٱلْمَلَٰٓئِكَةُ تَنزِيلًا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 26, 'ٱلْمُلْكُ يَوْمَئِذٍ ٱلْحَقُّ لِلرَّحْمَٰنِ ۚ وَكَانَ يَوْمًا عَلَى ٱلْكَٰفِرِينَ عَسِيرًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 27, 'وَيَوْمَ يَعَضُّ ٱلظَّالِمُ عَلَىٰ يَدَيْهِ يَقُولُ يَٰلَيْتَنِى ٱتَّخَذْتُ مَعَ ٱلرَّسُولِ سَبِيلًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 28, 'يَٰوَيْلَتَىٰ لَيْتَنِى لَمْ أَتَّخِذْ فُلَانًا خَلِيلًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 29, 'لَّقَدْ أَضَلَّنِى عَنِ ٱلذِّكْرِ بَعْدَ إِذْ جَآءَنِى ۗ وَكَانَ ٱلشَّيْطَٰنُ لِلْإِنسَٰنِ خَذُولًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 30, 'وَقَالَ ٱلرَّسُولُ يَٰرَبِّ إِنَّ قَوْمِى ٱتَّخَذُوا۟ هَٰذَا ٱلْقُرْءَانَ مَهْجُورًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 31, 'وَكَذَٰلِكَ جَعَلْنَا لِكُلِّ نَبِىٍّ عَدُوًّۭا مِّنَ ٱلْمُجْرِمِينَ ۗ وَكَفَىٰ بِرَبِّكَ هَادِيًۭا وَنَصِيرًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 32, 'وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَوْلَا نُزِّلَ عَلَيْهِ ٱلْقُرْءَانُ جُمْلَةًۭ وَٰحِدَةًۭ ۚ كَذَٰلِكَ لِنُثَبِّتَ بِهِۦ فُؤَادَكَ ۖ وَرَتَّلْنَٰهُ تَرْتِيلًۭا', NULL, 19, 145, 4, 362, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 33, 'وَلَا يَأْتُونَكَ بِمَثَلٍ إِلَّا جِئْنَٰكَ بِٱلْحَقِّ وَأَحْسَنَ تَفْسِيرًا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 34, 'ٱلَّذِينَ يُحْشَرُونَ عَلَىٰ وُجُوهِهِمْ إِلَىٰ جَهَنَّمَ أُو۟لَٰٓئِكَ شَرٌّۭ مَّكَانًۭا وَأَضَلُّ سَبِيلًۭا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 35, 'وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ وَجَعَلْنَا مَعَهُۥٓ أَخَاهُ هَٰرُونَ وَزِيرًۭا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 36, 'فَقُلْنَا ٱذْهَبَآ إِلَى ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا فَدَمَّرْنَٰهُمْ تَدْمِيرًۭا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 37, 'وَقَوْمَ نُوحٍۢ لَّمَّا كَذَّبُوا۟ ٱلرُّسُلَ أَغْرَقْنَٰهُمْ وَجَعَلْنَٰهُمْ لِلنَّاسِ ءَايَةًۭ ۖ وَأَعْتَدْنَا لِلظَّٰلِمِينَ عَذَابًا أَلِيمًۭا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 38, 'وَعَادًۭا وَثَمُودَا۟ وَأَصْحَٰبَ ٱلرَّسِّ وَقُرُونًۢا بَيْنَ ذَٰلِكَ كَثِيرًۭا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 39, 'وَكُلًّۭا ضَرَبْنَا لَهُ ٱلْأَمْثَٰلَ ۖ وَكُلًّۭا تَبَّرْنَا تَتْبِيرًۭا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 40, 'وَلَقَدْ أَتَوْا۟ عَلَى ٱلْقَرْيَةِ ٱلَّتِىٓ أُمْطِرَتْ مَطَرَ ٱلسَّوْءِ ۚ أَفَلَمْ يَكُونُوا۟ يَرَوْنَهَا ۚ بَلْ كَانُوا۟ لَا يَرْجُونَ نُشُورًۭا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 41, 'وَإِذَا رَأَوْكَ إِن يَتَّخِذُونَكَ إِلَّا هُزُوًا أَهَٰذَا ٱلَّذِى بَعَثَ ٱللَّهُ رَسُولًا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 42, 'إِن كَادَ لَيُضِلُّنَا عَنْ ءَالِهَتِنَا لَوْلَآ أَن صَبَرْنَا عَلَيْهَا ۚ وَسَوْفَ يَعْلَمُونَ حِينَ يَرَوْنَ ٱلْعَذَابَ مَنْ أَضَلُّ سَبِيلًا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 43, 'أَرَءَيْتَ مَنِ ٱتَّخَذَ إِلَٰهَهُۥ هَوَىٰهُ أَفَأَنتَ تَكُونُ عَلَيْهِ وَكِيلًا', NULL, 19, 145, 4, 363, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 44, 'أَمْ تَحْسَبُ أَنَّ أَكْثَرَهُمْ يَسْمَعُونَ أَوْ يَعْقِلُونَ ۚ إِنْ هُمْ إِلَّا كَٱلْأَنْعَٰمِ ۖ بَلْ هُمْ أَضَلُّ سَبِيلًا', NULL, 19, 145, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 45, 'أَلَمْ تَرَ إِلَىٰ رَبِّكَ كَيْفَ مَدَّ ٱلظِّلَّ وَلَوْ شَآءَ لَجَعَلَهُۥ سَاكِنًۭا ثُمَّ جَعَلْنَا ٱلشَّمْسَ عَلَيْهِ دَلِيلًۭا', NULL, 19, 145, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 46, 'ثُمَّ قَبَضْنَٰهُ إِلَيْنَا قَبْضًۭا يَسِيرًۭا', NULL, 19, 145, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 47, 'وَهُوَ ٱلَّذِى جَعَلَ لَكُمُ ٱلَّيْلَ لِبَاسًۭا وَٱلنَّوْمَ سُبَاتًۭا وَجَعَلَ ٱلنَّهَارَ نُشُورًۭا', NULL, 19, 145, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 48, 'وَهُوَ ٱلَّذِىٓ أَرْسَلَ ٱلرِّيَٰحَ بُشْرًۢا بَيْنَ يَدَىْ رَحْمَتِهِۦ ۚ وَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءًۭ طَهُورًۭا', NULL, 19, 145, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 49, 'لِّنُحْۦِىَ بِهِۦ بَلْدَةًۭ مَّيْتًۭا وَنُسْقِيَهُۥ مِمَّا خَلَقْنَآ أَنْعَٰمًۭا وَأَنَاسِىَّ كَثِيرًۭا', NULL, 19, 145, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 50, 'وَلَقَدْ صَرَّفْنَٰهُ بَيْنَهُمْ لِيَذَّكَّرُوا۟ فَأَبَىٰٓ أَكْثَرُ ٱلنَّاسِ إِلَّا كُفُورًۭا', NULL, 19, 145, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 51, 'وَلَوْ شِئْنَا لَبَعَثْنَا فِى كُلِّ قَرْيَةٍۢ نَّذِيرًۭا', NULL, 19, 145, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 52, 'فَلَا تُطِعِ ٱلْكَٰفِرِينَ وَجَٰهِدْهُم بِهِۦ جِهَادًۭا كَبِيرًۭا', NULL, 19, 145, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 53, '۞ وَهُوَ ٱلَّذِى مَرَجَ ٱلْبَحْرَيْنِ هَٰذَا عَذْبٌۭ فُرَاتٌۭ وَهَٰذَا مِلْحٌ أُجَاجٌۭ وَجَعَلَ بَيْنَهُمَا بَرْزَخًۭا وَحِجْرًۭا مَّحْجُورًۭا', NULL, 19, 146, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 54, 'وَهُوَ ٱلَّذِى خَلَقَ مِنَ ٱلْمَآءِ بَشَرًۭا فَجَعَلَهُۥ نَسَبًۭا وَصِهْرًۭا ۗ وَكَانَ رَبُّكَ قَدِيرًۭا', NULL, 19, 146, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 55, 'وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُهُمْ وَلَا يَضُرُّهُمْ ۗ وَكَانَ ٱلْكَافِرُ عَلَىٰ رَبِّهِۦ ظَهِيرًۭا', NULL, 19, 146, 4, 364, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 56, 'وَمَآ أَرْسَلْنَٰكَ إِلَّا مُبَشِّرًۭا وَنَذِيرًۭا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 57, 'قُلْ مَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ إِلَّا مَن شَآءَ أَن يَتَّخِذَ إِلَىٰ رَبِّهِۦ سَبِيلًۭا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 58, 'وَتَوَكَّلْ عَلَى ٱلْحَىِّ ٱلَّذِى لَا يَمُوتُ وَسَبِّحْ بِحَمْدِهِۦ ۚ وَكَفَىٰ بِهِۦ بِذُنُوبِ عِبَادِهِۦ خَبِيرًا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 59, 'ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍۢ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۚ ٱلرَّحْمَٰنُ فَسْـَٔلْ بِهِۦ خَبِيرًۭا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 60, 'وَإِذَا قِيلَ لَهُمُ ٱسْجُدُوا۟ لِلرَّحْمَٰنِ قَالُوا۟ وَمَا ٱلرَّحْمَٰنُ أَنَسْجُدُ لِمَا تَأْمُرُنَا وَزَادَهُمْ نُفُورًۭا ۩', NULL, 19, 146, 4, 365, true, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 61, 'تَبَارَكَ ٱلَّذِى جَعَلَ فِى ٱلسَّمَآءِ بُرُوجًۭا وَجَعَلَ فِيهَا سِرَٰجًۭا وَقَمَرًۭا مُّنِيرًۭا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 62, 'وَهُوَ ٱلَّذِى جَعَلَ ٱلَّيْلَ وَٱلنَّهَارَ خِلْفَةًۭ لِّمَنْ أَرَادَ أَن يَذَّكَّرَ أَوْ أَرَادَ شُكُورًۭا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 63, 'وَعِبَادُ ٱلرَّحْمَٰنِ ٱلَّذِينَ يَمْشُونَ عَلَى ٱلْأَرْضِ هَوْنًۭا وَإِذَا خَاطَبَهُمُ ٱلْجَٰهِلُونَ قَالُوا۟ سَلَٰمًۭا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 64, 'وَٱلَّذِينَ يَبِيتُونَ لِرَبِّهِمْ سُجَّدًۭا وَقِيَٰمًۭا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 65, 'وَٱلَّذِينَ يَقُولُونَ رَبَّنَا ٱصْرِفْ عَنَّا عَذَابَ جَهَنَّمَ ۖ إِنَّ عَذَابَهَا كَانَ غَرَامًا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 66, 'إِنَّهَا سَآءَتْ مُسْتَقَرًّۭا وَمُقَامًۭا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 67, 'وَٱلَّذِينَ إِذَآ أَنفَقُوا۟ لَمْ يُسْرِفُوا۟ وَلَمْ يَقْتُرُوا۟ وَكَانَ بَيْنَ ذَٰلِكَ قَوَامًۭا', NULL, 19, 146, 4, 365, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 68, 'وَٱلَّذِينَ لَا يَدْعُونَ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ وَلَا يَقْتُلُونَ ٱلنَّفْسَ ٱلَّتِى حَرَّمَ ٱللَّهُ إِلَّا بِٱلْحَقِّ وَلَا يَزْنُونَ ۚ وَمَن يَفْعَلْ ذَٰلِكَ يَلْقَ أَثَامًۭا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 69, 'يُضَٰعَفْ لَهُ ٱلْعَذَابُ يَوْمَ ٱلْقِيَٰمَةِ وَيَخْلُدْ فِيهِۦ مُهَانًا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 70, 'إِلَّا مَن تَابَ وَءَامَنَ وَعَمِلَ عَمَلًۭا صَٰلِحًۭا فَأُو۟لَٰٓئِكَ يُبَدِّلُ ٱللَّهُ سَيِّـَٔاتِهِمْ حَسَنَٰتٍۢ ۗ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًۭا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 71, 'وَمَن تَابَ وَعَمِلَ صَٰلِحًۭا فَإِنَّهُۥ يَتُوبُ إِلَى ٱللَّهِ مَتَابًۭا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 72, 'وَٱلَّذِينَ لَا يَشْهَدُونَ ٱلزُّورَ وَإِذَا مَرُّوا۟ بِٱللَّغْوِ مَرُّوا۟ كِرَامًۭا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 73, 'وَٱلَّذِينَ إِذَا ذُكِّرُوا۟ بِـَٔايَٰتِ رَبِّهِمْ لَمْ يَخِرُّوا۟ عَلَيْهَا صُمًّۭا وَعُمْيَانًۭا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 74, 'وَٱلَّذِينَ يَقُولُونَ رَبَّنَا هَبْ لَنَا مِنْ أَزْوَٰجِنَا وَذُرِّيَّٰتِنَا قُرَّةَ أَعْيُنٍۢ وَٱجْعَلْنَا لِلْمُتَّقِينَ إِمَامًا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 75, 'أُو۟لَٰٓئِكَ يُجْزَوْنَ ٱلْغُرْفَةَ بِمَا صَبَرُوا۟ وَيُلَقَّوْنَ فِيهَا تَحِيَّةًۭ وَسَلَٰمًا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 76, 'خَٰلِدِينَ فِيهَا ۚ حَسُنَتْ مُسْتَقَرًّۭا وَمُقَامًۭا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 25), 77, 'قُلْ مَا يَعْبَؤُا۟ بِكُمْ رَبِّى لَوْلَا دُعَآؤُكُمْ ۖ فَقَدْ كَذَّبْتُمْ فَسَوْفَ يَكُونُ لِزَامًۢا', NULL, 19, 146, 4, 366, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ طسٓمٓ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 2, 'تِلْكَ ءَايَٰتُ ٱلْكِتَٰبِ ٱلْمُبِينِ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 3, 'لَعَلَّكَ بَٰخِعٌۭ نَّفْسَكَ أَلَّا يَكُونُوا۟ مُؤْمِنِينَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 4, 'إِن نَّشَأْ نُنَزِّلْ عَلَيْهِم مِّنَ ٱلسَّمَآءِ ءَايَةًۭ فَظَلَّتْ أَعْنَٰقُهُمْ لَهَا خَٰضِعِينَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 5, 'وَمَا يَأْتِيهِم مِّن ذِكْرٍۢ مِّنَ ٱلرَّحْمَٰنِ مُحْدَثٍ إِلَّا كَانُوا۟ عَنْهُ مُعْرِضِينَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 6, 'فَقَدْ كَذَّبُوا۟ فَسَيَأْتِيهِمْ أَنۢبَٰٓؤُا۟ مَا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 7, 'أَوَلَمْ يَرَوْا۟ إِلَى ٱلْأَرْضِ كَمْ أَنۢبَتْنَا فِيهَا مِن كُلِّ زَوْجٍۢ كَرِيمٍ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 8, 'إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 9, 'وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 10, 'وَإِذْ نَادَىٰ رَبُّكَ مُوسَىٰٓ أَنِ ٱئْتِ ٱلْقَوْمَ ٱلظَّٰلِمِينَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 11, 'قَوْمَ فِرْعَوْنَ ۚ أَلَا يَتَّقُونَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 12, 'قَالَ رَبِّ إِنِّىٓ أَخَافُ أَن يُكَذِّبُونِ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 13, 'وَيَضِيقُ صَدْرِى وَلَا يَنطَلِقُ لِسَانِى فَأَرْسِلْ إِلَىٰ هَٰرُونَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 14, 'وَلَهُمْ عَلَىَّ ذَنۢبٌۭ فَأَخَافُ أَن يَقْتُلُونِ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 15, 'قَالَ كَلَّا ۖ فَٱذْهَبَا بِـَٔايَٰتِنَآ ۖ إِنَّا مَعَكُم مُّسْتَمِعُونَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 16, 'فَأْتِيَا فِرْعَوْنَ فَقُولَآ إِنَّا رَسُولُ رَبِّ ٱلْعَٰلَمِينَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 17, 'أَنْ أَرْسِلْ مَعَنَا بَنِىٓ إِسْرَٰٓءِيلَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 18, 'قَالَ أَلَمْ نُرَبِّكَ فِينَا وَلِيدًۭا وَلَبِثْتَ فِينَا مِنْ عُمُرِكَ سِنِينَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 19, 'وَفَعَلْتَ فَعْلَتَكَ ٱلَّتِى فَعَلْتَ وَأَنتَ مِنَ ٱلْكَٰفِرِينَ', NULL, 19, 147, 5, 367, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 20, 'قَالَ فَعَلْتُهَآ إِذًۭا وَأَنَا۠ مِنَ ٱلضَّآلِّينَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 21, 'فَفَرَرْتُ مِنكُمْ لَمَّا خِفْتُكُمْ فَوَهَبَ لِى رَبِّى حُكْمًۭا وَجَعَلَنِى مِنَ ٱلْمُرْسَلِينَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 22, 'وَتِلْكَ نِعْمَةٌۭ تَمُنُّهَا عَلَىَّ أَنْ عَبَّدتَّ بَنِىٓ إِسْرَٰٓءِيلَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 23, 'قَالَ فِرْعَوْنُ وَمَا رَبُّ ٱلْعَٰلَمِينَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 24, 'قَالَ رَبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُم مُّوقِنِينَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 25, 'قَالَ لِمَنْ حَوْلَهُۥٓ أَلَا تَسْتَمِعُونَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 26, 'قَالَ رَبُّكُمْ وَرَبُّ ءَابَآئِكُمُ ٱلْأَوَّلِينَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 27, 'قَالَ إِنَّ رَسُولَكُمُ ٱلَّذِىٓ أُرْسِلَ إِلَيْكُمْ لَمَجْنُونٌۭ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 28, 'قَالَ رَبُّ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُمْ تَعْقِلُونَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 29, 'قَالَ لَئِنِ ٱتَّخَذْتَ إِلَٰهًا غَيْرِى لَأَجْعَلَنَّكَ مِنَ ٱلْمَسْجُونِينَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 30, 'قَالَ أَوَلَوْ جِئْتُكَ بِشَىْءٍۢ مُّبِينٍۢ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 31, 'قَالَ فَأْتِ بِهِۦٓ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 32, 'فَأَلْقَىٰ عَصَاهُ فَإِذَا هِىَ ثُعْبَانٌۭ مُّبِينٌۭ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 33, 'وَنَزَعَ يَدَهُۥ فَإِذَا هِىَ بَيْضَآءُ لِلنَّٰظِرِينَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 34, 'قَالَ لِلْمَلَإِ حَوْلَهُۥٓ إِنَّ هَٰذَا لَسَٰحِرٌ عَلِيمٌۭ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 35, 'يُرِيدُ أَن يُخْرِجَكُم مِّنْ أَرْضِكُم بِسِحْرِهِۦ فَمَاذَا تَأْمُرُونَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 36, 'قَالُوٓا۟ أَرْجِهْ وَأَخَاهُ وَٱبْعَثْ فِى ٱلْمَدَآئِنِ حَٰشِرِينَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 37, 'يَأْتُوكَ بِكُلِّ سَحَّارٍ عَلِيمٍۢ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 38, 'فَجُمِعَ ٱلسَّحَرَةُ لِمِيقَٰتِ يَوْمٍۢ مَّعْلُومٍۢ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 39, 'وَقِيلَ لِلنَّاسِ هَلْ أَنتُم مُّجْتَمِعُونَ', NULL, 19, 147, 5, 368, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 40, 'لَعَلَّنَا نَتَّبِعُ ٱلسَّحَرَةَ إِن كَانُوا۟ هُمُ ٱلْغَٰلِبِينَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 41, 'فَلَمَّا جَآءَ ٱلسَّحَرَةُ قَالُوا۟ لِفِرْعَوْنَ أَئِنَّ لَنَا لَأَجْرًا إِن كُنَّا نَحْنُ ٱلْغَٰلِبِينَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 42, 'قَالَ نَعَمْ وَإِنَّكُمْ إِذًۭا لَّمِنَ ٱلْمُقَرَّبِينَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 43, 'قَالَ لَهُم مُّوسَىٰٓ أَلْقُوا۟ مَآ أَنتُم مُّلْقُونَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 44, 'فَأَلْقَوْا۟ حِبَالَهُمْ وَعِصِيَّهُمْ وَقَالُوا۟ بِعِزَّةِ فِرْعَوْنَ إِنَّا لَنَحْنُ ٱلْغَٰلِبُونَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 45, 'فَأَلْقَىٰ مُوسَىٰ عَصَاهُ فَإِذَا هِىَ تَلْقَفُ مَا يَأْفِكُونَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 46, 'فَأُلْقِىَ ٱلسَّحَرَةُ سَٰجِدِينَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 47, 'قَالُوٓا۟ ءَامَنَّا بِرَبِّ ٱلْعَٰلَمِينَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 48, 'رَبِّ مُوسَىٰ وَهَٰرُونَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 49, 'قَالَ ءَامَنتُمْ لَهُۥ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّهُۥ لَكَبِيرُكُمُ ٱلَّذِى عَلَّمَكُمُ ٱلسِّحْرَ فَلَسَوْفَ تَعْلَمُونَ ۚ لَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَٰفٍۢ وَلَأُصَلِّبَنَّكُمْ أَجْمَعِينَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 50, 'قَالُوا۟ لَا ضَيْرَ ۖ إِنَّآ إِلَىٰ رَبِّنَا مُنقَلِبُونَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 51, 'إِنَّا نَطْمَعُ أَن يَغْفِرَ لَنَا رَبُّنَا خَطَٰيَٰنَآ أَن كُنَّآ أَوَّلَ ٱلْمُؤْمِنِينَ', NULL, 19, 147, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 52, '۞ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَسْرِ بِعِبَادِىٓ إِنَّكُم مُّتَّبَعُونَ', NULL, 19, 148, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 53, 'فَأَرْسَلَ فِرْعَوْنُ فِى ٱلْمَدَآئِنِ حَٰشِرِينَ', NULL, 19, 148, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 54, 'إِنَّ هَٰٓؤُلَآءِ لَشِرْذِمَةٌۭ قَلِيلُونَ', NULL, 19, 148, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 55, 'وَإِنَّهُمْ لَنَا لَغَآئِظُونَ', NULL, 19, 148, 5, 369, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 56, 'وَإِنَّا لَجَمِيعٌ حَٰذِرُونَ', NULL, 19, 148, 5, 369, false, NOW(), NOW()),
