((SELECT id FROM mst_surah WHERE surah_number = 26), 225, 'أَلَمْ تَرَ أَنَّهُمْ فِى كُلِّ وَادٍۢ يَهِيمُونَ', NULL, 19, 150, 5, 376, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 226, 'وَأَنَّهُمْ يَقُولُونَ مَا لَا يَفْعَلُونَ', NULL, 19, 150, 5, 376, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 26), 227, 'إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَذَكَرُوا۟ ٱللَّهَ كَثِيرًۭا وَٱنتَصَرُوا۟ مِنۢ بَعْدِ مَا ظُلِمُوا۟ ۗ وَسَيَعْلَمُ ٱلَّذِينَ ظَلَمُوٓا۟ أَىَّ مُنقَلَبٍۢ يَنقَلِبُونَ', NULL, 19, 150, 5, 376, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ طسٓ ۚ تِلْكَ ءَايَٰتُ ٱلْقُرْءَانِ وَكِتَابٍۢ مُّبِينٍ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 2, 'هُدًۭى وَبُشْرَىٰ لِلْمُؤْمِنِينَ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 3, 'ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَهُم بِٱلْءَاخِرَةِ هُمْ يُوقِنُونَ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 4, 'إِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ زَيَّنَّا لَهُمْ أَعْمَٰلَهُمْ فَهُمْ يَعْمَهُونَ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 5, 'أُو۟لَٰٓئِكَ ٱلَّذِينَ لَهُمْ سُوٓءُ ٱلْعَذَابِ وَهُمْ فِى ٱلْءَاخِرَةِ هُمُ ٱلْأَخْسَرُونَ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 6, 'وَإِنَّكَ لَتُلَقَّى ٱلْقُرْءَانَ مِن لَّدُنْ حَكِيمٍ عَلِيمٍ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 7, 'إِذْ قَالَ مُوسَىٰ لِأَهْلِهِۦٓ إِنِّىٓ ءَانَسْتُ نَارًۭا سَـَٔاتِيكُم مِّنْهَا بِخَبَرٍ أَوْ ءَاتِيكُم بِشِهَابٍۢ قَبَسٍۢ لَّعَلَّكُمْ تَصْطَلُونَ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 8, 'فَلَمَّا جَآءَهَا نُودِىَ أَنۢ بُورِكَ مَن فِى ٱلنَّارِ وَمَنْ حَوْلَهَا وَسُبْحَٰنَ ٱللَّهِ رَبِّ ٱلْعَٰلَمِينَ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 9, 'يَٰمُوسَىٰٓ إِنَّهُۥٓ أَنَا ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 10, 'وَأَلْقِ عَصَاكَ ۚ فَلَمَّا رَءَاهَا تَهْتَزُّ كَأَنَّهَا جَآنٌّۭ وَلَّىٰ مُدْبِرًۭا وَلَمْ يُعَقِّبْ ۚ يَٰمُوسَىٰ لَا تَخَفْ إِنِّى لَا يَخَافُ لَدَىَّ ٱلْمُرْسَلُونَ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 11, 'إِلَّا مَن ظَلَمَ ثُمَّ بَدَّلَ حُسْنًۢا بَعْدَ سُوٓءٍۢ فَإِنِّى غَفُورٌۭ رَّحِيمٌۭ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 12, 'وَأَدْخِلْ يَدَكَ فِى جَيْبِكَ تَخْرُجْ بَيْضَآءَ مِنْ غَيْرِ سُوٓءٍۢ ۖ فِى تِسْعِ ءَايَٰتٍ إِلَىٰ فِرْعَوْنَ وَقَوْمِهِۦٓ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًۭا فَٰسِقِينَ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 13, 'فَلَمَّا جَآءَتْهُمْ ءَايَٰتُنَا مُبْصِرَةًۭ قَالُوا۟ هَٰذَا سِحْرٌۭ مُّبِينٌۭ', NULL, 19, 151, 5, 377, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 14, 'وَجَحَدُوا۟ بِهَا وَٱسْتَيْقَنَتْهَآ أَنفُسُهُمْ ظُلْمًۭا وَعُلُوًّۭا ۚ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُفْسِدِينَ', NULL, 19, 151, 5, 378, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 15, 'وَلَقَدْ ءَاتَيْنَا دَاوُۥدَ وَسُلَيْمَٰنَ عِلْمًۭا ۖ وَقَالَا ٱلْحَمْدُ لِلَّهِ ٱلَّذِى فَضَّلَنَا عَلَىٰ كَثِيرٍۢ مِّنْ عِبَادِهِ ٱلْمُؤْمِنِينَ', NULL, 19, 151, 5, 378, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 16, 'وَوَرِثَ سُلَيْمَٰنُ دَاوُۥدَ ۖ وَقَالَ يَٰٓأَيُّهَا ٱلنَّاسُ عُلِّمْنَا مَنطِقَ ٱلطَّيْرِ وَأُوتِينَا مِن كُلِّ شَىْءٍ ۖ إِنَّ هَٰذَا لَهُوَ ٱلْفَضْلُ ٱلْمُبِينُ', NULL, 19, 151, 5, 378, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 17, 'وَحُشِرَ لِسُلَيْمَٰنَ جُنُودُهُۥ مِنَ ٱلْجِنِّ وَٱلْإِنسِ وَٱلطَّيْرِ فَهُمْ يُوزَعُونَ', NULL, 19, 151, 5, 378, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 18, 'حَتَّىٰٓ إِذَآ أَتَوْا۟ عَلَىٰ وَادِ ٱلنَّمْلِ قَالَتْ نَمْلَةٌۭ يَٰٓأَيُّهَا ٱلنَّمْلُ ٱدْخُلُوا۟ مَسَٰكِنَكُمْ لَا يَحْطِمَنَّكُمْ سُلَيْمَٰنُ وَجُنُودُهُۥ وَهُمْ لَا يَشْعُرُونَ', NULL, 19, 151, 5, 378, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 19, 'فَتَبَسَّمَ ضَاحِكًۭا مِّن قَوْلِهَا وَقَالَ رَبِّ أَوْزِعْنِىٓ أَنْ أَشْكُرَ نِعْمَتَكَ ٱلَّتِىٓ أَنْعَمْتَ عَلَىَّ وَعَلَىٰ وَٰلِدَىَّ وَأَنْ أَعْمَلَ صَٰلِحًۭا تَرْضَىٰهُ وَأَدْخِلْنِى بِرَحْمَتِكَ فِى عِبَادِكَ ٱلصَّٰلِحِينَ', NULL, 19, 151, 5, 378, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 20, 'وَتَفَقَّدَ ٱلطَّيْرَ فَقَالَ مَا لِىَ لَآ أَرَى ٱلْهُدْهُدَ أَمْ كَانَ مِنَ ٱلْغَآئِبِينَ', NULL, 19, 151, 5, 378, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 21, 'لَأُعَذِّبَنَّهُۥ عَذَابًۭا شَدِيدًا أَوْ لَأَا۟ذْبَحَنَّهُۥٓ أَوْ لَيَأْتِيَنِّى بِسُلْطَٰنٍۢ مُّبِينٍۢ', NULL, 19, 151, 5, 378, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 22, 'فَمَكَثَ غَيْرَ بَعِيدٍۢ فَقَالَ أَحَطتُ بِمَا لَمْ تُحِطْ بِهِۦ وَجِئْتُكَ مِن سَبَإٍۭ بِنَبَإٍۢ يَقِينٍ', NULL, 19, 151, 5, 378, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 23, 'إِنِّى وَجَدتُّ ٱمْرَأَةًۭ تَمْلِكُهُمْ وَأُوتِيَتْ مِن كُلِّ شَىْءٍۢ وَلَهَا عَرْشٌ عَظِيمٌۭ', NULL, 19, 151, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 24, 'وَجَدتُّهَا وَقَوْمَهَا يَسْجُدُونَ لِلشَّمْسِ مِن دُونِ ٱللَّهِ وَزَيَّنَ لَهُمُ ٱلشَّيْطَٰنُ أَعْمَٰلَهُمْ فَصَدَّهُمْ عَنِ ٱلسَّبِيلِ فَهُمْ لَا يَهْتَدُونَ', NULL, 19, 151, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 25, 'أَلَّا يَسْجُدُوا۟ لِلَّهِ ٱلَّذِى يُخْرِجُ ٱلْخَبْءَ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَيَعْلَمُ مَا تُخْفُونَ وَمَا تُعْلِنُونَ', NULL, 19, 151, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 26, 'ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ رَبُّ ٱلْعَرْشِ ٱلْعَظِيمِ ۩', NULL, 19, 151, 5, 379, true, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 27, '۞ قَالَ سَنَنظُرُ أَصَدَقْتَ أَمْ كُنتَ مِنَ ٱلْكَٰذِبِينَ', NULL, 19, 152, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 28, 'ٱذْهَب بِّكِتَٰبِى هَٰذَا فَأَلْقِهْ إِلَيْهِمْ ثُمَّ تَوَلَّ عَنْهُمْ فَٱنظُرْ مَاذَا يَرْجِعُونَ', NULL, 19, 152, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 29, 'قَالَتْ يَٰٓأَيُّهَا ٱلْمَلَؤُا۟ إِنِّىٓ أُلْقِىَ إِلَىَّ كِتَٰبٌۭ كَرِيمٌ', NULL, 19, 152, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 30, 'إِنَّهُۥ مِن سُلَيْمَٰنَ وَإِنَّهُۥ بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ', NULL, 19, 152, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 31, 'أَلَّا تَعْلُوا۟ عَلَىَّ وَأْتُونِى مُسْلِمِينَ', NULL, 19, 152, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 32, 'قَالَتْ يَٰٓأَيُّهَا ٱلْمَلَؤُا۟ أَفْتُونِى فِىٓ أَمْرِى مَا كُنتُ قَاطِعَةً أَمْرًا حَتَّىٰ تَشْهَدُونِ', NULL, 19, 152, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 33, 'قَالُوا۟ نَحْنُ أُو۟لُوا۟ قُوَّةٍۢ وَأُو۟لُوا۟ بَأْسٍۢ شَدِيدٍۢ وَٱلْأَمْرُ إِلَيْكِ فَٱنظُرِى مَاذَا تَأْمُرِينَ', NULL, 19, 152, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 34, 'قَالَتْ إِنَّ ٱلْمُلُوكَ إِذَا دَخَلُوا۟ قَرْيَةً أَفْسَدُوهَا وَجَعَلُوٓا۟ أَعِزَّةَ أَهْلِهَآ أَذِلَّةًۭ ۖ وَكَذَٰلِكَ يَفْعَلُونَ', NULL, 19, 152, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 35, 'وَإِنِّى مُرْسِلَةٌ إِلَيْهِم بِهَدِيَّةٍۢ فَنَاظِرَةٌۢ بِمَ يَرْجِعُ ٱلْمُرْسَلُونَ', NULL, 19, 152, 5, 379, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 36, 'فَلَمَّا جَآءَ سُلَيْمَٰنَ قَالَ أَتُمِدُّونَنِ بِمَالٍۢ فَمَآ ءَاتَىٰنِۦَ ٱللَّهُ خَيْرٌۭ مِّمَّآ ءَاتَىٰكُم بَلْ أَنتُم بِهَدِيَّتِكُمْ تَفْرَحُونَ', NULL, 19, 152, 5, 380, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 37, 'ٱرْجِعْ إِلَيْهِمْ فَلَنَأْتِيَنَّهُم بِجُنُودٍۢ لَّا قِبَلَ لَهُم بِهَا وَلَنُخْرِجَنَّهُم مِّنْهَآ أَذِلَّةًۭ وَهُمْ صَٰغِرُونَ', NULL, 19, 152, 5, 380, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 38, 'قَالَ يَٰٓأَيُّهَا ٱلْمَلَؤُا۟ أَيُّكُمْ يَأْتِينِى بِعَرْشِهَا قَبْلَ أَن يَأْتُونِى مُسْلِمِينَ', NULL, 19, 152, 5, 380, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 39, 'قَالَ عِفْرِيتٌۭ مِّنَ ٱلْجِنِّ أَنَا۠ ءَاتِيكَ بِهِۦ قَبْلَ أَن تَقُومَ مِن مَّقَامِكَ ۖ وَإِنِّى عَلَيْهِ لَقَوِىٌّ أَمِينٌۭ', NULL, 19, 152, 5, 380, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 40, 'قَالَ ٱلَّذِى عِندَهُۥ عِلْمٌۭ مِّنَ ٱلْكِتَٰبِ أَنَا۠ ءَاتِيكَ بِهِۦ قَبْلَ أَن يَرْتَدَّ إِلَيْكَ طَرْفُكَ ۚ فَلَمَّا رَءَاهُ مُسْتَقِرًّا عِندَهُۥ قَالَ هَٰذَا مِن فَضْلِ رَبِّى لِيَبْلُوَنِىٓ ءَأَشْكُرُ أَمْ أَكْفُرُ ۖ وَمَن شَكَرَ فَإِنَّمَا يَشْكُرُ لِنَفْسِهِۦ ۖ وَمَن كَفَرَ فَإِنَّ رَبِّى غَنِىٌّۭ كَرِيمٌۭ', NULL, 19, 152, 5, 380, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 41, 'قَالَ نَكِّرُوا۟ لَهَا عَرْشَهَا نَنظُرْ أَتَهْتَدِىٓ أَمْ تَكُونُ مِنَ ٱلَّذِينَ لَا يَهْتَدُونَ', NULL, 19, 152, 5, 380, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 42, 'فَلَمَّا جَآءَتْ قِيلَ أَهَٰكَذَا عَرْشُكِ ۖ قَالَتْ كَأَنَّهُۥ هُوَ ۚ وَأُوتِينَا ٱلْعِلْمَ مِن قَبْلِهَا وَكُنَّا مُسْلِمِينَ', NULL, 19, 152, 5, 380, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 43, 'وَصَدَّهَا مَا كَانَت تَّعْبُدُ مِن دُونِ ٱللَّهِ ۖ إِنَّهَا كَانَتْ مِن قَوْمٍۢ كَٰفِرِينَ', NULL, 19, 152, 5, 380, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 44, 'قِيلَ لَهَا ٱدْخُلِى ٱلصَّرْحَ ۖ فَلَمَّا رَأَتْهُ حَسِبَتْهُ لُجَّةًۭ وَكَشَفَتْ عَن سَاقَيْهَا ۚ قَالَ إِنَّهُۥ صَرْحٌۭ مُّمَرَّدٌۭ مِّن قَوَارِيرَ ۗ قَالَتْ رَبِّ إِنِّى ظَلَمْتُ نَفْسِى وَأَسْلَمْتُ مَعَ سُلَيْمَٰنَ لِلَّهِ رَبِّ ٱلْعَٰلَمِينَ', NULL, 19, 152, 5, 380, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 45, 'وَلَقَدْ أَرْسَلْنَآ إِلَىٰ ثَمُودَ أَخَاهُمْ صَٰلِحًا أَنِ ٱعْبُدُوا۟ ٱللَّهَ فَإِذَا هُمْ فَرِيقَانِ يَخْتَصِمُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 46, 'قَالَ يَٰقَوْمِ لِمَ تَسْتَعْجِلُونَ بِٱلسَّيِّئَةِ قَبْلَ ٱلْحَسَنَةِ ۖ لَوْلَا تَسْتَغْفِرُونَ ٱللَّهَ لَعَلَّكُمْ تُرْحَمُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 47, 'قَالُوا۟ ٱطَّيَّرْنَا بِكَ وَبِمَن مَّعَكَ ۚ قَالَ طَٰٓئِرُكُمْ عِندَ ٱللَّهِ ۖ بَلْ أَنتُمْ قَوْمٌۭ تُفْتَنُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 48, 'وَكَانَ فِى ٱلْمَدِينَةِ تِسْعَةُ رَهْطٍۢ يُفْسِدُونَ فِى ٱلْأَرْضِ وَلَا يُصْلِحُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 49, 'قَالُوا۟ تَقَاسَمُوا۟ بِٱللَّهِ لَنُبَيِّتَنَّهُۥ وَأَهْلَهُۥ ثُمَّ لَنَقُولَنَّ لِوَلِيِّهِۦ مَا شَهِدْنَا مَهْلِكَ أَهْلِهِۦ وَإِنَّا لَصَٰدِقُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 50, 'وَمَكَرُوا۟ مَكْرًۭا وَمَكَرْنَا مَكْرًۭا وَهُمْ لَا يَشْعُرُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 51, 'فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ مَكْرِهِمْ أَنَّا دَمَّرْنَٰهُمْ وَقَوْمَهُمْ أَجْمَعِينَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 52, 'فَتِلْكَ بُيُوتُهُمْ خَاوِيَةًۢ بِمَا ظَلَمُوٓا۟ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَعْلَمُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 53, 'وَأَنجَيْنَا ٱلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 54, 'وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ أَتَأْتُونَ ٱلْفَٰحِشَةَ وَأَنتُمْ تُبْصِرُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 55, 'أَئِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ شَهْوَةًۭ مِّن دُونِ ٱلنِّسَآءِ ۚ بَلْ أَنتُمْ قَوْمٌۭ تَجْهَلُونَ', NULL, 19, 152, 5, 381, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 56, '۞ فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوٓا۟ أَخْرِجُوٓا۟ ءَالَ لُوطٍۢ مِّن قَرْيَتِكُمْ ۖ إِنَّهُمْ أُنَاسٌۭ يَتَطَهَّرُونَ', NULL, 20, 153, 5, 382, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 57, 'فَأَنجَيْنَٰهُ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ قَدَّرْنَٰهَا مِنَ ٱلْغَٰبِرِينَ', NULL, 20, 153, 5, 382, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 58, 'وَأَمْطَرْنَا عَلَيْهِم مَّطَرًۭا ۖ فَسَآءَ مَطَرُ ٱلْمُنذَرِينَ', NULL, 20, 153, 5, 382, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 59, 'قُلِ ٱلْحَمْدُ لِلَّهِ وَسَلَٰمٌ عَلَىٰ عِبَادِهِ ٱلَّذِينَ ٱصْطَفَىٰٓ ۗ ءَآللَّهُ خَيْرٌ أَمَّا يُشْرِكُونَ', NULL, 20, 153, 5, 382, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 60, 'أَمَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَأَنزَلَ لَكُم مِّنَ ٱلسَّمَآءِ مَآءًۭ فَأَنۢبَتْنَا بِهِۦ حَدَآئِقَ ذَاتَ بَهْجَةٍۢ مَّا كَانَ لَكُمْ أَن تُنۢبِتُوا۟ شَجَرَهَآ ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ بَلْ هُمْ قَوْمٌۭ يَعْدِلُونَ', NULL, 20, 153, 5, 382, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 61, 'أَمَّن جَعَلَ ٱلْأَرْضَ قَرَارًۭا وَجَعَلَ خِلَٰلَهَآ أَنْهَٰرًۭا وَجَعَلَ لَهَا رَوَٰسِىَ وَجَعَلَ بَيْنَ ٱلْبَحْرَيْنِ حَاجِزًا ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ', NULL, 20, 153, 5, 382, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 62, 'أَمَّن يُجِيبُ ٱلْمُضْطَرَّ إِذَا دَعَاهُ وَيَكْشِفُ ٱلسُّوٓءَ وَيَجْعَلُكُمْ خُلَفَآءَ ٱلْأَرْضِ ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ قَلِيلًۭا مَّا تَذَكَّرُونَ', NULL, 20, 153, 5, 382, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 63, 'أَمَّن يَهْدِيكُمْ فِى ظُلُمَٰتِ ٱلْبَرِّ وَٱلْبَحْرِ وَمَن يُرْسِلُ ٱلرِّيَٰحَ بُشْرًۢا بَيْنَ يَدَىْ رَحْمَتِهِۦٓ ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ تَعَٰلَى ٱللَّهُ عَمَّا يُشْرِكُونَ', NULL, 20, 153, 5, 382, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 64, 'أَمَّن يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ وَمَن يَرْزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ ۗ أَءِلَٰهٌۭ مَّعَ ٱللَّهِ ۚ قُلْ هَاتُوا۟ بُرْهَٰنَكُمْ إِن كُنتُمْ صَٰدِقِينَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 65, 'قُل لَّا يَعْلَمُ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ٱلْغَيْبَ إِلَّا ٱللَّهُ ۚ وَمَا يَشْعُرُونَ أَيَّانَ يُبْعَثُونَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 66, 'بَلِ ٱدَّٰرَكَ عِلْمُهُمْ فِى ٱلْءَاخِرَةِ ۚ بَلْ هُمْ فِى شَكٍّۢ مِّنْهَا ۖ بَلْ هُم مِّنْهَا عَمُونَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 67, 'وَقَالَ ٱلَّذِينَ كَفَرُوٓا۟ أَءِذَا كُنَّا تُرَٰبًۭا وَءَابَآؤُنَآ أَئِنَّا لَمُخْرَجُونَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 68, 'لَقَدْ وُعِدْنَا هَٰذَا نَحْنُ وَءَابَآؤُنَا مِن قَبْلُ إِنْ هَٰذَآ إِلَّآ أَسَٰطِيرُ ٱلْأَوَّلِينَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 69, 'قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُجْرِمِينَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 70, 'وَلَا تَحْزَنْ عَلَيْهِمْ وَلَا تَكُن فِى ضَيْقٍۢ مِّمَّا يَمْكُرُونَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 71, 'وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 72, 'قُلْ عَسَىٰٓ أَن يَكُونَ رَدِفَ لَكُم بَعْضُ ٱلَّذِى تَسْتَعْجِلُونَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 73, 'وَإِنَّ رَبَّكَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَشْكُرُونَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 74, 'وَإِنَّ رَبَّكَ لَيَعْلَمُ مَا تُكِنُّ صُدُورُهُمْ وَمَا يُعْلِنُونَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 75, 'وَمَا مِنْ غَآئِبَةٍۢ فِى ٱلسَّمَآءِ وَٱلْأَرْضِ إِلَّا فِى كِتَٰبٍۢ مُّبِينٍ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 76, 'إِنَّ هَٰذَا ٱلْقُرْءَانَ يَقُصُّ عَلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ أَكْثَرَ ٱلَّذِى هُمْ فِيهِ يَخْتَلِفُونَ', NULL, 20, 153, 5, 383, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 77, 'وَإِنَّهُۥ لَهُدًۭى وَرَحْمَةٌۭ لِّلْمُؤْمِنِينَ', NULL, 20, 153, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 78, 'إِنَّ رَبَّكَ يَقْضِى بَيْنَهُم بِحُكْمِهِۦ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْعَلِيمُ', NULL, 20, 153, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 79, 'فَتَوَكَّلْ عَلَى ٱللَّهِ ۖ إِنَّكَ عَلَى ٱلْحَقِّ ٱلْمُبِينِ', NULL, 20, 153, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 80, 'إِنَّكَ لَا تُسْمِعُ ٱلْمَوْتَىٰ وَلَا تُسْمِعُ ٱلصُّمَّ ٱلدُّعَآءَ إِذَا وَلَّوْا۟ مُدْبِرِينَ', NULL, 20, 153, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 81, 'وَمَآ أَنتَ بِهَٰدِى ٱلْعُمْىِ عَن ضَلَٰلَتِهِمْ ۖ إِن تُسْمِعُ إِلَّا مَن يُؤْمِنُ بِـَٔايَٰتِنَا فَهُم مُّسْلِمُونَ', NULL, 20, 153, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 82, '۞ وَإِذَا وَقَعَ ٱلْقَوْلُ عَلَيْهِمْ أَخْرَجْنَا لَهُمْ دَآبَّةًۭ مِّنَ ٱلْأَرْضِ تُكَلِّمُهُمْ أَنَّ ٱلنَّاسَ كَانُوا۟ بِـَٔايَٰتِنَا لَا يُوقِنُونَ', NULL, 20, 154, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 83, 'وَيَوْمَ نَحْشُرُ مِن كُلِّ أُمَّةٍۢ فَوْجًۭا مِّمَّن يُكَذِّبُ بِـَٔايَٰتِنَا فَهُمْ يُوزَعُونَ', NULL, 20, 154, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 84, 'حَتَّىٰٓ إِذَا جَآءُو قَالَ أَكَذَّبْتُم بِـَٔايَٰتِى وَلَمْ تُحِيطُوا۟ بِهَا عِلْمًا أَمَّاذَا كُنتُمْ تَعْمَلُونَ', NULL, 20, 154, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 85, 'وَوَقَعَ ٱلْقَوْلُ عَلَيْهِم بِمَا ظَلَمُوا۟ فَهُمْ لَا يَنطِقُونَ', NULL, 20, 154, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 86, 'أَلَمْ يَرَوْا۟ أَنَّا جَعَلْنَا ٱلَّيْلَ لِيَسْكُنُوا۟ فِيهِ وَٱلنَّهَارَ مُبْصِرًا ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ', NULL, 20, 154, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 87, 'وَيَوْمَ يُنفَخُ فِى ٱلصُّورِ فَفَزِعَ مَن فِى ٱلسَّمَٰوَٰتِ وَمَن فِى ٱلْأَرْضِ إِلَّا مَن شَآءَ ٱللَّهُ ۚ وَكُلٌّ أَتَوْهُ دَٰخِرِينَ', NULL, 20, 154, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 88, 'وَتَرَى ٱلْجِبَالَ تَحْسَبُهَا جَامِدَةًۭ وَهِىَ تَمُرُّ مَرَّ ٱلسَّحَابِ ۚ صُنْعَ ٱللَّهِ ٱلَّذِىٓ أَتْقَنَ كُلَّ شَىْءٍ ۚ إِنَّهُۥ خَبِيرٌۢ بِمَا تَفْعَلُونَ', NULL, 20, 154, 5, 384, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 89, 'مَن جَآءَ بِٱلْحَسَنَةِ فَلَهُۥ خَيْرٌۭ مِّنْهَا وَهُم مِّن فَزَعٍۢ يَوْمَئِذٍ ءَامِنُونَ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 90, 'وَمَن جَآءَ بِٱلسَّيِّئَةِ فَكُبَّتْ وُجُوهُهُمْ فِى ٱلنَّارِ هَلْ تُجْزَوْنَ إِلَّا مَا كُنتُمْ تَعْمَلُونَ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 91, 'إِنَّمَآ أُمِرْتُ أَنْ أَعْبُدَ رَبَّ هَٰذِهِ ٱلْبَلْدَةِ ٱلَّذِى حَرَّمَهَا وَلَهُۥ كُلُّ شَىْءٍۢ ۖ وَأُمِرْتُ أَنْ أَكُونَ مِنَ ٱلْمُسْلِمِينَ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 92, 'وَأَنْ أَتْلُوَا۟ ٱلْقُرْءَانَ ۖ فَمَنِ ٱهْتَدَىٰ فَإِنَّمَا يَهْتَدِى لِنَفْسِهِۦ ۖ وَمَن ضَلَّ فَقُلْ إِنَّمَآ أَنَا۠ مِنَ ٱلْمُنذِرِينَ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 27), 93, 'وَقُلِ ٱلْحَمْدُ لِلَّهِ سَيُرِيكُمْ ءَايَٰتِهِۦ فَتَعْرِفُونَهَا ۚ وَمَا رَبُّكَ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ طسٓمٓ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 2, 'تِلْكَ ءَايَٰتُ ٱلْكِتَٰبِ ٱلْمُبِينِ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 3, 'نَتْلُوا۟ عَلَيْكَ مِن نَّبَإِ مُوسَىٰ وَفِرْعَوْنَ بِٱلْحَقِّ لِقَوْمٍۢ يُؤْمِنُونَ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 4, 'إِنَّ فِرْعَوْنَ عَلَا فِى ٱلْأَرْضِ وَجَعَلَ أَهْلَهَا شِيَعًۭا يَسْتَضْعِفُ طَآئِفَةًۭ مِّنْهُمْ يُذَبِّحُ أَبْنَآءَهُمْ وَيَسْتَحْىِۦ نِسَآءَهُمْ ۚ إِنَّهُۥ كَانَ مِنَ ٱلْمُفْسِدِينَ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 5, 'وَنُرِيدُ أَن نَّمُنَّ عَلَى ٱلَّذِينَ ٱسْتُضْعِفُوا۟ فِى ٱلْأَرْضِ وَنَجْعَلَهُمْ أَئِمَّةًۭ وَنَجْعَلَهُمُ ٱلْوَٰرِثِينَ', NULL, 20, 154, 5, 385, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 6, 'وَنُمَكِّنَ لَهُمْ فِى ٱلْأَرْضِ وَنُرِىَ فِرْعَوْنَ وَهَٰمَٰنَ وَجُنُودَهُمَا مِنْهُم مَّا كَانُوا۟ يَحْذَرُونَ', NULL, 20, 154, 5, 386, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 7, 'وَأَوْحَيْنَآ إِلَىٰٓ أُمِّ مُوسَىٰٓ أَنْ أَرْضِعِيهِ ۖ فَإِذَا خِفْتِ عَلَيْهِ فَأَلْقِيهِ فِى ٱلْيَمِّ وَلَا تَخَافِى وَلَا تَحْزَنِىٓ ۖ إِنَّا رَآدُّوهُ إِلَيْكِ وَجَاعِلُوهُ مِنَ ٱلْمُرْسَلِينَ', NULL, 20, 154, 5, 386, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 8, 'فَٱلْتَقَطَهُۥٓ ءَالُ فِرْعَوْنَ لِيَكُونَ لَهُمْ عَدُوًّۭا وَحَزَنًا ۗ إِنَّ فِرْعَوْنَ وَهَٰمَٰنَ وَجُنُودَهُمَا كَانُوا۟ خَٰطِـِٔينَ', NULL, 20, 154, 5, 386, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 9, 'وَقَالَتِ ٱمْرَأَتُ فِرْعَوْنَ قُرَّتُ عَيْنٍۢ لِّى وَلَكَ ۖ لَا تَقْتُلُوهُ عَسَىٰٓ أَن يَنفَعَنَآ أَوْ نَتَّخِذَهُۥ وَلَدًۭا وَهُمْ لَا يَشْعُرُونَ', NULL, 20, 154, 5, 386, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 10, 'وَأَصْبَحَ فُؤَادُ أُمِّ مُوسَىٰ فَٰرِغًا ۖ إِن كَادَتْ لَتُبْدِى بِهِۦ لَوْلَآ أَن رَّبَطْنَا عَلَىٰ قَلْبِهَا لِتَكُونَ مِنَ ٱلْمُؤْمِنِينَ', NULL, 20, 154, 5, 386, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 11, 'وَقَالَتْ لِأُخْتِهِۦ قُصِّيهِ ۖ فَبَصُرَتْ بِهِۦ عَن جُنُبٍۢ وَهُمْ لَا يَشْعُرُونَ', NULL, 20, 154, 5, 386, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 12, '۞ وَحَرَّمْنَا عَلَيْهِ ٱلْمَرَاضِعَ مِن قَبْلُ فَقَالَتْ هَلْ أَدُلُّكُمْ عَلَىٰٓ أَهْلِ بَيْتٍۢ يَكْفُلُونَهُۥ لَكُمْ وَهُمْ لَهُۥ نَٰصِحُونَ', NULL, 20, 155, 5, 386, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 13, 'فَرَدَدْنَٰهُ إِلَىٰٓ أُمِّهِۦ كَىْ تَقَرَّ عَيْنُهَا وَلَا تَحْزَنَ وَلِتَعْلَمَ أَنَّ وَعْدَ ٱللَّهِ حَقٌّۭ وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ', NULL, 20, 155, 5, 386, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 14, 'وَلَمَّا بَلَغَ أَشُدَّهُۥ وَٱسْتَوَىٰٓ ءَاتَيْنَٰهُ حُكْمًۭا وَعِلْمًۭا ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ', NULL, 20, 155, 5, 387, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 15, 'وَدَخَلَ ٱلْمَدِينَةَ عَلَىٰ حِينِ غَفْلَةٍۢ مِّنْ أَهْلِهَا فَوَجَدَ فِيهَا رَجُلَيْنِ يَقْتَتِلَانِ هَٰذَا مِن شِيعَتِهِۦ وَهَٰذَا مِنْ عَدُوِّهِۦ ۖ فَٱسْتَغَٰثَهُ ٱلَّذِى مِن شِيعَتِهِۦ عَلَى ٱلَّذِى مِنْ عَدُوِّهِۦ فَوَكَزَهُۥ مُوسَىٰ فَقَضَىٰ عَلَيْهِ ۖ قَالَ هَٰذَا مِنْ عَمَلِ ٱلشَّيْطَٰنِ ۖ إِنَّهُۥ عَدُوٌّۭ مُّضِلٌّۭ مُّبِينٌۭ', NULL, 20, 155, 5, 387, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 16, 'قَالَ رَبِّ إِنِّى ظَلَمْتُ نَفْسِى فَٱغْفِرْ لِى فَغَفَرَ لَهُۥٓ ۚ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ', NULL, 20, 155, 5, 387, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 17, 'قَالَ رَبِّ بِمَآ أَنْعَمْتَ عَلَىَّ فَلَنْ أَكُونَ ظَهِيرًۭا لِّلْمُجْرِمِينَ', NULL, 20, 155, 5, 387, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 18, 'فَأَصْبَحَ فِى ٱلْمَدِينَةِ خَآئِفًۭا يَتَرَقَّبُ فَإِذَا ٱلَّذِى ٱسْتَنصَرَهُۥ بِٱلْأَمْسِ يَسْتَصْرِخُهُۥ ۚ قَالَ لَهُۥ مُوسَىٰٓ إِنَّكَ لَغَوِىٌّۭ مُّبِينٌۭ', NULL, 20, 155, 5, 387, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 19, 'فَلَمَّآ أَنْ أَرَادَ أَن يَبْطِشَ بِٱلَّذِى هُوَ عَدُوٌّۭ لَّهُمَا قَالَ يَٰمُوسَىٰٓ أَتُرِيدُ أَن تَقْتُلَنِى كَمَا قَتَلْتَ نَفْسًۢا بِٱلْأَمْسِ ۖ إِن تُرِيدُ إِلَّآ أَن تَكُونَ جَبَّارًۭا فِى ٱلْأَرْضِ وَمَا تُرِيدُ أَن تَكُونَ مِنَ ٱلْمُصْلِحِينَ', NULL, 20, 155, 5, 387, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 20, 'وَجَآءَ رَجُلٌۭ مِّنْ أَقْصَا ٱلْمَدِينَةِ يَسْعَىٰ قَالَ يَٰمُوسَىٰٓ إِنَّ ٱلْمَلَأَ يَأْتَمِرُونَ بِكَ لِيَقْتُلُوكَ فَٱخْرُجْ إِنِّى لَكَ مِنَ ٱلنَّٰصِحِينَ', NULL, 20, 155, 5, 387, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 21, 'فَخَرَجَ مِنْهَا خَآئِفًۭا يَتَرَقَّبُ ۖ قَالَ رَبِّ نَجِّنِى مِنَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ', NULL, 20, 155, 5, 387, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 22, 'وَلَمَّا تَوَجَّهَ تِلْقَآءَ مَدْيَنَ قَالَ عَسَىٰ رَبِّىٓ أَن يَهْدِيَنِى سَوَآءَ ٱلسَّبِيلِ', NULL, 20, 155, 5, 388, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 23, 'وَلَمَّا وَرَدَ مَآءَ مَدْيَنَ وَجَدَ عَلَيْهِ أُمَّةًۭ مِّنَ ٱلنَّاسِ يَسْقُونَ وَوَجَدَ مِن دُونِهِمُ ٱمْرَأَتَيْنِ تَذُودَانِ ۖ قَالَ مَا خَطْبُكُمَا ۖ قَالَتَا لَا نَسْقِى حَتَّىٰ يُصْدِرَ ٱلرِّعَآءُ ۖ وَأَبُونَا شَيْخٌۭ كَبِيرٌۭ', NULL, 20, 155, 5, 388, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 24, 'فَسَقَىٰ لَهُمَا ثُمَّ تَوَلَّىٰٓ إِلَى ٱلظِّلِّ فَقَالَ رَبِّ إِنِّى لِمَآ أَنزَلْتَ إِلَىَّ مِنْ خَيْرٍۢ فَقِيرٌۭ', NULL, 20, 155, 5, 388, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 25, 'فَجَآءَتْهُ إِحْدَىٰهُمَا تَمْشِى عَلَى ٱسْتِحْيَآءٍۢ قَالَتْ إِنَّ أَبِى يَدْعُوكَ لِيَجْزِيَكَ أَجْرَ مَا سَقَيْتَ لَنَا ۚ فَلَمَّا جَآءَهُۥ وَقَصَّ عَلَيْهِ ٱلْقَصَصَ قَالَ لَا تَخَفْ ۖ نَجَوْتَ مِنَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ', NULL, 20, 155, 5, 388, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 26, 'قَالَتْ إِحْدَىٰهُمَا يَٰٓأَبَتِ ٱسْتَـْٔجِرْهُ ۖ إِنَّ خَيْرَ مَنِ ٱسْتَـْٔجَرْتَ ٱلْقَوِىُّ ٱلْأَمِينُ', NULL, 20, 155, 5, 388, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 27, 'قَالَ إِنِّىٓ أُرِيدُ أَنْ أُنكِحَكَ إِحْدَى ٱبْنَتَىَّ هَٰتَيْنِ عَلَىٰٓ أَن تَأْجُرَنِى ثَمَٰنِىَ حِجَجٍۢ ۖ فَإِنْ أَتْمَمْتَ عَشْرًۭا فَمِنْ عِندِكَ ۖ وَمَآ أُرِيدُ أَنْ أَشُقَّ عَلَيْكَ ۚ سَتَجِدُنِىٓ إِن شَآءَ ٱللَّهُ مِنَ ٱلصَّٰلِحِينَ', NULL, 20, 155, 5, 388, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 28, 'قَالَ ذَٰلِكَ بَيْنِى وَبَيْنَكَ ۖ أَيَّمَا ٱلْأَجَلَيْنِ قَضَيْتُ فَلَا عُدْوَٰنَ عَلَىَّ ۖ وَٱللَّهُ عَلَىٰ مَا نَقُولُ وَكِيلٌۭ', NULL, 20, 155, 5, 388, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 29, '۞ فَلَمَّا قَضَىٰ مُوسَى ٱلْأَجَلَ وَسَارَ بِأَهْلِهِۦٓ ءَانَسَ مِن جَانِبِ ٱلطُّورِ نَارًۭا قَالَ لِأَهْلِهِ ٱمْكُثُوٓا۟ إِنِّىٓ ءَانَسْتُ نَارًۭا لَّعَلِّىٓ ءَاتِيكُم مِّنْهَا بِخَبَرٍ أَوْ جَذْوَةٍۢ مِّنَ ٱلنَّارِ لَعَلَّكُمْ تَصْطَلُونَ', NULL, 20, 156, 5, 389, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 30, 'فَلَمَّآ أَتَىٰهَا نُودِىَ مِن شَٰطِئِ ٱلْوَادِ ٱلْأَيْمَنِ فِى ٱلْبُقْعَةِ ٱلْمُبَٰرَكَةِ مِنَ ٱلشَّجَرَةِ أَن يَٰمُوسَىٰٓ إِنِّىٓ أَنَا ٱللَّهُ رَبُّ ٱلْعَٰلَمِينَ', NULL, 20, 156, 5, 389, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 31, 'وَأَنْ أَلْقِ عَصَاكَ ۖ فَلَمَّا رَءَاهَا تَهْتَزُّ كَأَنَّهَا جَآنٌّۭ وَلَّىٰ مُدْبِرًۭا وَلَمْ يُعَقِّبْ ۚ يَٰمُوسَىٰٓ أَقْبِلْ وَلَا تَخَفْ ۖ إِنَّكَ مِنَ ٱلْءَامِنِينَ', NULL, 20, 156, 5, 389, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 32, 'ٱسْلُكْ يَدَكَ فِى جَيْبِكَ تَخْرُجْ بَيْضَآءَ مِنْ غَيْرِ سُوٓءٍۢ وَٱضْمُمْ إِلَيْكَ جَنَاحَكَ مِنَ ٱلرَّهْبِ ۖ فَذَٰنِكَ بُرْهَٰنَانِ مِن رَّبِّكَ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦٓ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًۭا فَٰسِقِينَ', NULL, 20, 156, 5, 389, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 33, 'قَالَ رَبِّ إِنِّى قَتَلْتُ مِنْهُمْ نَفْسًۭا فَأَخَافُ أَن يَقْتُلُونِ', NULL, 20, 156, 5, 389, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 34, 'وَأَخِى هَٰرُونُ هُوَ أَفْصَحُ مِنِّى لِسَانًۭا فَأَرْسِلْهُ مَعِىَ رِدْءًۭا يُصَدِّقُنِىٓ ۖ إِنِّىٓ أَخَافُ أَن يُكَذِّبُونِ', NULL, 20, 156, 5, 389, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 35, 'قَالَ سَنَشُدُّ عَضُدَكَ بِأَخِيكَ وَنَجْعَلُ لَكُمَا سُلْطَٰنًۭا فَلَا يَصِلُونَ إِلَيْكُمَا ۚ بِـَٔايَٰتِنَآ أَنتُمَا وَمَنِ ٱتَّبَعَكُمَا ٱلْغَٰلِبُونَ', NULL, 20, 156, 5, 389, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 36, 'فَلَمَّا جَآءَهُم مُّوسَىٰ بِـَٔايَٰتِنَا بَيِّنَٰتٍۢ قَالُوا۟ مَا هَٰذَآ إِلَّا سِحْرٌۭ مُّفْتَرًۭى وَمَا سَمِعْنَا بِهَٰذَا فِىٓ ءَابَآئِنَا ٱلْأَوَّلِينَ', NULL, 20, 156, 5, 390, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 37, 'وَقَالَ مُوسَىٰ رَبِّىٓ أَعْلَمُ بِمَن جَآءَ بِٱلْهُدَىٰ مِنْ عِندِهِۦ وَمَن تَكُونُ لَهُۥ عَٰقِبَةُ ٱلدَّارِ ۖ إِنَّهُۥ لَا يُفْلِحُ ٱلظَّٰلِمُونَ', NULL, 20, 156, 5, 390, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 38, 'وَقَالَ فِرْعَوْنُ يَٰٓأَيُّهَا ٱلْمَلَأُ مَا عَلِمْتُ لَكُم مِّنْ إِلَٰهٍ غَيْرِى فَأَوْقِدْ لِى يَٰهَٰمَٰنُ عَلَى ٱلطِّينِ فَٱجْعَل لِّى صَرْحًۭا لَّعَلِّىٓ أَطَّلِعُ إِلَىٰٓ إِلَٰهِ مُوسَىٰ وَإِنِّى لَأَظُنُّهُۥ مِنَ ٱلْكَٰذِبِينَ', NULL, 20, 156, 5, 390, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 39, 'وَٱسْتَكْبَرَ هُوَ وَجُنُودُهُۥ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَظَنُّوٓا۟ أَنَّهُمْ إِلَيْنَا لَا يُرْجَعُونَ', NULL, 20, 156, 5, 390, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 40, 'فَأَخَذْنَٰهُ وَجُنُودَهُۥ فَنَبَذْنَٰهُمْ فِى ٱلْيَمِّ ۖ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلظَّٰلِمِينَ', NULL, 20, 156, 5, 390, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 41, 'وَجَعَلْنَٰهُمْ أَئِمَّةًۭ يَدْعُونَ إِلَى ٱلنَّارِ ۖ وَيَوْمَ ٱلْقِيَٰمَةِ لَا يُنصَرُونَ', NULL, 20, 156, 5, 390, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 42, 'وَأَتْبَعْنَٰهُمْ فِى هَٰذِهِ ٱلدُّنْيَا لَعْنَةًۭ ۖ وَيَوْمَ ٱلْقِيَٰمَةِ هُم مِّنَ ٱلْمَقْبُوحِينَ', NULL, 20, 156, 5, 390, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 43, 'وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ مِنۢ بَعْدِ مَآ أَهْلَكْنَا ٱلْقُرُونَ ٱلْأُولَىٰ بَصَآئِرَ لِلنَّاسِ وَهُدًۭى وَرَحْمَةًۭ لَّعَلَّهُمْ يَتَذَكَّرُونَ', NULL, 20, 156, 5, 390, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 44, 'وَمَا كُنتَ بِجَانِبِ ٱلْغَرْبِىِّ إِذْ قَضَيْنَآ إِلَىٰ مُوسَى ٱلْأَمْرَ وَمَا كُنتَ مِنَ ٱلشَّٰهِدِينَ', NULL, 20, 156, 5, 391, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 45, 'وَلَٰكِنَّآ أَنشَأْنَا قُرُونًۭا فَتَطَاوَلَ عَلَيْهِمُ ٱلْعُمُرُ ۚ وَمَا كُنتَ ثَاوِيًۭا فِىٓ أَهْلِ مَدْيَنَ تَتْلُوا۟ عَلَيْهِمْ ءَايَٰتِنَا وَلَٰكِنَّا كُنَّا مُرْسِلِينَ', NULL, 20, 156, 5, 391, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 46, 'وَمَا كُنتَ بِجَانِبِ ٱلطُّورِ إِذْ نَادَيْنَا وَلَٰكِن رَّحْمَةًۭ مِّن رَّبِّكَ لِتُنذِرَ قَوْمًۭا مَّآ أَتَىٰهُم مِّن نَّذِيرٍۢ مِّن قَبْلِكَ لَعَلَّهُمْ يَتَذَكَّرُونَ', NULL, 20, 156, 5, 391, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 47, 'وَلَوْلَآ أَن تُصِيبَهُم مُّصِيبَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ فَيَقُولُوا۟ رَبَّنَا لَوْلَآ أَرْسَلْتَ إِلَيْنَا رَسُولًۭا فَنَتَّبِعَ ءَايَٰتِكَ وَنَكُونَ مِنَ ٱلْمُؤْمِنِينَ', NULL, 20, 156, 5, 391, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 48, 'فَلَمَّا جَآءَهُمُ ٱلْحَقُّ مِنْ عِندِنَا قَالُوا۟ لَوْلَآ أُوتِىَ مِثْلَ مَآ أُوتِىَ مُوسَىٰٓ ۚ أَوَلَمْ يَكْفُرُوا۟ بِمَآ أُوتِىَ مُوسَىٰ مِن قَبْلُ ۖ قَالُوا۟ سِحْرَانِ تَظَٰهَرَا وَقَالُوٓا۟ إِنَّا بِكُلٍّۢ كَٰفِرُونَ', NULL, 20, 156, 5, 391, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 49, 'قُلْ فَأْتُوا۟ بِكِتَٰبٍۢ مِّنْ عِندِ ٱللَّهِ هُوَ أَهْدَىٰ مِنْهُمَآ أَتَّبِعْهُ إِن كُنتُمْ صَٰدِقِينَ', NULL, 20, 156, 5, 391, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 50, 'فَإِن لَّمْ يَسْتَجِيبُوا۟ لَكَ فَٱعْلَمْ أَنَّمَا يَتَّبِعُونَ أَهْوَآءَهُمْ ۚ وَمَنْ أَضَلُّ مِمَّنِ ٱتَّبَعَ هَوَىٰهُ بِغَيْرِ هُدًۭى مِّنَ ٱللَّهِ ۚ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّٰلِمِينَ', NULL, 20, 156, 5, 391, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 51, '۞ وَلَقَدْ وَصَّلْنَا لَهُمُ ٱلْقَوْلَ لَعَلَّهُمْ يَتَذَكَّرُونَ', NULL, 20, 157, 5, 392, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 52, 'ٱلَّذِينَ ءَاتَيْنَٰهُمُ ٱلْكِتَٰبَ مِن قَبْلِهِۦ هُم بِهِۦ يُؤْمِنُونَ', NULL, 20, 157, 5, 392, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 53, 'وَإِذَا يُتْلَىٰ عَلَيْهِمْ قَالُوٓا۟ ءَامَنَّا بِهِۦٓ إِنَّهُ ٱلْحَقُّ مِن رَّبِّنَآ إِنَّا كُنَّا مِن قَبْلِهِۦ مُسْلِمِينَ', NULL, 20, 157, 5, 392, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 54, 'أُو۟لَٰٓئِكَ يُؤْتَوْنَ أَجْرَهُم مَّرَّتَيْنِ بِمَا صَبَرُوا۟ وَيَدْرَءُونَ بِٱلْحَسَنَةِ ٱلسَّيِّئَةَ وَمِمَّا رَزَقْنَٰهُمْ يُنفِقُونَ', NULL, 20, 157, 5, 392, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 55, 'وَإِذَا سَمِعُوا۟ ٱللَّغْوَ أَعْرَضُوا۟ عَنْهُ وَقَالُوا۟ لَنَآ أَعْمَٰلُنَا وَلَكُمْ أَعْمَٰلُكُمْ سَلَٰمٌ عَلَيْكُمْ لَا نَبْتَغِى ٱلْجَٰهِلِينَ', NULL, 20, 157, 5, 392, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 56, 'إِنَّكَ لَا تَهْدِى مَنْ أَحْبَبْتَ وَلَٰكِنَّ ٱللَّهَ يَهْدِى مَن يَشَآءُ ۚ وَهُوَ أَعْلَمُ بِٱلْمُهْتَدِينَ', NULL, 20, 157, 5, 392, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 57, 'وَقَالُوٓا۟ إِن نَّتَّبِعِ ٱلْهُدَىٰ مَعَكَ نُتَخَطَّفْ مِنْ أَرْضِنَآ ۚ أَوَلَمْ نُمَكِّن لَّهُمْ حَرَمًا ءَامِنًۭا يُجْبَىٰٓ إِلَيْهِ ثَمَرَٰتُ كُلِّ شَىْءٍۢ رِّزْقًۭا مِّن لَّدُنَّا وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ', NULL, 20, 157, 5, 392, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 58, 'وَكَمْ أَهْلَكْنَا مِن قَرْيَةٍۭ بَطِرَتْ مَعِيشَتَهَا ۖ فَتِلْكَ مَسَٰكِنُهُمْ لَمْ تُسْكَن مِّنۢ بَعْدِهِمْ إِلَّا قَلِيلًۭا ۖ وَكُنَّا نَحْنُ ٱلْوَٰرِثِينَ', NULL, 20, 157, 5, 392, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 59, 'وَمَا كَانَ رَبُّكَ مُهْلِكَ ٱلْقُرَىٰ حَتَّىٰ يَبْعَثَ فِىٓ أُمِّهَا رَسُولًۭا يَتْلُوا۟ عَلَيْهِمْ ءَايَٰتِنَا ۚ وَمَا كُنَّا مُهْلِكِى ٱلْقُرَىٰٓ إِلَّا وَأَهْلُهَا ظَٰلِمُونَ', NULL, 20, 157, 5, 392, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 60, 'وَمَآ أُوتِيتُم مِّن شَىْءٍۢ فَمَتَٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا وَزِينَتُهَا ۚ وَمَا عِندَ ٱللَّهِ خَيْرٌۭ وَأَبْقَىٰٓ ۚ أَفَلَا تَعْقِلُونَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 61, 'أَفَمَن وَعَدْنَٰهُ وَعْدًا حَسَنًۭا فَهُوَ لَٰقِيهِ كَمَن مَّتَّعْنَٰهُ مَتَٰعَ ٱلْحَيَوٰةِ ٱلدُّنْيَا ثُمَّ هُوَ يَوْمَ ٱلْقِيَٰمَةِ مِنَ ٱلْمُحْضَرِينَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 62, 'وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ أَيْنَ شُرَكَآءِىَ ٱلَّذِينَ كُنتُمْ تَزْعُمُونَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 63, 'قَالَ ٱلَّذِينَ حَقَّ عَلَيْهِمُ ٱلْقَوْلُ رَبَّنَا هَٰٓؤُلَآءِ ٱلَّذِينَ أَغْوَيْنَآ أَغْوَيْنَٰهُمْ كَمَا غَوَيْنَا ۖ تَبَرَّأْنَآ إِلَيْكَ ۖ مَا كَانُوٓا۟ إِيَّانَا يَعْبُدُونَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 64, 'وَقِيلَ ٱدْعُوا۟ شُرَكَآءَكُمْ فَدَعَوْهُمْ فَلَمْ يَسْتَجِيبُوا۟ لَهُمْ وَرَأَوُا۟ ٱلْعَذَابَ ۚ لَوْ أَنَّهُمْ كَانُوا۟ يَهْتَدُونَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 65, 'وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ مَاذَآ أَجَبْتُمُ ٱلْمُرْسَلِينَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 66, 'فَعَمِيَتْ عَلَيْهِمُ ٱلْأَنۢبَآءُ يَوْمَئِذٍۢ فَهُمْ لَا يَتَسَآءَلُونَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 67, 'فَأَمَّا مَن تَابَ وَءَامَنَ وَعَمِلَ صَٰلِحًۭا فَعَسَىٰٓ أَن يَكُونَ مِنَ ٱلْمُفْلِحِينَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 68, 'وَرَبُّكَ يَخْلُقُ مَا يَشَآءُ وَيَخْتَارُ ۗ مَا كَانَ لَهُمُ ٱلْخِيَرَةُ ۚ سُبْحَٰنَ ٱللَّهِ وَتَعَٰلَىٰ عَمَّا يُشْرِكُونَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 69, 'وَرَبُّكَ يَعْلَمُ مَا تُكِنُّ صُدُورُهُمْ وَمَا يُعْلِنُونَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 70, 'وَهُوَ ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ۖ لَهُ ٱلْحَمْدُ فِى ٱلْأُولَىٰ وَٱلْءَاخِرَةِ ۖ وَلَهُ ٱلْحُكْمُ وَإِلَيْهِ تُرْجَعُونَ', NULL, 20, 157, 5, 393, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 71, 'قُلْ أَرَءَيْتُمْ إِن جَعَلَ ٱللَّهُ عَلَيْكُمُ ٱلَّيْلَ سَرْمَدًا إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ مَنْ إِلَٰهٌ غَيْرُ ٱللَّهِ يَأْتِيكُم بِضِيَآءٍ ۖ أَفَلَا تَسْمَعُونَ', NULL, 20, 157, 5, 394, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 72, 'قُلْ أَرَءَيْتُمْ إِن جَعَلَ ٱللَّهُ عَلَيْكُمُ ٱلنَّهَارَ سَرْمَدًا إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ مَنْ إِلَٰهٌ غَيْرُ ٱللَّهِ يَأْتِيكُم بِلَيْلٍۢ تَسْكُنُونَ فِيهِ ۖ أَفَلَا تُبْصِرُونَ', NULL, 20, 157, 5, 394, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 73, 'وَمِن رَّحْمَتِهِۦ جَعَلَ لَكُمُ ٱلَّيْلَ وَٱلنَّهَارَ لِتَسْكُنُوا۟ فِيهِ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ', NULL, 20, 157, 5, 394, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 74, 'وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ أَيْنَ شُرَكَآءِىَ ٱلَّذِينَ كُنتُمْ تَزْعُمُونَ', NULL, 20, 157, 5, 394, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 75, 'وَنَزَعْنَا مِن كُلِّ أُمَّةٍۢ شَهِيدًۭا فَقُلْنَا هَاتُوا۟ بُرْهَٰنَكُمْ فَعَلِمُوٓا۟ أَنَّ ٱلْحَقَّ لِلَّهِ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ', NULL, 20, 157, 5, 394, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 76, '۞ إِنَّ قَٰرُونَ كَانَ مِن قَوْمِ مُوسَىٰ فَبَغَىٰ عَلَيْهِمْ ۖ وَءَاتَيْنَٰهُ مِنَ ٱلْكُنُوزِ مَآ إِنَّ مَفَاتِحَهُۥ لَتَنُوٓأُ بِٱلْعُصْبَةِ أُو۟لِى ٱلْقُوَّةِ إِذْ قَالَ لَهُۥ قَوْمُهُۥ لَا تَفْرَحْ ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْفَرِحِينَ', NULL, 20, 158, 5, 394, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 77, 'وَٱبْتَغِ فِيمَآ ءَاتَىٰكَ ٱللَّهُ ٱلدَّارَ ٱلْءَاخِرَةَ ۖ وَلَا تَنسَ نَصِيبَكَ مِنَ ٱلدُّنْيَا ۖ وَأَحْسِن كَمَآ أَحْسَنَ ٱللَّهُ إِلَيْكَ ۖ وَلَا تَبْغِ ٱلْفَسَادَ فِى ٱلْأَرْضِ ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْمُفْسِدِينَ', NULL, 20, 158, 5, 394, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 78, 'قَالَ إِنَّمَآ أُوتِيتُهُۥ عَلَىٰ عِلْمٍ عِندِىٓ ۚ أَوَلَمْ يَعْلَمْ أَنَّ ٱللَّهَ قَدْ أَهْلَكَ مِن قَبْلِهِۦ مِنَ ٱلْقُرُونِ مَنْ هُوَ أَشَدُّ مِنْهُ قُوَّةًۭ وَأَكْثَرُ جَمْعًۭا ۚ وَلَا يُسْـَٔلُ عَن ذُنُوبِهِمُ ٱلْمُجْرِمُونَ', NULL, 20, 158, 5, 395, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 79, 'فَخَرَجَ عَلَىٰ قَوْمِهِۦ فِى زِينَتِهِۦ ۖ قَالَ ٱلَّذِينَ يُرِيدُونَ ٱلْحَيَوٰةَ ٱلدُّنْيَا يَٰلَيْتَ لَنَا مِثْلَ مَآ أُوتِىَ قَٰرُونُ إِنَّهُۥ لَذُو حَظٍّ عَظِيمٍۢ', NULL, 20, 158, 5, 395, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 80, 'وَقَالَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ وَيْلَكُمْ ثَوَابُ ٱللَّهِ خَيْرٌۭ لِّمَنْ ءَامَنَ وَعَمِلَ صَٰلِحًۭا وَلَا يُلَقَّىٰهَآ إِلَّا ٱلصَّٰبِرُونَ', NULL, 20, 158, 5, 395, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 81, 'فَخَسَفْنَا بِهِۦ وَبِدَارِهِ ٱلْأَرْضَ فَمَا كَانَ لَهُۥ مِن فِئَةٍۢ يَنصُرُونَهُۥ مِن دُونِ ٱللَّهِ وَمَا كَانَ مِنَ ٱلْمُنتَصِرِينَ', NULL, 20, 158, 5, 395, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 82, 'وَأَصْبَحَ ٱلَّذِينَ تَمَنَّوْا۟ مَكَانَهُۥ بِٱلْأَمْسِ يَقُولُونَ وَيْكَأَنَّ ٱللَّهَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ ۖ لَوْلَآ أَن مَّنَّ ٱللَّهُ عَلَيْنَا لَخَسَفَ بِنَا ۖ وَيْكَأَنَّهُۥ لَا يُفْلِحُ ٱلْكَٰفِرُونَ', NULL, 20, 158, 5, 395, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 83, 'تِلْكَ ٱلدَّارُ ٱلْءَاخِرَةُ نَجْعَلُهَا لِلَّذِينَ لَا يُرِيدُونَ عُلُوًّۭا فِى ٱلْأَرْضِ وَلَا فَسَادًۭا ۚ وَٱلْعَٰقِبَةُ لِلْمُتَّقِينَ', NULL, 20, 158, 5, 395, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 84, 'مَن جَآءَ بِٱلْحَسَنَةِ فَلَهُۥ خَيْرٌۭ مِّنْهَا ۖ وَمَن جَآءَ بِٱلسَّيِّئَةِ فَلَا يُجْزَى ٱلَّذِينَ عَمِلُوا۟ ٱلسَّيِّـَٔاتِ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ', NULL, 20, 158, 5, 395, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 85, 'إِنَّ ٱلَّذِى فَرَضَ عَلَيْكَ ٱلْقُرْءَانَ لَرَآدُّكَ إِلَىٰ مَعَادٍۢ ۚ قُل رَّبِّىٓ أَعْلَمُ مَن جَآءَ بِٱلْهُدَىٰ وَمَنْ هُوَ فِى ضَلَٰلٍۢ مُّبِينٍۢ', NULL, 20, 158, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 86, 'وَمَا كُنتَ تَرْجُوٓا۟ أَن يُلْقَىٰٓ إِلَيْكَ ٱلْكِتَٰبُ إِلَّا رَحْمَةًۭ مِّن رَّبِّكَ ۖ فَلَا تَكُونَنَّ ظَهِيرًۭا لِّلْكَٰفِرِينَ', NULL, 20, 158, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 87, 'وَلَا يَصُدُّنَّكَ عَنْ ءَايَٰتِ ٱللَّهِ بَعْدَ إِذْ أُنزِلَتْ إِلَيْكَ ۖ وَٱدْعُ إِلَىٰ رَبِّكَ ۖ وَلَا تَكُونَنَّ مِنَ ٱلْمُشْرِكِينَ', NULL, 20, 158, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 28), 88, 'وَلَا تَدْعُ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ ۘ لَآ إِلَٰهَ إِلَّا هُوَ ۚ كُلُّ شَىْءٍ هَالِكٌ إِلَّا وَجْهَهُۥ ۚ لَهُ ٱلْحُكْمُ وَإِلَيْهِ تُرْجَعُونَ', NULL, 20, 158, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ الٓمٓ', NULL, 20, 159, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 2, 'أَحَسِبَ ٱلنَّاسُ أَن يُتْرَكُوٓا۟ أَن يَقُولُوٓا۟ ءَامَنَّا وَهُمْ لَا يُفْتَنُونَ', NULL, 20, 159, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 3, 'وَلَقَدْ فَتَنَّا ٱلَّذِينَ مِن قَبْلِهِمْ ۖ فَلَيَعْلَمَنَّ ٱللَّهُ ٱلَّذِينَ صَدَقُوا۟ وَلَيَعْلَمَنَّ ٱلْكَٰذِبِينَ', NULL, 20, 159, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 4, 'أَمْ حَسِبَ ٱلَّذِينَ يَعْمَلُونَ ٱلسَّيِّـَٔاتِ أَن يَسْبِقُونَا ۚ سَآءَ مَا يَحْكُمُونَ', NULL, 20, 159, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 5, 'مَن كَانَ يَرْجُوا۟ لِقَآءَ ٱللَّهِ فَإِنَّ أَجَلَ ٱللَّهِ لَءَاتٍۢ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ', NULL, 20, 159, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 6, 'وَمَن جَٰهَدَ فَإِنَّمَا يُجَٰهِدُ لِنَفْسِهِۦٓ ۚ إِنَّ ٱللَّهَ لَغَنِىٌّ عَنِ ٱلْعَٰلَمِينَ', NULL, 20, 159, 5, 396, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 7, 'وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَنُكَفِّرَنَّ عَنْهُمْ سَيِّـَٔاتِهِمْ وَلَنَجْزِيَنَّهُمْ أَحْسَنَ ٱلَّذِى كَانُوا۟ يَعْمَلُونَ', NULL, 20, 159, 5, 397, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 8, 'وَوَصَّيْنَا ٱلْإِنسَٰنَ بِوَٰلِدَيْهِ حُسْنًۭا ۖ وَإِن جَٰهَدَاكَ لِتُشْرِكَ بِى مَا لَيْسَ لَكَ بِهِۦ عِلْمٌۭ فَلَا تُطِعْهُمَآ ۚ إِلَىَّ مَرْجِعُكُمْ فَأُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ', NULL, 20, 159, 5, 397, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 9, 'وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَنُدْخِلَنَّهُمْ فِى ٱلصَّٰلِحِينَ', NULL, 20, 159, 5, 397, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 10, 'وَمِنَ ٱلنَّاسِ مَن يَقُولُ ءَامَنَّا بِٱللَّهِ فَإِذَآ أُوذِىَ فِى ٱللَّهِ جَعَلَ فِتْنَةَ ٱلنَّاسِ كَعَذَابِ ٱللَّهِ وَلَئِن جَآءَ نَصْرٌۭ مِّن رَّبِّكَ لَيَقُولُنَّ إِنَّا كُنَّا مَعَكُمْ ۚ أَوَلَيْسَ ٱللَّهُ بِأَعْلَمَ بِمَا فِى صُدُورِ ٱلْعَٰلَمِينَ', NULL, 20, 159, 5, 397, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 11, 'وَلَيَعْلَمَنَّ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَلَيَعْلَمَنَّ ٱلْمُنَٰفِقِينَ', NULL, 20, 159, 5, 397, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 12, 'وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوا۟ ٱتَّبِعُوا۟ سَبِيلَنَا وَلْنَحْمِلْ خَطَٰيَٰكُمْ وَمَا هُم بِحَٰمِلِينَ مِنْ خَطَٰيَٰهُم مِّن شَىْءٍ ۖ إِنَّهُمْ لَكَٰذِبُونَ', NULL, 20, 159, 5, 397, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 13, 'وَلَيَحْمِلُنَّ أَثْقَالَهُمْ وَأَثْقَالًۭا مَّعَ أَثْقَالِهِمْ ۖ وَلَيُسْـَٔلُنَّ يَوْمَ ٱلْقِيَٰمَةِ عَمَّا كَانُوا۟ يَفْتَرُونَ', NULL, 20, 159, 5, 397, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 14, 'وَلَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَلَبِثَ فِيهِمْ أَلْفَ سَنَةٍ إِلَّا خَمْسِينَ عَامًۭا فَأَخَذَهُمُ ٱلطُّوفَانُ وَهُمْ ظَٰلِمُونَ', NULL, 20, 159, 5, 397, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 15, 'فَأَنجَيْنَٰهُ وَأَصْحَٰبَ ٱلسَّفِينَةِ وَجَعَلْنَٰهَآ ءَايَةًۭ لِّلْعَٰلَمِينَ', NULL, 20, 159, 5, 398, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 16, 'وَإِبْرَٰهِيمَ إِذْ قَالَ لِقَوْمِهِ ٱعْبُدُوا۟ ٱللَّهَ وَٱتَّقُوهُ ۖ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ', NULL, 20, 159, 5, 398, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 17, 'إِنَّمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ أَوْثَٰنًۭا وَتَخْلُقُونَ إِفْكًا ۚ إِنَّ ٱلَّذِينَ تَعْبُدُونَ مِن دُونِ ٱللَّهِ لَا يَمْلِكُونَ لَكُمْ رِزْقًۭا فَٱبْتَغُوا۟ عِندَ ٱللَّهِ ٱلرِّزْقَ وَٱعْبُدُوهُ وَٱشْكُرُوا۟ لَهُۥٓ ۖ إِلَيْهِ تُرْجَعُونَ', NULL, 20, 159, 5, 398, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 18, 'وَإِن تُكَذِّبُوا۟ فَقَدْ كَذَّبَ أُمَمٌۭ مِّن قَبْلِكُمْ ۖ وَمَا عَلَى ٱلرَّسُولِ إِلَّا ٱلْبَلَٰغُ ٱلْمُبِينُ', NULL, 20, 159, 5, 398, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 19, 'أَوَلَمْ يَرَوْا۟ كَيْفَ يُبْدِئُ ٱللَّهُ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥٓ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ', NULL, 20, 159, 5, 398, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 20, 'قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ بَدَأَ ٱلْخَلْقَ ۚ ثُمَّ ٱللَّهُ يُنشِئُ ٱلنَّشْأَةَ ٱلْءَاخِرَةَ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ', NULL, 20, 159, 5, 398, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 21, 'يُعَذِّبُ مَن يَشَآءُ وَيَرْحَمُ مَن يَشَآءُ ۖ وَإِلَيْهِ تُقْلَبُونَ', NULL, 20, 159, 5, 398, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 22, 'وَمَآ أَنتُم بِمُعْجِزِينَ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ ۖ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّۢ وَلَا نَصِيرٍۢ', NULL, 20, 159, 5, 398, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 23, 'وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَٰتِ ٱللَّهِ وَلِقَآئِهِۦٓ أُو۟لَٰٓئِكَ يَئِسُوا۟ مِن رَّحْمَتِى وَأُو۟لَٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌۭ', NULL, 20, 159, 5, 398, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 24, 'فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوا۟ ٱقْتُلُوهُ أَوْ حَرِّقُوهُ فَأَنجَىٰهُ ٱللَّهُ مِنَ ٱلنَّارِ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ', NULL, 20, 159, 5, 399, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 25, 'وَقَالَ إِنَّمَا ٱتَّخَذْتُم مِّن دُونِ ٱللَّهِ أَوْثَٰنًۭا مَّوَدَّةَ بَيْنِكُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ ثُمَّ يَوْمَ ٱلْقِيَٰمَةِ يَكْفُرُ بَعْضُكُم بِبَعْضٍۢ وَيَلْعَنُ بَعْضُكُم بَعْضًۭا وَمَأْوَىٰكُمُ ٱلنَّارُ وَمَا لَكُم مِّن نَّٰصِرِينَ', NULL, 20, 159, 5, 399, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 26, '۞ فَـَٔامَنَ لَهُۥ لُوطٌۭ ۘ وَقَالَ إِنِّى مُهَاجِرٌ إِلَىٰ رَبِّىٓ ۖ إِنَّهُۥ هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 20, 160, 5, 399, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 27, 'وَوَهَبْنَا لَهُۥٓ إِسْحَٰقَ وَيَعْقُوبَ وَجَعَلْنَا فِى ذُرِّيَّتِهِ ٱلنُّبُوَّةَ وَٱلْكِتَٰبَ وَءَاتَيْنَٰهُ أَجْرَهُۥ فِى ٱلدُّنْيَا ۖ وَإِنَّهُۥ فِى ٱلْءَاخِرَةِ لَمِنَ ٱلصَّٰلِحِينَ', NULL, 20, 160, 5, 399, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 28, 'وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ إِنَّكُمْ لَتَأْتُونَ ٱلْفَٰحِشَةَ مَا سَبَقَكُم بِهَا مِنْ أَحَدٍۢ مِّنَ ٱلْعَٰلَمِينَ', NULL, 20, 160, 5, 399, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 29, 'أَئِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ وَتَقْطَعُونَ ٱلسَّبِيلَ وَتَأْتُونَ فِى نَادِيكُمُ ٱلْمُنكَرَ ۖ فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوا۟ ٱئْتِنَا بِعَذَابِ ٱللَّهِ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ', NULL, 20, 160, 5, 399, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 30, 'قَالَ رَبِّ ٱنصُرْنِى عَلَى ٱلْقَوْمِ ٱلْمُفْسِدِينَ', NULL, 20, 160, 5, 399, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 31, 'وَلَمَّا جَآءَتْ رُسُلُنَآ إِبْرَٰهِيمَ بِٱلْبُشْرَىٰ قَالُوٓا۟ إِنَّا مُهْلِكُوٓا۟ أَهْلِ هَٰذِهِ ٱلْقَرْيَةِ ۖ إِنَّ أَهْلَهَا كَانُوا۟ ظَٰلِمِينَ', NULL, 20, 160, 5, 400, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 32, 'قَالَ إِنَّ فِيهَا لُوطًۭا ۚ قَالُوا۟ نَحْنُ أَعْلَمُ بِمَن فِيهَا ۖ لَنُنَجِّيَنَّهُۥ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ كَانَتْ مِنَ ٱلْغَٰبِرِينَ', NULL, 20, 160, 5, 400, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 33, 'وَلَمَّآ أَن جَآءَتْ رُسُلُنَا لُوطًۭا سِىٓءَ بِهِمْ وَضَاقَ بِهِمْ ذَرْعًۭا وَقَالُوا۟ لَا تَخَفْ وَلَا تَحْزَنْ ۖ إِنَّا مُنَجُّوكَ وَأَهْلَكَ إِلَّا ٱمْرَأَتَكَ كَانَتْ مِنَ ٱلْغَٰبِرِينَ', NULL, 20, 160, 5, 400, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 34, 'إِنَّا مُنزِلُونَ عَلَىٰٓ أَهْلِ هَٰذِهِ ٱلْقَرْيَةِ رِجْزًۭا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَفْسُقُونَ', NULL, 20, 160, 5, 400, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 35, 'وَلَقَد تَّرَكْنَا مِنْهَآ ءَايَةًۢ بَيِّنَةًۭ لِّقَوْمٍۢ يَعْقِلُونَ', NULL, 20, 160, 5, 400, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 36, 'وَإِلَىٰ مَدْيَنَ أَخَاهُمْ شُعَيْبًۭا فَقَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ وَٱرْجُوا۟ ٱلْيَوْمَ ٱلْءَاخِرَ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ', NULL, 20, 160, 5, 400, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 37, 'فَكَذَّبُوهُ فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَٰثِمِينَ', NULL, 20, 160, 5, 400, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 38, 'وَعَادًۭا وَثَمُودَا۟ وَقَد تَّبَيَّنَ لَكُم مِّن مَّسَٰكِنِهِمْ ۖ وَزَيَّنَ لَهُمُ ٱلشَّيْطَٰنُ أَعْمَٰلَهُمْ فَصَدَّهُمْ عَنِ ٱلسَّبِيلِ وَكَانُوا۟ مُسْتَبْصِرِينَ', NULL, 20, 160, 5, 400, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 39, 'وَقَٰرُونَ وَفِرْعَوْنَ وَهَٰمَٰنَ ۖ وَلَقَدْ جَآءَهُم مُّوسَىٰ بِٱلْبَيِّنَٰتِ فَٱسْتَكْبَرُوا۟ فِى ٱلْأَرْضِ وَمَا كَانُوا۟ سَٰبِقِينَ', NULL, 20, 160, 5, 401, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 40, 'فَكُلًّا أَخَذْنَا بِذَنۢبِهِۦ ۖ فَمِنْهُم مَّنْ أَرْسَلْنَا عَلَيْهِ حَاصِبًۭا وَمِنْهُم مَّنْ أَخَذَتْهُ ٱلصَّيْحَةُ وَمِنْهُم مَّنْ خَسَفْنَا بِهِ ٱلْأَرْضَ وَمِنْهُم مَّنْ أَغْرَقْنَا ۚ وَمَا كَانَ ٱللَّهُ لِيَظْلِمَهُمْ وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ', NULL, 20, 160, 5, 401, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 41, 'مَثَلُ ٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ أَوْلِيَآءَ كَمَثَلِ ٱلْعَنكَبُوتِ ٱتَّخَذَتْ بَيْتًۭا ۖ وَإِنَّ أَوْهَنَ ٱلْبُيُوتِ لَبَيْتُ ٱلْعَنكَبُوتِ ۖ لَوْ كَانُوا۟ يَعْلَمُونَ', NULL, 20, 160, 5, 401, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 42, 'إِنَّ ٱللَّهَ يَعْلَمُ مَا يَدْعُونَ مِن دُونِهِۦ مِن شَىْءٍۢ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 20, 160, 5, 401, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 43, 'وَتِلْكَ ٱلْأَمْثَٰلُ نَضْرِبُهَا لِلنَّاسِ ۖ وَمَا يَعْقِلُهَآ إِلَّا ٱلْعَٰلِمُونَ', NULL, 20, 160, 5, 401, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 44, 'خَلَقَ ٱللَّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّلْمُؤْمِنِينَ', NULL, 20, 160, 5, 401, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 45, 'ٱتْلُ مَآ أُوحِىَ إِلَيْكَ مِنَ ٱلْكِتَٰبِ وَأَقِمِ ٱلصَّلَوٰةَ ۖ إِنَّ ٱلصَّلَوٰةَ تَنْهَىٰ عَنِ ٱلْفَحْشَآءِ وَٱلْمُنكَرِ ۗ وَلَذِكْرُ ٱللَّهِ أَكْبَرُ ۗ وَٱللَّهُ يَعْلَمُ مَا تَصْنَعُونَ', NULL, 20, 160, 5, 401, false, NOW(), NOW());
